-- Poems batch 361
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cd5f03cc-92ed-4a99-b6c8-694d4cad65f6','贈俞清老','許景衡','宋','宋诗','song-poetry','','[]','昔我江淮幾還往，聞君兄弟有聲名。',64,'全唐诗/poet.song.78000.json','["昔我江淮幾還往，聞君兄弟有聲名。", "小軒便作陶彭澤，五字何如李少卿。", "自說此身看老去，却慙相見太忙生。", "何時粗有田園計，把手江邊取次行。"]'),
('0a333830-af21-4921-b5e2-5c7e08f38b60','贈鄭介夫','許景衡','宋','宋诗','song-poetry','','[]','人笑流離自抱關，天教强健老林泉。',64,'全唐诗/poet.song.78000.json','["人笑流離自抱關，天教强健老林泉。", "回頭嶺海幾千里，屈指星霜五十年。", "無事一樽誰與醉，有時兩手自争先。", "也知世上皆兒戯，出處如公豈偶然。"]'),
('0a2297f8-8b28-4101-ae71-3d81e389d8b5','贈吳惇仁','許景衡','宋','宋诗','song-poetry','','[]','塵埃簿領判悠悠，瘦馬尋春到海頭。',64,'全唐诗/poet.song.78000.json','["塵埃簿領判悠悠，瘦馬尋春到海頭。", "已是二毛侵老境，尚能一笑得英遊。", "誰言前輩風流盡，我覺名家世業優。", "但得此心常了了，豈知州縣是淹留。"]'),
('b960d7f0-b237-4c42-b88e-d08f594b962f','贈董公權','許景衡','宋','宋诗','song-poetry','','[]','前輩風流今掃地，怪君尚肯轉頭看。',64,'全唐诗/poet.song.78000.json','["前輩風流今掃地，怪君尚肯轉頭看。", "元來自作小兒子，猶及當初老長官。", "簡冊微言齊日月，絃歌餘澤在芝蘭。", "却慚江海生尤晚，不得同年拜杏壇。"]'),
('a18617f8-b8b8-415b-9918-f379669f5c5d','璧山堂','許景衡','宋','宋诗','song-poetry','','[]','在處看山多間斷，經行尤喜得斯堂。',64,'全唐诗/poet.song.78000.json','["在處看山多間斷，經行尤喜得斯堂。", "畫屏簇簇連千室，古璧蒼蒼遶四旁。", "憶昨服官叨內府，祗供嚴祀屬新陽。", "天涯寓目徒增感，一覺鈞天夢帝鄉。"]'),
('5ad52878-f407-474b-b8a6-a3ca603dca5b','題竹閣','許景衡','宋','宋诗','song-poetry','','[]','西岑僧舍知多少，竹閣巍然鹿苑中。',64,'全唐诗/poet.song.78000.json','["西岑僧舍知多少，竹閣巍然鹿苑中。", "蠟屐登臨非俗客，石床宴坐屬詩翁。", "黄金階砌紛紛月，碧玉窗櫺細細風。", "千里江山應在眼，狂鞭何用作深叢。"]'),
('1b0a3e5c-45d4-4881-ad8e-e8cd0b704aa4','又招虞仲來竹閣','許景衡','宋','宋诗','song-poetry','','[]','一諾定須遊竹閣，多時凝望出松臺。',64,'全唐诗/poet.song.78000.json','["一諾定須遊竹閣，多時凝望出松臺。", "祇應城市醺醺醉，肯爲詩翁特特來。", "湖水秋來清見底，仙山雨後翠成堆。", "欄干供盡登臨目，鷗鷺翩翩日幾回。"]'),
('a59c0816-d3b3-4db7-9c53-5c38eaabbaad','寄張宰幾仲','許景衡','宋','宋诗','song-poetry','','[]','往在横塘詩酒社，而今不忍重尋思。',64,'全唐诗/poet.song.78000.json','["往在横塘詩酒社，而今不忍重尋思。", "時人狂簡無如我，縣尹風流更有誰。", "塞上塵沙長冥寞，江南梅柳正葳蕤。", "人生閒健須行樂，莫學安仁鬢早衰。"]'),
('e3cdb63f-f6ea-49fe-b2ae-991b6c9b56b0','送高宰','許景衡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','長愛西湖無點塵，樓臺倒影雜星辰。',64,'全唐诗/poet.song.78000.json','["長愛西湖無點塵，樓臺倒影雜星辰。", "未能把釣爲閒客，且喜鳴琴有主人。", "揺槳何妨長載月，新隄最好是遊春。", "何須更說林間雉，看取熙熙百里民。"]'),
('f985f2d1-8f8e-44af-a192-7fc4f950bc46','送李彦侯宰黄巖  其一','許景衡','宋','宋诗','song-poetry','','[]','委羽人物已先去，陳迹風流猶至今。',64,'全唐诗/poet.song.78000.json','["委羽人物已先去，陳迹風流猶至今。", "隱吏向來慚懶散，令君此去好追尋。", "春歸山奥十里雪，霜後園林三寸金。", "况有左生詩句好，一尊端爲伴高吟。"]'),
('1a075789-e59c-4045-afcf-1c8ea3f10171','送李彦侯宰黄巖  其二','許景衡','宋','宋诗','song-poetry','','[]','自笑當初作底官，只應山水得盤桓。',64,'全唐诗/poet.song.78000.json','["自笑當初作底官，只應山水得盤桓。", "江樓風月傳觴後，邊塞塵沙行路難。", "閭里樵漁無失業，歲時簫鼓有餘歡。", "十年父老今何似，爲我從頭問訊看。"]'),
('f03f5f6c-4bc2-444b-b4ef-a4d0278f1e8c','題雁蕩山圖','許景衡','宋','宋诗','song-poetry','','[]','别來嘗憶舊躋攀，好信迢迢慰病顔。',64,'全唐诗/poet.song.78000.json','["别來嘗憶舊躋攀，好信迢迢慰病顔。", "多按地圖傳藥石，不煩魂夢到仙山。", "塵沙猶在微茫處，雲水都歸指顧間。", "看取蕩中多少雁，衹應飛倦始知還。"]'),
('25883580-a8e9-437c-a2df-e3a5b558862b','跋亨老所藏買田帖','許景衡','宋','宋诗','song-poetry','','[]','世間榮利等雲浮，珍重先生早轉頭。',64,'全唐诗/poet.song.78000.json','["世間榮利等雲浮，珍重先生早轉頭。", "要得良田供玉粒，何妨累紙灑銀鈎。", "千金身後方爲貴，十襲公家得盡收。", "我亦塵埃倦遊者，紫薸二頃尚悠悠。"]'),
('b9f44325-551e-4bea-9ea5-ab5a7b325f80','送爲章','許景衡','宋','宋诗','song-poetry','','[]','使君遺愛在甘棠，故老于今尚未忘。',64,'全唐诗/poet.song.78000.json','["使君遺愛在甘棠，故老于今尚未忘。", "椎鈍自嗟生太晚，風流猶及見諸郎。", "鳴琴暫肯留山縣，飛舄還同指帝鄉。", "回首樓前江上月，夜來無故照離觴。"]'),
('399ee6b3-072f-4877-92a2-8bd9aaa98436','送李彦禮','許景衡','宋','宋诗','song-poetry','','[]','持節西陲已清切，還輿北道却盤桓。',64,'全唐诗/poet.song.78000.json','["持節西陲已清切，還輿北道却盤桓。", "當官未覺家風遠，抗疏要令邊計寛。", "世俗多應笑公拙，我曹徒解嘆才難。", "但將名節爲親壽，何止平反一笑歡。"]'),
('2dab1f3b-9184-49c4-b7a6-43f6a9622638','送廖用中','許景衡','宋','宋诗','song-poetry','','[]','也知志業在詩書，可是才高與世疏。',64,'全唐诗/poet.song.78000.json','["也知志業在詩書，可是才高與世疏。", "戯綵北遊非我計，督郵南去近吾廬。", "官田雨足秋多黍，城市潮來食有魚。", "更誦九江長短句，人間樂事得如渠。"]'),
('eb173808-c69e-4f6a-b358-4043f5a57cd1','送趙仲明二首  其一','許景衡','宋','宋诗','song-poetry','','[]','關塞相逢眼便青，從容猶得問平生。',64,'全唐诗/poet.song.78000.json','["關塞相逢眼便青，從容猶得問平生。", "高談大抵多忠義，先世元來好弟兄。", "但得朝廷收閥閲，不論文武盡功名。", "河隄奔走非吾事，去去神京信意行。"]'),
('01c3cd6b-0df9-4eca-9a10-a2dbd74a75ab','送趙仲明二首  其二','許景衡','宋','宋诗','song-poetry','','[]','役役都來幾獻酬，生憎别語攪離愁。',64,'全唐诗/poet.song.78000.json','["役役都來幾獻酬，生憎别語攪離愁。", "五更門吏開魚鑰，千里春風在馬頭。", "若見遊從出京國，爲傳消息到真州。", "田園未有歸來計，萍梗而今已倦游。"]'),
('b6e0ff88-bc78-4348-a6ca-cf111c969458','送商霖兼簡共叔','許景衡','宋','宋诗','song-poetry','','[]','末學紛紛只是誇，孔顔門户本無遮。',64,'全唐诗/poet.song.78000.json','["末學紛紛只是誇，孔顔門户本無遮。", "農工商賈皆同氣，草木蟲魚是一家。", "我欲收心求克己，公知誠意在閑邪。", "汝南夫子規模大，歸去相從海一涯。"]'),
('1488a85d-87fa-42bf-8a7c-79db442ba595','宿崇國院','許景衡','宋','宋诗','song-poetry','','[]','世塗足趨競，野性惟閒散。',24,'全唐诗/poet.song.78000.json','["世塗足趨競，野性惟閒散。", "卧聞風雨聲，更覺江湖遠。"]'),
('6722f0cc-8d96-4708-b3ea-8e430ccb666d','再宿崇國院和前韻二首  其一','許景衡','宋','宋诗','song-poetry','','[]','能詩老工部，好鍛狂中散。',24,'全唐诗/poet.song.78000.json','["能詩老工部，好鍛狂中散。", "相望千載間，未覺風流遠。"]'),
('8201ab53-73e4-450a-83fe-94257a21fabc','再宿崇國院和前韻二首  其二','許景衡','宋','宋诗','song-poetry','','[]','羣山盡龍蟠，十駕客駑散。',24,'全唐诗/poet.song.78000.json','["羣山盡龍蟠，十駕客駑散。", "嗜酒愧陶潛，過橋煩惠遠。"]'),
('5cbb2704-dc96-4c85-bf15-febb53ea6d31','題坡竹','許景衡','宋','宋诗','song-poetry','','[]','勁節風霜日，平生忠義心。',24,'全唐诗/poet.song.78000.json','["勁節風霜日，平生忠義心。", "誰知身死後，寸墨市千金。"]'),
('592487b2-d329-4d4f-9255-f3f0a58c27e0','絕句  其一','許景衡','宋','宋诗','song-poetry','','[]','五載客河關，塵沙滿領間。',24,'全唐诗/poet.song.78000.json','["五載客河關，塵沙滿領間。", "扁舟下清阪，眼底是淮山。"]'),
('d80003a5-4d6a-4dd0-bea5-06c5487131c9','絕句  其二','許景衡','宋','宋诗','song-poetry','','[]','笑語三關去，扶持萬里歸。',24,'全唐诗/poet.song.78000.json','["笑語三關去，扶持萬里歸。", "情知是同載，爲底更霑衣。"]'),
('9516ceee-510c-4845-ad67-934b59624c75','江樓','許景衡','宋','宋诗','song-poetry','','[]','江水去無邊，江樓思渺然。',24,'全唐诗/poet.song.78000.json','["江水去無邊，江樓思渺然。", "西風掛帆席，一一是歸船。"]'),
('5e7e7226-18fc-426b-af21-a33c70282709','默室','許景衡','宋','宋诗','song-poetry','','[]','寶冠題榜意已到，竹閣作銘言豈多。',32,'全唐诗/poet.song.78000.json','["寶冠題榜意已到，竹閣作銘言豈多。", "入室人人知是默，誰知个裏有傾河。"]'),
('e1025053-4c09-43fd-8178-95d3dc729275','送人遊天台','許景衡','宋','宋诗','song-poetry','','[]','洞裏桃花無數開，玉人不肯放春回。',32,'全唐诗/poet.song.78000.json','["洞裏桃花無數開，玉人不肯放春回。", "未容梅福休官去，應怪劉郎獨自來。"]'),
('512dcb58-5534-46a0-876c-c56422f2c2f9','過寶勝哭雅師二首  其一','許景衡','宋','宋诗','song-poetry','','[]','鳳凰巖石最稜嶒，十載重來强一登。',32,'全唐诗/poet.song.78000.json','["鳳凰巖石最稜嶒，十載重來强一登。", "怪底巖前能寂寞，年來失却兩詩僧。"]'),
('0d6b245a-0f65-401b-8bed-e6af750cb8ed','過寶勝哭雅師二首  其二','許景衡','宋','宋诗','song-poetry','','[]','陳迹都來俯仰間，空堂遺像已斕斑。',32,'全唐诗/poet.song.78000.json','["陳迹都來俯仰間，空堂遺像已斕斑。", "白雲誰道無情劇，猶向山前自往還。"]'),
('894aad46-f37b-4c5f-bcb9-3d9e3153ab8c','借蘇子美畫像呈趙君','許景衡','宋','宋诗','song-poetry','','[]','鐡面蒼髯見舊詩，人間物色轉參差。',32,'全唐诗/poet.song.78000.json','["鐡面蒼髯見舊詩，人間物色轉參差。", "君家好本煩相示，要識滄浪晚步時。"]'),
('5df6761c-2904-4710-af2b-cf2ebe7d84a7','過襄城三首  其一','許景衡','宋','宋诗','song-poetry','','[]','公子言歸歲月深，絃歌猶自有遺音。',32,'全唐诗/poet.song.78000.json','["公子言歸歲月深，絃歌猶自有遺音。", "誰云故國無喬木，看取青青著作林。"]'),
('122add68-0d41-4202-980e-9bdb07d12273','過襄城三首  其二','許景衡','宋','宋诗','song-poetry','','[]','父老分明識長官，青衫綠鬢照朱顔。',32,'全唐诗/poet.song.78000.json','["父老分明識長官，青衫綠鬢照朱顔。", "故知廊廟經綸意，也似鳴琴百里間。"]'),
('ae7ca698-b50b-412f-8584-e575a2e510e8','過襄城三首  其三','許景衡','宋','宋诗','song-poetry','','[]','聞道愛民如愛兒，從教閭里作兒嬉。',32,'全唐诗/poet.song.78000.json','["聞道愛民如愛兒，從教閭里作兒嬉。", "紛紛行路皆垂白，知是當年不忍欺。"]'),
('ceb89df8-df99-461e-b531-2500422c1657','題野鵲','許景衡','宋','宋诗','song-poetry','','[]','羽物從來數易完，張生妙筆更多端。',32,'全唐诗/poet.song.78000.json','["羽物從來數易完，張生妙筆更多端。", "東山詩老今黄壤，野鵲寒林忍更看。"]'),
('17ec7a39-cdfc-4f50-a23a-b355950778e2','題醒心亭','許景衡','宋','宋诗','song-poetry','','[]','醒心亭下水悠悠，歸棹匆匆更少留。',32,'全唐诗/poet.song.78000.json','["醒心亭下水悠悠，歸棹匆匆更少留。", "何日飄然五湖去，醉吟還得過浮邱。"]'),
('a03e54d6-1675-4b11-819f-91d3da3db07a','春日','許景衡','宋','宋诗','song-poetry','','[]','春日尋常醉不醒，而今春日若爲情。',32,'全唐诗/poet.song.78000.json','["春日尋常醉不醒，而今春日若爲情。", "青絲纖手成陳跡，舉案齊眉已隔生。"]'),
('b775b565-f919-425e-b258-b780149a60af','梅','許景衡','宋','宋诗','song-poetry','','[]','朔風吹雪滿長安，閩越生來不識寒。',32,'全唐诗/poet.song.78000.json','["朔風吹雪滿長安，閩越生來不識寒。", "却有暗香飄六出，不須借與外人看。"]'),
('3f748159-0783-46ec-b81b-e5b142b37d5d','送筍與經臣','許景衡','宋','宋诗','song-poetry','','[]','短短犀簪尚带泥，重重書卷已參差。',32,'全唐诗/poet.song.78000.json','["短短犀簪尚带泥，重重書卷已參差。", "題詩分贈君應笑，何似東坡噴飯時。"]'),
('d29d5522-aec4-4ecd-a457-02e3aa3b52e8','再次江左司韻四絕句  其一','許景衡','宋','宋诗','song-poetry','','[]','平生學道竟何知，不覺垂垂兩鬢絲。',32,'全唐诗/poet.song.78000.json','["平生學道竟何知，不覺垂垂兩鬢絲。", "六義賴公多比興，一言猶足慰朝饑。"]'),
('54776f11-d4bf-4886-865c-67d257e40bf3','再次江左司韻四絕句  其二','許景衡','宋','宋诗','song-poetry','','[]','春風吹面立多時，此句誰知好色絲。',32,'全唐诗/poet.song.78000.json','["春風吹面立多時，此句誰知好色絲。", "未許飲河同鼴鼠，只消翫味已忘饑。"]'),
('1bd8280e-38af-4b3d-8d2b-3f2abcdbb852','再次江左司韻四絕句  其三','許景衡','宋','宋诗','song-poetry','','[]','玉粉盛來祗小盤，仁人覽物不徒然。',32,'全唐诗/poet.song.78000.json','["玉粉盛來祗小盤，仁人覽物不徒然。", "豈惟廪賜皆民力，牛磨團團轉幾千。"]'),
