('41399c1b-46e2-4fb0-ad79-3b2f013e6376','寄盧中甫四首  其三','許景衡','宋','宋诗','song-poetry','','[]','朝米暮鹽何日休，塵埃滿面霜滿頭。',32,'全唐诗/poet.song.78000.json','["朝米暮鹽何日休，塵埃滿面霜滿頭。", "草堂竹閣壓秋水，幾時和月弄扁舟。"]'),
('af099d39-48b3-460e-adfa-b88137a50921','寄盧中甫四首  其四','許景衡','宋','宋诗','song-poetry','','[]','制勝關頭雪未融，崆峒山下又春風。',32,'全唐诗/poet.song.78000.json','["制勝關頭雪未融，崆峒山下又春風。", "此身不及涇川水，漾絮飄花日向東。"]'),
('b5482b49-70f1-4386-abb5-7139c6069805','寄筆墨紙兄長絕句三首  其一','許景衡','宋','宋诗','song-poetry','','[]','最憐修貢自峨岷，拜賜中天雨露新。',32,'全唐诗/poet.song.78000.json','["最憐修貢自峨岷，拜賜中天雨露新。", "好爲先生載嘉句，却愁紙價湧京塵。"]'),
('b4c6df63-3204-4e9a-b34c-dc72aa55203b','寄筆墨紙兄長絕句三首  其二','許景衡','宋','宋诗','song-poetry','','[]','潘生地下骨應朽，妙技猶藏天府中。',32,'全唐诗/poet.song.78000.json','["潘生地下骨應朽，妙技猶藏天府中。", "刀筆未應當好賜，不如分付與詩翁。"]'),
('ba4fa8e7-ffc8-485a-ab79-62677bda5c12','寄筆墨紙兄長絕句三首  其三','許景衡','宋','宋诗','song-poetry','','[]','刑名去取漫忉忉，慚愧官家五色毫。',32,'全唐诗/poet.song.78000.json','["刑名去取漫忉忉，慚愧官家五色毫。", "老矣弟兄無用處，只應警鋭屬兒曹。"]'),
('35813b5e-9cbe-42a5-9936-5b025372f779','寸碧亭','許景衡','宋','宋诗','song-poetry','','[]','杖履尋常行樂處，不論小徑與幽亭。',32,'全唐诗/poet.song.78000.json','["杖履尋常行樂處，不論小徑與幽亭。", "誰知蒼莽千峰外，尚有仙山一點青。"]'),
('418f1802-9708-4ec7-8948-da81cc10078d','江','許景衡','宋','宋诗','song-poetry','','[]','江邊問舟子，潮落幾時回。',24,'全唐诗/poet.song.78000.json','["江邊問舟子，潮落幾時回。", "野店無燈火，還須明月來。"]'),
('10830604-9da9-48d2-8424-ec3d6b2331ac','繁叔見和再依韻謝之  其一','許景衡','宋','宋诗','song-poetry','','[]','曾錄新詩數百章，簡編從此有輝光。',64,'全唐诗/poet.song.78000.json','["曾錄新詩數百章，簡編從此有輝光。", "當年俱是江邊客，今日早爲天上郎。", "竹葉一樽魚似玉，梅花三弄月如霜。", "邊城樂事還隨分，莫教終朝有底忙。"]'),
('e3f46e60-2bf9-4381-9b8c-3097fe1cc0d3','繁叔見和再依韻謝之  其二','許景衡','宋','宋诗','song-poetry','','[]','分明喜色滿眉間，誰怕霜毛作老顔。',64,'全唐诗/poet.song.78000.json','["分明喜色滿眉間，誰怕霜毛作老顔。", "況有杯盤留客醉，不教風雨爲人慳。", "子真最愛橫塘水，居士新遷巾子山。", "唯有詩壇小工部，吾君未可放教閑。"]'),
('364a2eca-7a9d-4002-abcb-4fdfa414f789','送僧遊天台','許景衡','宋','宋诗','song-poetry','','[]','石梁天絕赤城深，影落滄溟幾萬尋。',32,'全唐诗/poet.song.78000.json','["石梁天絕赤城深，影落滄溟幾萬尋。", "金策若回聊爲說，慰予終老愛山心。"]'),
('5c2a67fd-5929-4a4f-bfb5-eb28b3f44737','鑑湖','許景衡','宋','宋诗','song-poetry','','[]','賀老舊時宅，平湖照眼明。',48,'全唐诗/poet.song.78000.json','["賀老舊時宅，平湖照眼明。", "魚蝦無遠近，菱芡自生成。", "歷歷疑猶見，紛紛盡肆耕。", "斯民日牢落，無路問魚並。"]'),
('76d7dff4-0d8e-40a5-8756-ccf26b6c2f2c','墨梅花三絕  其一','許景衡','宋','宋诗','song-poetry','','[]','園林颯颯正飛沙，欻見東風第一花。',33,'全唐诗/poet.song.78000.json','["園林颯颯正飛沙，欻見東風第一花。", "畫裏有立場還會麽，分明竹外一枝斜。"]'),
('a6e7f5c2-c3fb-4bb4-a3bc-4290d7ee9c2b','墨梅花三絕  其二','許景衡','宋','宋诗','song-poetry','','[]','柔條亂蕊照人寒，多少冰姿在筆端。',32,'全唐诗/poet.song.78000.json','["柔條亂蕊照人寒，多少冰姿在筆端。", "迥出暗香疏影外，詩人莫作一般看。"]'),
('d5c0702b-9425-47f8-9eff-61393ef585cb','墨梅花三絕  其三','許景衡','宋','宋诗','song-poetry','','[]','冰繭連槽無點翳，忽驚雪片滿寒枝。',32,'全唐诗/poet.song.78000.json','["冰繭連槽無點翳，忽驚雪片滿寒枝。", "須知造物生成處，也似毫端拂淡時。"]'),
('d3fd12e2-5d2a-4f72-af75-c070f7672415','先兄舊作梅花覓張先生畫因覽之愴然輒次其韻','許景衡','宋','宋诗','song-poetry','','[]','茂陵雪片追方好，亂點鉛華卻不宜。',32,'全唐诗/poet.song.78000.json','["茂陵雪片追方好，亂點鉛華卻不宜。", "多少人間春色在，未有寫盡向南枝。"]'),
('4e8b5f06-631b-4181-95c8-6ed14004e2e0','示師言民表','許景衡','宋','宋诗','song-poetry','','[]','二子追涼古寺東，陰陰綠葉散清風。',32,'全唐诗/poet.song.78000.json','["二子追涼古寺東，陰陰綠葉散清風。", "蓽門蝸舍日亭午，試問此風同不同。"]'),
('092cd746-4306-4867-a201-f30d9353b124','張帥進職再留敏叔有詩賀之次韻','許景衡','宋','宋诗','song-poetry','','[]','憶昔初辭九棘班，齊壇授銭氣桓桓。',64,'全唐诗/poet.song.78000.json','["憶昔初辭九棘班，齊壇授銭氣桓桓。", "邊民慣見平安火，天子新除侍從官。", "此去一年聊許借，從來五袴不愁寒。", "進賢自是平生志，看取他年頭上冠。"]'),
('2d8cf418-af53-4295-b9af-63546c628e58','論學','許景衡','宋','宋诗','song-poetry','','[]','咨爾學者，學古之道。',60,'全唐诗/poet.song.78000.json','["咨爾學者，學古之道。", "惟古善教，有倫有要。", "其學維何，致知格物。", "對身而誠，物我爲一。", "匪曰我私，推之斯行。", "親親長長，而天下平。"]'),
('f8059241-fbdb-47d2-8faa-0af9543a38c3','銘劉安節墓','許景衡','宋','宋诗','song-poetry','','[]','溫溫劉子其美璞，斯文有傳與敦琢。',64,'全唐诗/poet.song.78000.json','["溫溫劉子其美璞，斯文有傳與敦琢。", "始乎致知物斯格，沈涵充積卒自得。", "衆人巧智獨敦朴，衆人迫隘獨恢廓。", "衆人利欲獨淡泊，洞然無礙油然樂。"]'),
('938fb2cf-c710-409b-98a3-0843e8d3b29e','觀書有感','羅從彥','宋','宋诗','song-poetry','','[]','靜處觀心塵不染，閑中稽古意尤深。',32,'全唐诗/poet.song.78000.json','["靜處觀心塵不染，閑中稽古意尤深。", "周誠程敬應粗會，奧理休從此外尋。"]'),
('06f5ec33-1cda-4eee-a05f-21cc6432a570','自警','羅從彥','宋','宋诗','song-poetry','','[]','性地栽培恐易蕪，是非理欲謹於初。',32,'全唐诗/poet.song.78000.json','["性地栽培恐易蕪，是非理欲謹於初。", "孔顔樂地非難造，好讀誠明靜定書。"]'),
('d74dfe49-ea1c-4e42-807e-4e2b1514a6df','示書生','羅從彥','宋','宋诗','song-poetry','','[]','知行蹊徑固非艱，每在操存養性間。',32,'全唐诗/poet.song.78000.json','["知行蹊徑固非艱，每在操存養性間。", "此道悟來隨寓見，一毫物慾敢相關。"]'),
('4431d4ec-ec5b-4e24-9838-077a112ac58f','顔樂齋','羅從彥','宋','宋诗','song-poetry','','[]','山染嵐光带日黄，瀟然茅屋枕池塘。',32,'全唐诗/poet.song.78000.json','["山染嵐光带日黄，瀟然茅屋枕池塘。", "自知寡與真堪笑，賴有顔瓢一味長。"]'),
('9626cce2-7ddd-45dc-9e51-2937a57bdac2','邀月臺','羅從彥','宋','宋诗','song-poetry','','[]','矮作垣牆小作臺，時邀明月寫襟懷。',32,'全唐诗/poet.song.78000.json','["矮作垣牆小作臺，時邀明月寫襟懷。", "夜深獨有長庚伴，不許庸人取次來。"]'),
('a57d3d96-3cf6-474a-aa15-932db3f07387','送南劍王守歸  其一','羅從彥','宋','宋诗','song-poetry','','[]','三年政化被生民，甘雨祥風溢劍津。',32,'全唐诗/poet.song.78000.json','["三年政化被生民，甘雨祥風溢劍津。", "解組幡然賦歸去，攀轅無計可留恂。"]'),
('e5a01d5d-0f03-4fa2-93e7-56917a6c9b07','送南劍王守歸  其二','羅從彥','宋','宋诗','song-poetry','','[]','未把陽關三疊吟，且將謬句寫離心。',32,'全唐诗/poet.song.78000.json','["未把陽關三疊吟，且將謬句寫離心。", "千尋浩浩鐔溪水，別恨不知誰淺深。"]'),
('a2b1aa05-dbec-42c1-aaae-e41735739040','勉李願中五首  其一','羅從彥','宋','宋诗','song-poetry','','[]','聖道由來自坦夷，休迷佛學惑他岐。',32,'全唐诗/poet.song.78000.json','["聖道由來自坦夷，休迷佛學惑他岐。", "死灰槁本渾無用，緣置心官不肯思。"]'),
('e3beda39-cba3-4dbe-9660-01ead12a6d72','勉李願中五首  其二','羅從彥','宋','宋诗','song-poetry','','[]','不開雞犬鬧桑麻，仁宅安居是我家。',32,'全唐诗/poet.song.78000.json','["不開雞犬鬧桑麻，仁宅安居是我家。", "耕種情田勤禮義，眼前風物任繁華。"]'),
('fb35cf0d-1d05-4f71-83a1-5c66c7d59e4b','勉李願中五首  其三','羅從彥','宋','宋诗','song-poetry','','[]','今古乾坤共此身，安身須是且安民。',32,'全唐诗/poet.song.78000.json','["今古乾坤共此身，安身須是且安民。", "臨深履薄緣何事，祇恐操心近矢人。"]'),
('01cbc7dc-dd8a-4746-b7cb-b9870452614a','勉李願中五首  其四','羅從彥','宋','宋诗','song-poetry','','[]','彩筆書空空不染，利刀割水水無痕。',32,'全唐诗/poet.song.78000.json','["彩筆書空空不染，利刀割水水無痕。", "人心但得如空水，與物自然無怨恩。"]'),
('32787adf-ebf2-4ff3-8f8b-23660885255c','勉李願中五首  其五','羅從彥','宋','宋诗','song-poetry','','[]','權門來往絕行蹤，一片閑雲過九峰。',32,'全唐诗/poet.song.78000.json','["權門來往絕行蹤，一片閑雲過九峰。", "不似在家貧亦好，水邊林下養疏慵。"]'),
('ebf01f04-5c0a-4812-acbb-a8b685d946e7','自述','羅從彥','宋','宋诗','song-poetry','','[]','松菊相親莫厭頻，紛紛人世只紅塵。',32,'全唐诗/poet.song.78000.json','["松菊相親莫厭頻，紛紛人世只紅塵。", "自憐寡與真堪笑，賴有清風是故人。"]'),
('f55c6302-cb17-4fea-b970-3d054ae29c3a','題一鉢菴','羅從彥','宋','宋诗','song-poetry','','[]','可憐萱草信無憂，誰謂幽蘭解結愁。',32,'全唐诗/poet.song.78000.json','["可憐萱草信無憂，誰謂幽蘭解結愁。", "欲得寸田斷荆棘，只消長伴赤松游。"]'),
('fe8867a6-4268-4692-b9a5-42e3c78e5b82','挽吉溪吳助教  其一','羅從彥','宋','宋诗','song-poetry','','[]','室富真儒業，門多長者車。',48,'全唐诗/poet.song.78000.json','["室富真儒業，門多長者車。", "明經方教子，得第已榮家。", "性守仍知分，天然不愛奢。", "百年成古昔，行路亦咨嗟。"]'),
('7baac382-442b-461c-848b-53dd22e4cf7f','挽吉溪吳助教  其二','羅從彥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','新生誇躑躅，舊德嘆凋零。',48,'全唐诗/poet.song.78000.json','["新生誇躑躅，舊德嘆凋零。", "冷带商巖月，光凌處士星。", "布衣難得祿，白首易窮經。", "追想今何在，溪流對洞庭。"]'),
('ec531aaf-5ab0-437f-9106-704db3683920','顔樂亭用陳默堂韻','羅從彥','宋','宋诗','song-poetry','','[]','平時仰止在高山，要以亭名樂內顔。',64,'全唐诗/poet.song.78000.json','["平時仰止在高山，要以亭名樂內顔。", "顛倒一生渾是夢，尋思百計不如閑。", "心齋肯與塵汙染，陋巷寧容俗往還。", "堅守簞瓢心不改，恐流乞祭向墦間。"]'),
('c0706fe6-8e66-4551-9155-7f4beb96a299','寄傲軒用陳默堂韻','羅從彥','宋','宋诗','song-poetry','','[]','自嗟踽踽復涼涼，糊口安能仰四方。',64,'全唐诗/poet.song.78000.json','["自嗟踽踽復涼涼，糊口安能仰四方。", "目送歸鴻心自遠，門堪羅雀日偏長。", "家徒四壁樽仍綠，侯戶千頭橘又黄。", "我醉欲眠卿且去，肯陪俗客語羲皇。"]'),
('c671ba13-440f-4858-9e5f-6c180db88283','濯纓亭用陳默堂韻','羅從彥','宋','宋诗','song-poetry','','[]','十載猶緇京洛塵，歸歟那復厠朝紳。',64,'全唐诗/poet.song.78000.json','["十載猶緇京洛塵，歸歟那復厠朝紳。", "君今談笑青油幕，我但巍峨烏角巾。", "江漢更從尼父濯，衣冠寧羨屈原新。", "欲賡孺子滄浪詠，會意須還舍瑟人。"]'),
('25a7e96f-7d8f-4c40-a706-53518a121f1f','題靜亭','羅從彥','宋','宋诗','song-poetry','','[]','鼎創新亭靜更幽，四時景象鎮長留。',64,'全唐诗/poet.song.78000.json','["鼎創新亭靜更幽，四時景象鎮長留。", "端如和氣裏談笑，恍若春風中泳游。", "排闥山供藍色重，憑欄水擁壁光浮。", "我來登賞無窮趣，好把篇詩與唱酬。"]'),
('379b6034-f233-4ec4-b34a-42e5b964d821','送延年行','羅從彥','宋','宋诗','song-poetry','','[]','聖言天遠海潭潭，獨在潛心久泳涵。',64,'全唐诗/poet.song.78000.json','["聖言天遠海潭潭，獨在潛心久泳涵。", "猥念百家非己好，妄將一貫與君談。", "賢如賜也才知二，學若陳亢只得三。", "此道悮來因自足，卻隨鵬鳥話圖南。"]'),
('453d75dd-db47-45fc-8177-3cbb7ab4d23a','再用韻送延年','羅從彥','宋','宋诗','song-poetry','','[]','心源寂靜映寒潭，每欲操存更養涵。',64,'全唐诗/poet.song.78000.json','["心源寂靜映寒潭，每欲操存更養涵。", "顧我日思攀劇論，荷君時與得高談。", "眼前舊識知多少，物外深交沒二三。", "幸久相親頻握手，遽成分別又東南。"]'),
('e2545169-f425-4ebf-8c83-268faffaf8cd','和延年巖桂','羅從彥','宋','宋诗','song-poetry','','[]','幾樹芬芳檀與沉，枝枝若占郄家林。',64,'全唐诗/poet.song.78000.json','["幾樹芬芳檀與沉，枝枝若占郄家林。", "風搖已認飄殘菊，日照渾疑綴散金。", "仙窟移來成美景，東堂分去結清陰。", "我今不願蟾宮折，待到蟾宮向上吟。"]'),
('19ab1f3e-cc3f-4d9e-a469-3ccc6fbdc170','題德士退菴','羅從彥','宋','宋诗','song-poetry','','[]','牛頭山頂鏁煙霞，簷月松風即我家。',64,'全唐诗/poet.song.78000.json','["牛頭山頂鏁煙霞，簷月松風即我家。", "筏渡有情新活計，袋空無物舊生涯。", "已將黄葉分雙手，卻攟白茅占一窊。", "會得懶慵歸去路，索然忘鳥更忘花。"]'),
('46af27de-023c-4e9c-8137-b85c2b712b45','賀田溪張公遷居','羅從彥','宋','宋诗','song-poetry','','[]','華構經營占地靈，濃嵐環合數峰青。',64,'全唐诗/poet.song.78000.json','["華構經營占地靈，濃嵐環合數峰青。", "苟完公子方成室，趨訓兒孫已過庭。", "豈止一時誇壯麗，定知百世享安寧。", "顧惟善頌非張老，祇貢湯盤往日銘。"]'),
('26a8b19f-4082-4aec-8bd8-e484001dbf2c','和張公敘別古風','羅從彥','宋','宋诗','song-poetry','','[]','良工創新第，瀟灑侔洞府。',264,'全唐诗/poet.song.78000.json','["良工創新第，瀟灑侔洞府。", "經營未畢工，四面方興渚。", "蛟龍忽夜徙，空中震雷雨。", "親舊賀于門，主人迎孔戶。", "連喚鳳兒來，藏書幾多部。", "爲我張廣筵，酬賓酌以旅。", "人謂主公賢，敦朴嗤峻宇。", "規模出心匠，務卑由乃祖。", "欲圖久安逸，勿辭暫勞苦。", "忠孝闡門家，詩禮光族緒。", "居室云苟完，謙沖彌自處。", "玉石不分別，鶴雞謾爲侶。", "顧予局促輩，鄉評少推許。", "嘗遊莊嶽間，喜作齊人語。", "何幸天相之，幡然交鄒魯。", "早年欽大名，馳書聊以序。", "比來揖清風，談笑揮玉麈。", "見之名利盡，久侍豈無補。", "素志以深酬，青眼猶相與。", "默念湯盤頌，未爲傾肺腑。", "何當惠古風，錦繡施牋楮。", "妙曲誠寡和，取則憑柯斧。"]'),
('750de20f-0205-4b1a-92ee-eff32943a0fd','翠雲巖次陳默堂韻','羅從彥','宋','宋诗','song-poetry','','[]','濟渡遊丹洞，穿林惹翠雲。',48,'全唐诗/poet.song.78000.json','["濟渡遊丹洞，穿林惹翠雲。", "邇來多野趣，殊覺少塵紛。", "笑日花迎客，臨巖鳥喚羣。", "真機皆自得，此道與平分。"]'),
('b6351c50-6fa8-4cb3-8396-52e5003ce8ef','嘲茶山','葛勝仲','宋','宋诗','song-poetry','','[]','吳興紫笋，實産顧渚。',120,'全唐诗/poet.song.78000.json','["吳興紫笋，實産顧渚。", "唐昔底貢，闞山芽吐。", "隼旟出臨，虎巖親駐。", "鄰邦刺史，金匏相遇。", "木瓜堂前，穿雲浥露。", "烹蒸包發，及春未暮。", "天子稱珍，分甘當路。", "今則不然，名毀勢去。", "金沙弗湘，玉食弗御。", "敷榮窮山，牢落誰顧。", "如女失寵，空閨自嫮。", "請以千金，買長門賦。"]'),
('c4758eb5-8ebd-4721-b05e-38f294edfad0','茶山解嘲','葛勝仲','宋','宋诗','song-poetry','','[]','衆萬之生，於世暫寓。',120,'全唐诗/poet.song.78000.json','["衆萬之生，於世暫寓。", "一僨一興，孰知其故。", "退黜奚戚，進升奚慕。", "豈以通塞，顧改常度。", "有如我翁，昔嘗掀翥。", "戴纚垂纓，去天尺五。", "今屏山城，亦皆時數。", "左右佩劍，疇可笑侮。", "翁具退省，前言大悞。", "用與不用，智力何預。", "幸同此邦，邂逅承晤。", "結爲金蘭，安此貧素。"]'),
('731633be-5a4e-48b2-8870-1d47378499bb','閱訟訴忽疲起卧少頃復視事','葛勝仲','宋','宋诗','song-poetry','','[]','平明坐早衙，投缿來相踵。',60,'全唐诗/poet.song.78000.json','["平明坐早衙，投缿來相踵。", "訟牘鼠雀暗，吏行鳬鶩擁。", "外臺竦風稜，檄至亟須捧。", "以身爲形役，劾去顧未勇。", "病骨痩欒欒，衰髮希種種。"]'),
('95b76c0b-1dc3-4996-9c84-f40e33986ef3','送鄧寧民罷瑕丘簿','葛勝仲','宋','宋诗','song-poetry','','[]','火雲燒晴空，大暑金石流。',192,'全唐诗/poet.song.78000.json','["火雲燒晴空，大暑金石流。", "行人口生烟，千里無停輈。", "胡爲趣遵路，僚好挽莫留。", "自言爲升斗，往日辭親遊。", "兒嬉膝前歡，三載不可求。", "所得較所失，輕重真不侔。", "于茲滿秩歸，子職冀稍修。", "微官亦何樂，觸事有庶尤。", "米鹽聒雙耳，簿領昏兩眸。", "畏首復畏尾，人役不得休。", "豈無讀書暇，頃刻但少偷。", "幸此案上歷，數日獲到頭。", "白雲已在眼，喜色津津浮。", "我亦厭羈官，如苦南冠囚。", "羡子有行色，去若登崑丘。", "更書縱未下，投劾行當謀。"]'),
('c77c142a-c135-412f-bb38-e99497d191f3','次韻良器真意亭探韻','葛勝仲','宋','宋诗','song-poetry','','[]','我愛陶淵明，脫穎深天機。',288,'全唐诗/poet.song.78000.json','["我愛陶淵明，脫穎深天機。", "叢菊遶荒徑，五柳搖幽扉。", "生逢卯金興，典午勢已非。", "著書但甲子，歲晚頻歔欷。", "仕宦聊復爾，樽酒真焉依。", "南畝猶種秫，西山同採薇。", "浩歌歸去來，熹微恨晨暉。", "迷途往莫諫，今是庶可幾。", "蓄琴但取意，不施絃與徽。", "觀其四八目，賢喆在所希。", "出處固有意，夫豈輕行違。", "誰云憚束带，辭榮俄拂衣。", "念彼同産人，撫視因遄歸。", "平生共志趣，但有一翟妃。", "少陵罪責子，頗謂達道非。", "右丞鄙乞食，更以人我譏。", "乃知第一流，尚此知音稀。", "妙詩發天奥，流轉同衡璣。", "自謂處人境，喧無車馬騑。", "心與塵事遠，地偏堪遁肥。", "東籬秋色晚，悠然望翠微。", "真意不可辨，佳氣隨鳥飛。", "詩辭向千載，凛凛猶光輝。", "我生但睎驥，望之有等威。"]'),
('6bfc12d5-cc19-4d0c-8871-1935c714d435','送寧守罷任赴闕四首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','材大多不容，論剛苦難受。',96,'全唐诗/poet.song.78000.json','["材大多不容，論剛苦難受。", "儒玄閱三朝，偉馮今白首。", "胸中有藏室，設張動掣肘。", "人言專城樂，聊結新安綬。", "獨喜衆毀言，不及河東守。", "三年四寶堂，紅梅傾白酒。", "出處固有在，兒輩浪奔走。", "豈復恨典籤，得州大如斗。"]'),
('a5336533-2e3e-42d6-9ffb-723abd6e4be5','送寧守罷任赴闕四首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','老人聚扶杖，兒啼使君前。',96,'全唐诗/poet.song.78000.json','["老人聚扶杖，兒啼使君前。", "習知使君清，一觴代一錢。", "六城十萬户，焉依刺史天。", "刑清艾作韠，俗朴蒲爲鞭。", "赭衣入佗郡，關户得晏眠。", "州鄉大作社，擊壤歌康年。", "左轓忽照路，更借知無緣。", "願公治者廣，此惠周幅員。"]'),
('7bd15c28-b389-4d83-8bef-3a50fa32b97e','送寧守罷任赴闕四首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','陽城拙催科，賈誼困遷謫。',96,'全唐诗/poet.song.78000.json','["陽城拙催科，賈誼困遷謫。", "騎曹呼馬曹，罰滿何止百。", "一笑爲闊略，坐免投此幘。", "鈴齋父黨尊，均禮不賜隔。", "人疑典午公，豈嘗有此客。", "連年三露章，慰薦飛絡繹。", "自慚骨相屯，顧使議見格。", "途窮窘論報，紙札謾搖擘。"]'),
('e04de098-57cc-4a6a-89cc-1c35f8a03e2a','送寧守罷任赴闕四首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','紫陽如佳人，晻靄送征舳。',96,'全唐诗/poet.song.78000.json','["紫陽如佳人，晻靄送征舳。", "含愁入長眉，盡斂故時綠。", "語兒已在眼，歡迎走僮僕。", "舊社問枌榆，新逕開松菊。", "還家聊作客，行色催輦轂。", "同升紗籠人，拔士有豐禄。", "會當出水鏡，一洗凡眼肉。", "躋榮赤墀塗，雁門詩可復。"]'),
('20c97cd3-4667-4150-a1e8-9581dcfbba74','兖學叙舊呈子充','葛勝仲','宋','宋诗','song-poetry','','[]','羲和無停輪，年鬢日夜改。',240,'全唐诗/poet.song.78000.json','["羲和無停輪，年鬢日夜改。", "惟有金蘭心，歲晚依然在。", "頗憶四門舘，研席同諸生。", "聫名理朱穆，結駟留陽城。", "縞紵初定交，車裘容共敝。", "駿馬馳春風，休沐章臺市。", "年少未涉道，惟論場屋文。", "鼻息拂霄漢，心期勇風雲。", "春闈鎻儒仙，試席兩心競。", "閬仙時乞靈，孤懿肯移病。", "喜君先得桂，時我猶飄蓬。", "鳯凰黄鵠歎，振手國門東。", "離羣十周星，爲僚一都會。", "涵牛鼎烹鷄，邑小非材配。", "理縣不用譜，政如密與蒲。", "糗水代厨傳，木索閒庭除。", "肯憐冰子窮，夜凍午不粒。", "綈袍累故人，口腹煩安邑。", "更迂長者轍，来顧空宇中。", "坐令羈官興，不復嘆秋風。"]'),
('f7e0328c-1223-42ec-b3ee-05c2c22caac8','立秋日六兄將仕先入都赴銓試會飲東郊作詩送之','葛勝仲','宋','宋诗','song-poetry','','[]','缺月耿疏林，凉飈拂輕袵。',264,'全唐诗/poet.song.78000.json','["缺月耿疏林，凉飈拂輕袵。", "荒溪趣遵塗，客子敢安枕。", "自言赴銓府，試判取微廩。", "清時廣招延，選部雜流品。", "門子萃金張，文人富曹沈。", "春秋兩較試，器業一精審。", "探珠到淵洄，求金自沙墋。", "騰裝分區區，蓄志常懔懔。", "家翁昔初仕，恬退聲藉甚。", "求閒絕外慕，行義鄙中荏。", "以兹久淹蟠，通籍才十稔。", "飄然宦游倦，遽以歸休諗。", "優恩得世祿，綸告下綈錦。", "兄材濟世美，聖讀近天禀。", "所長皆蓋人，無一可鐫鋟。", "摛辭昔賢均，說經餘子噤。", "臨書蛇蚓結，搊琴魚鮪淰。", "辛勤客虞庠，藜藿就烹餁。", "謂當妙穿楊，百中羽皆飲。", "如何遭刖頻，歸步每踔踸。", "兹行定焚舟，已事空拾瀋。", "將期冠羣英，喜劇不能寢。"]'),
('5399efe4-7939-47ba-9661-7430992ab3f0','送友赴試鉅野送之西門時方有外舅之戚極目無聊歸不得卧作詩五首却寄以風雲入壯懷爲韻  其一','葛勝仲','宋','宋诗','song-poetry','','[]','三吳炊未熟，祗命挈挈東。',120,'全唐诗/poet.song.78000.json','["三吳炊未熟，祗命挈挈東。", "鉛刀一何補，糧食賦頖宫。", "寥寥坐空廬，寂寞如揚雄。", "引脰望南境，不及馬牛風。", "何如廣文飯，終歲與子同。", "年顔吾老矣，癡愚心尚童。", "子雖齒髪少，操行一老翁。", "豈獨友于厚，政賴博我功。", "儒玄各精詣，衮衮傾談叢。", "欲知不常處，乃在阿堵中。"]'),
('22b21135-c588-48ff-8873-f9aeb1ec3ea8','送友赴試鉅野送之西門時方有外舅之戚極目無聊歸不得卧作詩五首却寄以風雲入壯懷爲韻  其二','葛勝仲','宋','宋诗','song-poetry','','[]','此子早樹立，抗志高浮雲。',108,'全唐诗/poet.song.78000.json','["此子早樹立，抗志高浮雲。", "委蛇處州巷，頗以雋秀聞。", "挾書從我遊，追琢益自勤。", "便便經與史，用志初不分。", "疑篇了咄嗟，確論摧紛紜。", "文辭近道要，見者筆爲焚。", "差肩魯諸儒，藹藹揚清芬。", "秋風濟陽戰，足掃千人軍。", "只今呼賀酒，佇子歸策勲。"]'),
('64913733-00f9-4308-b21e-bcf634c5693c','送友赴試鉅野送之西門時方有外舅之戚極目無聊歸不得卧作詩五首却寄以風雲入壯懷爲韻  其三','葛勝仲','宋','宋诗','song-poetry','','[]','寒齋篁竹間，牆屋久不葺。',120,'全唐诗/poet.song.78000.json','["寒齋篁竹間，牆屋久不葺。", "旁穿及上漏，雨過滿床濕。", "忍饑哦詩書，亭午或未粒。", "先生自不飽，濡沫豈能及。", "出門有紛奢，囊空自羞澀。", "世事不如意，八九更論十。", "問君胡不歸，肄業乃其急。", "自言苦心志，更覺聦明入。", "誰能學仲卿，夜抱牛衣泣。", "說經已鏗鏗，青紫真可拾。"]'),
('0af38224-5b82-40c5-abce-043324a87700','送友赴試鉅野送之西門時方有外舅之戚極目無聊歸不得卧作詩五首却寄以風雲入壯懷爲韻  其四','葛勝仲','宋','宋诗','song-poetry','','[]','寥寥里選空，齪齪士風喪。',84,'全唐诗/poet.song.78000.json','["寥寥里選空，齪齪士風喪。", "狂瀾欲東之，汎濫不可障。", "詞場自衒鬻，相與計留放。", "夸毗徒一名，傾排至千狀。", "不知厲術業，徒欲擠輩行。", "黄生獨往資，風義古人抗。", "悠悠衰俗中，此士真可壯。"]'),
('7d87bb00-e9d6-4b52-84f0-8fabf2838e67','送友赴試鉅野送之西門時方有外舅之戚極目無聊歸不得卧作詩五首却寄以風雲入壯懷爲韻  其五','葛勝仲','宋','宋诗','song-poetry','','[]','江南一紙書，沉憂割中懷。',132,'全唐诗/poet.song.78000.json','["江南一紙書，沉憂割中懷。", "嗟予足憂患，生世苦不諧。", "匆匆子行色，適與遠訃偕。", "破涕彊出祖，尊酒不及排。", "還歸坐講肄，寒篠搖空齋。", "推門誤相從，忽驚形影乖。", "誰云阻一舍，目斷真天涯。", "念子早自力，清明播朋儕。", "觸熱赴夷路，跨馬脚不鞋。", "自言取鄉送，通顯資其階。", "臨别何以贈，手板裁香楷。"]'),
('fcd33467-7b7e-4e75-a4fb-ae7fff8f744a','寄題長安譚損之遐觀閣','葛勝仲','宋','宋诗','song-poetry','','[]','乾坤一浩蕩，小智自窘拘。',96,'全唐诗/poet.song.78000.json','["乾坤一浩蕩，小智自窘拘。", "低徊褌中蝨，齷齪轅下駒。", "達人獨矯首，抗志在八區。", "歸来繞荒徑，所喜覺迷途。", "時讀穆滿傳，乍觀山海圖。", "林木凈交蔭，所見與道俱。", "誰能遠羈宦，五斗一丈夫。", "築閣者誰子，無乃柴桑徒。"]'),
('adbe6803-2ac0-46bc-ac47-461e22298097','次韻張宏道勸釋奠致齋','葛勝仲','宋','宋诗','song-poetry','','[]','齋居屏塵務，况復儒宫清。',120,'全唐诗/poet.song.78000.json','["齋居屏塵務，况復儒宫清。", "木落必糞本，祭菜敢不誠。", "瑚簋見三代，錯落羅兩楹。", "骨冷破夢境，虛窗坐黎明。", "祠官趣盥頮，珊然環佩聲。", "巍巍素王像，視若四海營。", "當時杏壇士，與享彯華纓。", "樂教属昭代，弟子陳歌笙。", "端如從陳蔡，琴舞紛縱横。", "元功流萬祀，德大遍諸生。"]'),
('945ecb7a-7cce-4369-b7b0-0c6bee6ebec1','次韻盧行之知原見贈','葛勝仲','宋','宋诗','song-poetry','','[]','元豐詩禮將，勲略傳萬口。',156,'全唐诗/poet.song.78000.json','["元豐詩禮將，勲略傳萬口。", "長城國西陲，寄託十年久。", "折箠笞黠羌，游魂屢窮走。", "羊公緩裘带，李廣静刁斗。", "黑頭已青雲，日昃笑擊缶。", "陰功與忠諫，二俱宜有後。", "繩繩丈夫子，茂宰最稱首。", "不裁猶能裁，應有既盡有。", "丘墳三十車，習復不置手。", "尚友千載人，豈論骨已朽。", "芳蘭秀深林，嘉芑就菑畝。", "宜爲數旬客，顧作三日婦。", "行聞尺一來，內閣延枚叟。"]'),
('7c704254-5a90-4fd0-8d7d-6216aa56d23e','次韻季明','葛勝仲','宋','宋诗','song-poetry','','[]','我生任飄蕩，所向如虚舟。',192,'全唐诗/poet.song.78000.json','["我生任飄蕩，所向如虚舟。", "誰能涉險難，入此正急流。", "行止兩無累，自遂逍遙游。", "巉路豈不佳，夙意非所留。", "迎親四門舘，登道初麥秋。", "政喜寢門近，敢言征路悠。", "山陽雨連月，平陸不可求。", "居將雜蛙黽，渚不辨馬牛。", "淮湖共瀰漫，以爲行者憂。", "今朝好風色，歌笑輕陽侯。", "紅鱗上圉圉，可以供殽羞。", "便呼拍浮船，甘味苴兩頭。", "坐待缺月掛，玉斧亦可修。", "酩酊聊自彊，淹速非人謀。", "數程次京國，猶待半蓐收。", "相從共蒲酒，賴有嵇阮儔。"]'),
('360076c0-3664-4c81-88c5-17c13808febb','再和示季明','葛勝仲','宋','宋诗','song-poetry','','[]','劍不用置履，柏非可爲舟。',192,'全唐诗/poet.song.78000.json','["劍不用置履，柏非可爲舟。", "古來倜儻士，渠肯甘凡流。", "君材早邁往，華問馳交游。", "高文筆如掃，雋辨舌不留。", "白黑自了了，皮裏藏陽秋。", "擁卷得淵旨，奮辭祛繆悠。", "身雖不求人，政自人所求。", "恢恢有餘刃，所見無全牛。", "亨衢恐不免，位遇豈足憂。", "初官三語掾，審克裨藩侯。", "退公豐暇裕，問學日益羞。", "行爲孔獨誦，端以賈長頭。", "嗟余過立境，沒沒謝藴修。", "廣文一飯足，其他非所謀。", "勝境定時訪，良書亦可收。", "但恐與君别，無復往朋儔。"]'),
('8293ca75-45b2-4f97-9dc1-1943917f7e17','誦金剛經滿二藏偶作','葛勝仲','宋','宋诗','song-poetry','','[]','我誦大智度，非疾無日空。',96,'全唐诗/poet.song.78000.json','["我誦大智度，非疾無日空。", "銅爐海岸香，亦復充凈供。", "積數向洛义，而實未嘗誦。", "凡諸有爲法，實如幻泡夢。", "一字本不立，况有千百頌。", "不受一切法，乃簉預流衆。", "於法有所得，十八成不共。", "妙理端會心，筌蹄那復用。"]'),
('ac00caa5-a78f-4b37-b74c-8a153a4909b9','妙凈院','葛勝仲','宋','宋诗','song-poetry','','[]','入門無行路，十頃漲方塘。',132,'全唐诗/poet.song.78000.json','["入門無行路，十頃漲方塘。", "藉葉受微雨，瑟瑟瀉滄浪。", "石梁一何偉，延袤百肘長。", "臨流兩華屋，東西蔚相望。", "雲堂始斷手，潤蒸松桂香。", "弛檐諧雲卧，何殊贊公房。", "夜步庭除月，心與空水凉。", "世人侈居第，規永庇蒸嘗。", "墓木未及拱，破鬻何披猖。", "何如施給園，千載綿寶坊。", "君看寺前村，至今俞氏昌。"]'),
('9296bd95-b5d2-4ae5-9f49-16a397c2cf62','禪静寺','葛勝仲','宋','宋诗','song-poetry','','[]','古寺鄰曹崇，怪石羅庭户。',72,'全唐诗/poet.song.78000.json','["古寺鄰曹崇，怪石羅庭户。", "奇礓漫難名，鬰林不知數。", "集虚竦蒼桂，左紐真獨步。", "兩詩照丹壁，好在支與許。", "却坐留芳軒，松竹發佳趣。", "山行未覺疲，更問勞勞路。"]'),
('d22982e4-82d2-45e2-b010-97f8be2ee3ae','採芝菴明辨師求泉名以月光命之','葛勝仲','宋','宋诗','song-poetry','','[]','方池洌寒泉，湛湛纓可濯。',84,'全唐诗/poet.song.78000.json','["方池洌寒泉，湛湛纓可濯。", "其源出陽崖，其委則陰壑。", "齋盂給晨炊，茗椀共午酌。", "道人習水觀，趺坐閒兩屩。", "性水了真空，非以識心度。", "浮幢諸刹海，視身同不涸。", "爲名月光泉，永配一宿覺。"]'),
('0ccce9fe-08da-4831-9583-c24aa16f6ca9','己丑次梅溪樂平寺兄子宗丞嘗監鎮即寺爲廨卒官晚之東莊','葛勝仲','宋','宋诗','song-poetry','','[]','蘭陵華腴姓，數不到吾族。',108,'全唐诗/poet.song.78000.json','["蘭陵華腴姓，數不到吾族。", "何堪從子賢，變滅石火速。", "早搴東堂桂，宗寺副惇睦。", "迎親官就此，半載歡水菽。", "方開萬里塗，一蹶遽折軸。", "我時跼里居，十起愧骨肉。", "朅来訪遺蹤，徙倚寒溪曲。", "人與紫梅花，二俱不可續。", "憂端齊前山，東莊寫松竹。"]'),
('c5464f9d-0ec3-4f30-910a-8c2af30c0751','次去非韻簡元忠使君','葛勝仲','宋','宋诗','song-poetry','','[]','翻飛堕青冥，巖邑漫濡跡。',192,'全唐诗/poet.song.78000.json','["翻飛堕青冥，巖邑漫濡跡。", "脫無賢已交，久矣去移疾。", "興州天下士，奇節非碌碌。", "魁然索價高，未肯輕沽玉。", "居閒時過我，端若右尹夕。", "文詞天分工，沈詩更任筆。", "蟬連語入微，不覺聽更僕。", "舊交半廊廟，勲閥藏帝籙。", "毋寧一麾出，不屈數旬客。", "五十始過二，榮途尚努力。", "才資况加人，何止什與百。", "是事姑置之，秋日方在翼。", "鮮鮮黄金花，冷艷照墻屋。", "郊原沐時雨，枯槁蘇霑足。", "城南天息河，流水有令德。", "相攜共擊汰，泛此寒湜湜。"]'),
('c315ff92-72ad-4a89-b46d-4fcbfbc366ff','九月二十四日陪少藴左轄飲朱氏林亭以朱行中寄其弟詩爲韻席上同賦','葛勝仲','宋','宋诗','song-poetry','','[]','蕭晨天宇澄，雲物掃氛霿。',240,'全唐诗/poet.song.78000.json','["蕭晨天宇澄，雲物掃氛霿。", "寒飈振飛藿，策策商聲中。", "官散無町畦，出若孤雲縦。", "仰懷山中相，隱居鄰二仲。", "駕言訪精舍，連日食指動。", "午坐烹茶龍，夜飲燒燭鳳。", "殷勤數啗我，省煩慚閔貢。", "美哉澄空隄，松竹鎻巗洞。", "怪石初平留，嘉樹橐駝種。", "山水有清音，招隐詩可誦。", "初如叩清角，乍若聽幽美。", "窺臨已不惡，況乃陪營從。", "清談木霏屑，圓機盤走汞。", "清寒逼吟魄，不起梨雲夢。", "半生了官事，今假幸少空。", "坐有第一流，不飲宜自訟。", "人生行樂耳，急若奉漏甕。", "東山恐不免，衮職行登用。", "槎通天衢升，茅茹諸賢共。", "惟有數奇人，辛苦仍耘葑。"]'),
('266a38fa-911d-4628-958f-ff5cfc1044f9','蒙左轄復次韻見寄復賦一首','葛勝仲','宋','宋诗','song-poetry','','[]','四海吳興公，嗜學屏塵霿。',240,'全唐诗/poet.song.78000.json','["四海吳興公，嗜學屏塵霿。", "妙齡儀天朝，獻納言必中。", "軒軒雲鵬升，洋洋壑魚縱。", "內庭大手筆，傅班真伯仲。", "武庫富所藏，砥柱矻不動。", "骯髒妨居中，大觀俄歸鳯。", "歸来一丘壑，彈冠謝王貢。", "嶪峨懸霤山，窈窕琦玕洞。", "奇礓不待輦，桐竹已前種。", "神畀賈長頭，天扶孔獨誦。", "衡霍縮地来，林深聽幽哢。", "軒池攬風月，杖屨屏營從。", "山貲自足了，不待燒鉛汞。", "斯文未應喪，審象俄入夢。", "巖廊翊元化，告猷無日空。", "上游倚韜鈐，出聽秣陵訟。", "方將膾劉闢，行酒贏萬甕。", "急流自勇退，惟深閟神用。", "行藏亦何常，此道聖賢共。", "終爲巖野霖，且並苕溪葑。"]'),
('63f6e2cc-5f08-44ab-ae5f-dac78ce2c159','盆池放魚呈曹文中','葛勝仲','宋','宋诗','song-poetry','','[]','小魚如針鋒，大魚如柳葉。',120,'全唐诗/poet.song.78000.json','["小魚如針鋒，大魚如柳葉。", "舍之石斛中，潑潑逝鱗鬛。", "秋毫麩與籺，腹果意各愜。", "渺如在湖海，不歎杯水狹。", "笑之復自笑，邑小大邦攝。", "搖足已恐堕，一動不敢輙。", "廪人給五斗，饘粥周兒妾。", "雖然頗自適，攜杖園日涉。", "豈羡蟬冕窟，遷擢等常獵。", "漆園信知魚，非惟常夢蝶。"]'),
('f46acde0-fc92-411f-bc71-f418f74a93e2','辛卯次霧山大明院進士萬廷老介来謁','葛勝仲','宋','宋诗','song-poetry','','[]','石橋跨斯干，路轉得佛廟。',84,'全唐诗/poet.song.78000.json','["石橋跨斯干，路轉得佛廟。", "叩鐘集黑衣，迎我千指閙。", "龍宫五十軸，金碧爛相照。", "空翠霑我襟，冥濛認堂奥。", "無乃張公超，五里方術妙。", "鄰居一逢掖，作名屣爲倒。", "莫言山未深，終當隱玄豹。"]'),
('91f87a29-52ce-493e-8724-3a45258f8a5c','寄友卿窄韻一首','葛勝仲','宋','宋诗','song-poetry','','[]','昔子遊魯中，飄然起幽棲。',288,'全唐诗/poet.song.78000.json','["昔子遊魯中，飄然起幽棲。", "翛翛一書簏，長物無所攜。", "辛勤涉長道，足趼面目黧。", "自言寡聞識，走俗多沉迷。", "今不勇自奮，蹉跎將噬臍。", "類渇欲石髄，如矇想金篦。", "来簉胄子席，求言學端倪。", "嗟予淺聞道，太倉之一稊。", "松菊有荒徑，桃李無成蹊。", "胡能使糓似，每每頳顔低。", "晨昏不予舍，三歲改攝提。", "對案但苜蓿，有黍多無鷄。", "一笑爲流啜，甘若羊新刲。", "秋霜八九月，絺綌臨風凄。", "寧甘范叔寒，不求故人綈。", "夜窗經與史，短檠照栖栖。", "靡曼一不顧，端如金日磾。", "嘉子甚年少，老成同齒齯。", "照庭真玉樹，飣座稱佳梨。", "爲文頗挺拔，絕去翰墨畦。", "聲華出諸彦，籍籍喧青齊。", "遂收濟北薦，謂即辭蒿藜。", "如何尚齟齬，時命多乖暌。", "方今天子聖，隆學古與稽。"]'),
('e1802e14-cf85-4fb8-9696-29230c3bf86c','張周韓侍御遷居北市示詩次韻','葛勝仲','宋','宋诗','song-poetry','','[]','神羊厭峨冠，銅虎出分土。',120,'全唐诗/poet.song.78000.json','["神羊厭峨冠，銅虎出分土。", "一區久未卜，薄遽歸無所。", "寓居得爽塏，衆口粗安堵。", "委懷榮槁外，長歌樂韶武。", "自言倦霜臺，筆端有蕭斧。", "毋寧乞小愒，松菊問衡宇。", "未看武當山，聊踏南梁鼓。", "浮生皆寄耳，莫作飄流苦。", "要津況虚位，掀騰在仰俯。", "政恐尺一来，均人隔綏撫。"]'),
('fa4d0724-848f-4bb8-9bb3-94bb0a7dce9f','朱偃吹笛','葛勝仲','宋','宋诗','song-poetry','','[]','李謨美梁州，獨孤生竊笑。',144,'全唐诗/poet.song.78000.json','["李謨美梁州，獨孤生竊笑。", "聲既雜夷樂，疊復誤水調。", "區區許雲封，女子稱商肖。", "天寶小部樂，能使玉妃釂。", "論竹取雲夢，不老不可少。", "七月望一周，生伐以此料。", "韋郎衒名管，半曲裂數竅。", "風流渺無繼，是子差可教。", "安得君山翁，漁艇巴陵道。", "擫捻三五聲，萬籟發天妙。", "清音徹四山，猿鳥驚飛噭。", "大管藏合拱，直俟元君召。"]'),
('2c2d9afb-ecd2-4e9c-b747-11fb21008911','壬辰次靈峰山百福院','葛勝仲','宋','宋诗','song-poetry','','[]','豺虎縱鬰攸，此寺神獨赦。',96,'全唐诗/poet.song.78000.json','["豺虎縱鬰攸，此寺神獨赦。", "樓臺倚山腹，碧瓦粲相射。", "奔崖插雲霄，縮地見衡華。", "竹翠染僧裾，泉聲喧佛舍。", "峰巒佳有餘，顧揖真不暇。", "我欲陟山椒，嶝嶮未應怕。", "摩娑舊聖石，政恐嫌俗駕。", "感慨明義師，徘徊一悲咤。"]'),
('02a288f8-e2e0-41d8-a6a9-b8ceee3318af','披雲臺','葛勝仲','宋','宋诗','song-poetry','','[]','深公出東都，山色已清好。',120,'全唐诗/poet.song.78000.json','["深公出東都，山色已清好。", "流行滄江上，快意時絕倒。", "洗盡眼界塵，招提迹如掃。", "衆挽来靈山，世故亦相惱。", "平生愛山心，不厭更幽討。", "捫蘿開細岑，脫履藉豐草。", "聊煩坡陀石，坐此突兀老。", "是身端如雲，去住殊未保。", "孤峰起孤烟，晴湖漾晴昊。", "賓主兩忘言，可爲知者道。"]'),
('a67683bf-fab1-4e47-beab-a5e39a579e22','跋胡德輝詩卷','葛勝仲','宋','宋诗','song-poetry','','[]','一官三語掾，驅車大河北。',96,'全唐诗/poet.song.78000.json','["一官三語掾，驅車大河北。", "飯澀羹亦稀，哦詩寫胸臆。", "作者非難到，已自入閫域。", "郵筒遠相餉，我豈今衡尺。", "粗能擿隴雲，亦不誤雌霓。", "千里得行記，了了所見歷。", "士材有如此，磊落固易識。", "寄語直指公，勿作寒蟬默。"]'),
('fc84e8af-b731-480b-af4e-bf045b78d50e','德輝次舊韻見寄復和','葛勝仲','宋','宋诗','song-poetry','','[]','邗溝别清揚，十稔限南北。',96,'全唐诗/poet.song.78000.json','["邗溝别清揚，十稔限南北。", "羈游多面交，從誰吐心臆。", "初筵羣玉府，香譽藹區域。", "如何窽言加，進寸輙退尺。", "歸来賦郊居，邀客賞冰霓。", "青雲一蹙易，斜飛要游歷。", "水鏡豈無人，瑾瑜固易識。", "君子有常道，要不失語默。"]'),
('719caa0f-b71d-44f3-bb24-c015f1b33596','題柘城懷古亭','葛勝仲','宋','宋诗','song-poetry','','[]','陳本太姬封，卒以夏姬亂。',96,'全唐诗/poet.song.78000.json','["陳本太姬封，卒以夏姬亂。", "君臣同宣淫，父子並遘患。", "直諫洩冶死，詐忠巫臣竄。", "郢兵討少西，昊墟且爲縣。", "嗚呼女戎禍，陳祚僅如綫。", "餘波及羊舌，伯石實首難。", "我行徑株林，懷古一興歎。", "流波似當時，惟有城東渙。"]'),
('ef8a4e98-d683-4991-93b2-6c34e2fd14cf','癸巳次古浮山普慈寺','葛勝仲','宋','宋诗','song-poetry','','[]','老人百念冷，看山獨不足。',120,'全唐诗/poet.song.78000.json','["老人百念冷，看山獨不足。", "未能尋地肺，聊復訪天目。", "路出古浮山，木杪飛華屋。", "松迷突兀殿，雲鎻窈窕谷。", "高閣藏複道，朱欄穿屈曲。", "羲和隱崑崙，借此休騶僕。", "小摘園中蔬，充我屬饜腹。", "緬懷峨豸翁，草廬親卜築。", "意恃金匕藥，終亦戢一木。", "不如學無生，妙諦祖身毒。"]'),
('cbed7eb1-51a8-4454-8525-eae8696a699a','甲午次東天目山紫陽觀梁武初置昭明太子勒碑紀當時恩奬之盛','葛勝仲','宋','宋诗','song-poetry','','[]','蕭公老寺主，亦復知尋真。',132,'全唐诗/poet.song.78000.json','["蕭公老寺主，亦復知尋真。", "大同築精舍，招延羽衣賓。", "園囿廓數里，嚴更紛徼巡。", "東宫奮鴻筆，紀事傳堅珉。", "山基半吳境，高與帝所鄰。", "偉哉古石室，空洞容千人。", "當年許遠遊，自此升玉宸。", "至今雪山草，靈苖雜荆榛。", "幽池湛寒水，亦說棲龍鱗。", "靈物有變化，誰能窮其神。", "窺臨擬仙去，未信隔兩塵。"]'),
('57d78b2f-9fe4-4cad-a0d5-8b0de739bceb','乙未次普信院與首座惟表談道','葛勝仲','宋','宋诗','song-poetry','','[]','蓐食起紫陽，憩寺始亭午。',108,'全唐诗/poet.song.78000.json','["蓐食起紫陽，憩寺始亭午。", "清幽釋子居，山影落窗户。", "樓臺互相臨，雲石粲可覩。", "陰崖溜清泉，甘美過牛乳。", "山僧立勝事，争以筠筒股。", "表公久遊方，妙諦明佛祖。", "雖未衆拆床，已見屨滿户。", "相攜環翠堂，身覺度飛羽。", "登臨固已往，況乃真吾土。"]'),
('4962cc94-f5bc-43e2-af1a-aab85914cd8a','余謫沙陽地僻家遠遇寒食如不知蓋閩人亦不甚重其節也感而賦詩五首以杜子美無家對寒食五字爲韻  其一','葛勝仲','宋','宋诗','song-poetry','','[]','往歲遇寒食，親賓相與娛。',60,'全唐诗/poet.song.78000.json','["往歲遇寒食，親賓相與娛。", "飄零客異土，對之渾若無。", "豈不念佳節，寸心愁欲枯。", "花間有好鳥，勸我提胡盧。", "一醉聊自適，醉夢歸東吳。"]'),
('7bd672ab-ce64-4fab-9793-171620fa0310','余謫沙陽地僻家遠遇寒食如不知蓋閩人亦不甚重其節也感而賦詩五首以杜子美無家對寒食五字爲韻  其二','葛勝仲','宋','宋诗','song-poetry','','[]','異縣遇寒食，悵然懷我家。',60,'全唐诗/poet.song.78000.json','["異縣遇寒食，悵然懷我家。", "千里遙相望，各在天一涯。", "佳節無與同，冉冉悲年華。", "鳴禽花底聒，舞燕風中斜。", "物情各自在，羈束誠可嗟。"]'),
('06bdd5eb-8e75-4d07-a83c-88d7eaba73cd','余謫沙陽地僻家遠遇寒食如不知蓋閩人亦不甚重其節也感而賦詩五首以杜子美無家對寒食五字爲韻  其三','葛勝仲','宋','宋诗','song-poetry','','[]','天涯遇寒食，嘉節無與對。',60,'全唐诗/poet.song.78000.json','["天涯遇寒食，嘉節無與對。", "獨酌一盃酒，慷慨使心痗。", "来者復可追，既往那復悔。", "翛然畎畝心，敢忘犬馬愛。", "之推自欲隱，去去何所懟。"]'),
('90eb833d-2672-4bcf-b69f-a689d7b23298','余謫沙陽地僻家遠遇寒食如不知蓋閩人亦不甚重其節也感而賦詩五首以杜子美無家對寒食五字爲韻  其四','葛勝仲','宋','宋诗','song-poetry','','[]','嘉節遇寒食，春陰猶作寒。',60,'全唐诗/poet.song.78000.json','["嘉節遇寒食，春陰猶作寒。", "閩人不知重，渾作等閑看。", "餳粥不復煮，青楓誰與鑽。", "開窗延霽景，脩竹正團欒。", "翠眉雙侍女，對此一樽殘。"]'),
('8eb3f21c-44bb-4106-836a-e062a8f9b5bb','余謫沙陽地僻家遠遇寒食如不知蓋閩人亦不甚重其節也感而賦詩五首以杜子美無家對寒食五字爲韻  其五','葛勝仲','宋','宋诗','song-poetry','','[]','逐客已淒涼，矧復值寒食。',60,'全唐诗/poet.song.78000.json','["逐客已淒涼，矧復值寒食。", "花深日遲遲，院静春寂寂。", "雨餘山吐青，日落霞掃赤。", "浙江渺何在，三月無消息。", "棄置勿復陳，吾心乃如石。"]'),
('01499fc9-d658-46f4-b1e8-5cfafa4097d2','涉汝詩','葛勝仲','宋','宋诗','song-poetry','','[]','居官行兩周，出郭劣半里。',156,'全唐诗/poet.song.78000.json','["居官行兩周，出郭劣半里。", "名稱臨汝守，初未涉汝水。", "今朝破巨浪，萬頃寄一葦。", "源從天息山，此地乃其委。", "青嵩正北踴，紫邏復西峙。", "兩岸千萬峰，落影照清泚。", "下瀨劇迅速，舟輕如激矢。", "周南滯留恨，此假聊一洗。", "悵無周旋人，同載如郭李。", "似聞汝陰湖，揚塵清潁尾。", "醉翁漾舟處，無復碧染指。", "歲月供感概，人事有遷徙。", "兹水美洋洋，正堪行樂耳。"]'),
('18b8d0f1-4884-4055-8921-a89c8663117a','再和涉汝詩呈去非伯仲','葛勝仲','宋','宋诗','song-poetry','','[]','清汝如荆溪，不異我州里。',156,'全唐诗/poet.song.78000.json','["清汝如荆溪，不異我州里。", "奔流相豗蹙，敢謂衣带水。", "携賓泛漫汗，畫鷁延緣葦。", "出城散腰脚，朱墨逃紛委。", "却望城中塔，烟林隱孤峙。", "何人貎清景，墨筆可就泚。", "幽尋要關楗，善飽未遺矢。", "塵纓政堪濯，凡髓亦可洗。", "不須學東山，韶顔載桃李。", "顧當似白傅，玉粒炊船尾。", "膾縷斫鮮鱗，遣客動食指。", "風流得意事，一官不願徙。", "脱有戚戚時，晤言消之耳。"]'),
('29f8797b-9442-4972-ac87-da8bfb3c9000','送姪元延之官','葛勝仲','宋','宋诗','song-poetry','','[]','浮游五嶺南，屐裙遍遷客。',96,'全唐诗/poet.song.78000.json','["浮游五嶺南，屐裙遍遷客。", "寵以鼇冠詩，獨步文章伯。", "十年未得調，浪有聲華白。", "來寜未死叔，知費幾馬策。", "相携泛清汝，壺酒映山碧。", "肯嗣陳留風，一笑飲爲劇。", "清途子初延，我老欲投劾。", "出處政參辰，此歡寜易得。"]'),
('46e14f47-08dc-4aef-b235-c1f8dbe438e3','俞居易兄弟並時爲屬邑長示其父所藏東坡送行詩用其韻跋卷末','葛勝仲','宋','宋诗','song-poetry','','[]','吾州兩支邑，伯季俱鳴琴。',72,'全唐诗/poet.song.78000.json','["吾州兩支邑，伯季俱鳴琴。", "清談一傾倒，亹亹正始音。", "文室賴芝蘭，藥籠資桂參。", "猥示晏楹書，什襲緘藏深。", "好事識雅趣，揚美知孝心。", "躋榮荷門基，行矣勳業尋。"]'),
('8962ca89-129d-4ec4-ad28-9b244cc4d637','戊戌次福勝院','葛勝仲','宋','宋诗','song-poetry','','[]','錦溪足墟落，高陸推繁華。',96,'全唐诗/poet.song.78000.json','["錦溪足墟落，高陸推繁華。", "豈惟邑屋富，政自山水佳。", "幽清背人境，千柱梵王家。", "巍巍二子亭，雲表飛簷牙。", "我生功名忤，巖壑爲生涯。", "山僧類祝田，施薄求者奢。", "乞書鳴刹疏，無鵝惟潑茶。", "一笑爲涉筆，勿笑蟠秋蛇。"]'),
('42c7aa87-1f94-486c-a573-4657b869ba42','比作青蘿山塔記并徐敏求墓銘皆蒙宏道爲書作詩以謝','葛勝仲','宋','宋诗','song-poetry','','[]','文苑無飛聲，碑板謬見赴。',84,'全唐诗/poet.song.78000.json','["文苑無飛聲，碑板謬見赴。", "結因時佞佛，書美間諛墓。", "從僚乞正書，見許不嫌屢。", "虞筋與柳骨，濃纖皆合度。", "浮海觀鴻戲，抉石逢猊怒。", "吾文敢言絕，驥尾蠅所附。", "它年翰墨場，不朽知有助。"]'),
('39727178-0602-4956-92e2-b3322aac52ca','次長清寺','葛勝仲','宋','宋诗','song-poetry','','[]','迎賓一紅亭，棟宇飛半嶺。',108,'全唐诗/poet.song.78000.json','["迎賓一紅亭，棟宇飛半嶺。", "松筠引幽步，以漸入佳境。", "陰風起澗壑，凛冽噤蛙黽。", "歸雲擁僧裓，飛溜入茶鼎。", "搘笻薰風閣，玉溪兩峰並。", "中闕認牢山，一點煙鬟整。", "我來見所見，賫恨在俄頃。", "丘樊絕泥滓，鍾鼎值機穽。", "老逐黑衣居，此心真炯炯。"]'),
('9d9cba3d-1eca-43f7-b735-beabccba59a1','至南陽却寄吳興諸僚','葛勝仲','宋','宋诗','song-poetry','','[]','震州推不去，游食歲月久。',60,'全唐诗/poet.song.78000.json','["震州推不去，游食歲月久。", "尺一從天來，換作秦頭守。", "迎新無竹馬，記舊已芻狗。", "迂愚敢護前，警發賴鞭後。", "獨坐百花堂，還憶百花酒。"]'),
('aa29932c-f26e-4c41-bd21-742d271d704d','與襄陽太守張亞仲泛漢江','葛勝仲','宋','宋诗','song-poetry','','[]','春波漲醱醅，綠淨疑染黛。',120,'全唐诗/poet.song.78000.json','["春波漲醱醅，綠淨疑染黛。", "神女昔江臯，翫珠仍解珮。", "沙光射目明，浪影摇風碎。", "樂哉今日遊，放溜舞滂湃。", "華觴挹空闊，疊鼓助擊汰。", "仰視白銅堤，岑樓飛綵繪。", "遊女凭危欄，紛若五家隊。", "真想謝窘拘，意有千里快。", "遠岸指煙藍，飛流羅水磑。", "尚想競渡時，千船唱何在。"]'),
('d6abe8a8-abcd-4e0d-b1a3-3bab016b4a82','襄陽大悲院作','葛勝仲','宋','宋诗','song-poetry','','[]','善財叩補陀，大千一弹指。',120,'全唐诗/poet.song.78000.json','["善財叩補陀，大千一弹指。", "我行無神足，重趼二百里。", "中年逢百罹，所欠但一死。", "稽首聞薰王，覬以俗障洗。", "魚山彊讚述，文污梵書庋。", "自憐迷本聞，云何見大士。", "覺與所覺空，根脱不用耳。", "圓融聲度垣，變現月映水。", "臂目恒河沙，如幻本一理。", "以是見觀音，文殊亦如是。"]'),
('1b99e3e7-4710-4e5f-88af-97f33b5c9bf8','乾明院作','葛勝仲','宋','宋诗','song-poetry','','[]','我欲乞襄陽，驅車峴山址。',144,'全唐诗/poet.song.78000.json','["我欲乞襄陽，驅車峴山址。", "文弔杜征南，酒酹羊叔子。", "披榛訪二碑，事辭俱俊偉。", "高賢千載後，遺魄猶登此。", "一官推不去，事故違願始。", "不如造乾明，山名亦相似。", "交流千斛乳，未減漢江水。", "遐眺真不惡，悲傷未燭理。", "湮沒與垂名，趨死皆一軌。", "我與同遊人，痛飲共擇旨。", "生前一杯重，恨山無石髓。", "預憂名不傳，却笑鄒從事。"]'),
('c08a6d68-817c-4446-a37e-d72f8a87057d','遊峴山','葛勝仲','宋','宋诗','song-poetry','','[]','山隨宇宙結，千古真苒苒。',120,'全唐诗/poet.song.78000.json','["山隨宇宙結，千古真苒苒。", "登臨足攬勝，兹來余復忝。", "山椒聳太華，夷路謝躋險。", "溶溶鴨頭水，綠淨衣可染。", "漁師網槎頭，盡以紅鮮掩。", "金刀鱠縷飛，來佐華觴灔。", "前修俱鬼錄，勲閥謾琬琰。", "谷虚禽響答，月皎煙華斂。", "同登幸曠士，形迹孰拘檢。", "長嘯揖清流，一洗鄒湛諂。"]'),
('001d7014-1e2e-47ba-986c-a8ab59944511','次韻葉夢得遊西余山','葛勝仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋霖喜新霽，裹飯山中遊。',240,'全唐诗/poet.song.78000.json','["秋霖喜新霽，裹飯山中遊。", "遥指大夫橋，閒泛野人舟。", "追隨得勝客，雅趣同滄洲。", "山路已清絕，顥氣况蓐收。", "亂石蹲狠羊，蒼官聳髯虯。", "古寺亦何有，森森瀟洒侯。", "忘懷一笑粲，更以大白浮。", "翰林廊廟姿，席珍韞天球。", "如何問三徑，更復尋一丘。", "升高澀投足，陟險眩迴眸。", "洞庭四萬頃，旁占鐺脚州。", "中有東西山，千奴熟霜秋。", "孤亭快寫望，欲去更少休。", "菟裘便可卜，何必依先疇。", "徘徊共懷古，徂歲真如流。", "封侯昔此地，顧余乃諸劉。", "一朝失茅土，窘急須人周。", "雍門曲池嘆，事往将何求。", "雲木餘參錯，烟巖自深幽。", "人生行樂耳，慎勿曲如鈎。"]'),
('15de24a9-6b57-4193-8d7a-5f3b51f2d450','柏悦堂宴集晚移望嶽亭德升有詩復次韻','葛勝仲','宋','宋诗','song-poetry','','[]','陰森美章園，爽塏背塵陌。',240,'全唐诗/poet.song.78000.json','["陰森美章園，爽塏背塵陌。", "紛紛辟疆家，勝處此其伯。", "登危覧幽奇，寬敞盪喧窄。", "層層綠陰暗，中有孤花拆。", "三品玩伏虎，兩部當鳴蟈。", "主人延客眼，清映壺觴碧。", "茂宰工撥煩，恢恢奏刀騞。", "議郎兼語掾，闔府畏跼蹐。", "仇梅諸鉅公，燕笑歡一席。", "蹇予但空餐，營職無半策。", "文墨彊抽身，林池同息跡。", "金火爭伏見，執熱如焚炙。", "頗願百斛船，浮浮兩頭拍。", "嶽雲插晴空，移尊及未夕。", "清飈起四座，肅肅生羽翮。", "人生不謀歡，带眼計月瘠。", "誰能較榮槁，瑣尾論干澤。", "相從飲文字，一笑百憂釋。", "歌呼到爾汝，坐待霜月白。", "歸軒踏清影，光謝紗籠赫。"]'),
('00387ab1-f4a2-44e7-9c32-ba1b358f11a0','幽居夙興','葛勝仲','宋','宋诗','song-poetry','','[]','宴安毒於鴆，嗜睡真成蛇。',96,'全唐诗/poet.song.78000.json','["宴安毒於鴆，嗜睡真成蛇。", "攬衣待明發，是味豈不佳。", "天宇自澄穆，羣囂肅無譁。", "喔吚雞一鳴，衆星猶撒沙。", "皂莢頮頭目，楊枝清齒牙。", "爐中結願香，凈几對名花。", "澄懷覩道祕，浮念無由邪。", "欠伸起三昧，雲錦升朝霞。"]'),
('dacbf850-e77d-4f87-9ba9-c9d10d459d63','蒙莫伯鎔餉酒携即菁村元舉山荘賞菊坐客皆稱歎以詩二首謝  其一','葛勝仲','宋','宋诗','song-poetry','','[]','野飲政自樂，何庸拘束交。',96,'全唐诗/poet.song.78000.json','["野飲政自樂，何庸拘束交。", "窮居闕醇旨，逼此歲欲凋。", "冷仙歘照坐，開嘗驚韻高。", "秋空映黄菊，氣澄掃微霄。", "携之壽佳客，豈諱十里勞。", "供釀者誰子，頗疑人姓焦。", "三杯反淳朴，一醆破鬰陶。", "酒材兼譜至，我醉吟今朝。"]'),
('716d5576-9da8-4004-a098-87ddc5bb0f94','蒙莫伯鎔餉酒携即菁村元舉山荘賞菊坐客皆稱歎以詩二首謝  其二','葛勝仲','宋','宋诗','song-poetry','','[]','迷塗不自覺，坐見六秩交。',96,'全唐诗/poet.song.78000.json','["迷塗不自覺，坐見六秩交。", "霜髪凛無幾，况此日夜凋。", "所寄在酒盞，傾銀不辭高。", "澆我磊塊胸，那復氣干霄。", "手開赤泥封，不辦呼孟勞。", "乍紓愁膓回，亦沃渴肺焦。", "君甚似江州，愧我非姓陶。", "爲僚且親串，酌我非一朝。"]'),
('789a62e7-c2ca-49c0-8d43-482e1b9488d4','謝洛師蔡尹餉酒','葛勝仲','宋','宋诗','song-poetry','','[]','叩門赤縣尹，來餉青州酒。',108,'全唐诗/poet.song.78000.json','["叩門赤縣尹，來餉青州酒。", "底貢上天閽，餘瀝到衰朽。", "開嘗正及卯，醇旨異失酉。", "公不數瑶泉，家還卑玉友。", "我時苦無悰，愁緒不論斗。", "紛紛方寸亂，飛絮起風柳。", "呼兒共一尊，盎盎純氣守。", "豈惟詩膽大，更覺魔軍走。", "寄謝魏陽元，頻望掃愁帚。"]'),
('733c2baf-2046-4e8e-b16e-a9545e402696','和韻答馬用宏朝散','葛勝仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','三吳汗漫遊，彌月沐風雨。',264,'全唐诗/poet.song.78000.json','["三吳汗漫遊，彌月沐風雨。", "歸來駭貧舍，忽有金剛杵。", "豈惟心疾失，頓覺頭風愈。", "句如冰壺清，格類瓦棺古。", "五言有奥境，此段得箋詁。", "吾衰久寂寂，笑人憂鄧禹。", "自貶豈不能，趨競虞姍侮。", "洞庭巖壑秀，信美真吾土。", "秋濤浮乾坤，日月互吞吐。", "中有七十山，招提稱踵武。", "歸命兩足尊，一洗俗諦苦。", "但喜經翻貝，那知檄馳羽。", "鐘魚走諸刹，袵席詎安處。", "洞天隔塵寰，仙境一二數。", "毛公金丹成，拔宅已輕舉。", "空餘朝斗壇，遺址猶可覩。", "法城有龍象，今作西山主。", "淨瓶逗真機，松枝代揮麈。", "示我第一義，金篦破昏瞽。", "清遊懷清標，所恨隔笑語。", "茅廬新塈塗，戶牖木僅斧。", "劇談佇公來，相望十里許。"]'),
('ecb17a09-d052-4fb9-9390-1dd50d636afd','用宏見和復和一首','葛勝仲','宋','宋诗','song-poetry','','[]','荒鷄號将晨，不改風及雨。',264,'全唐诗/poet.song.78000.json','["荒鷄號将晨，不改風及雨。", "高賢兩投分，定交從臼杵。", "心期久彌堅，膠漆比孰愈。", "有初顧隙未，賣友起中古。", "五交有形状，孝標能訓詁。", "邈哉弹冠契，王陽知貢禹。", "乘權獻巧妍，失時輙輕侮。", "管鮑貧時交，此道棄如土。", "孟嘗唾其面，憤懣聊一吐。", "翟公書其門，薄夫常接武。", "蹇予不知量，拔士偏寒苦。", "見欺多校人，覈實失子羽。", "歸來蓬蒿園，弔影甘窮處。", "知舊棄如遺，那復見比數。", "誰知荆州丞，厚德能克舉。", "任安窮不去，平仲久更覩。", "詩文連慰藉，詞鋒設賓主。", "剡藤快展讀，如坐對談麈。", "惜哉華國文，乃以觀矇瞽。", "舂容寫河漢，寒窘笑三語。", "才凡特俎豆，德薄更藻斧。", "玉巵實無當，深恐累稱許。"]'),
('ef357b78-830c-4872-bbe6-953919efc937','海昌從中散兄遊硤石東西山及讚山而别兄獨遊黄灣諸山寺寵寄三詩因追述前遊却寄','葛勝仲','宋','宋诗','song-poetry','','[]','相從十日歡，預恐别淚滴。',288,'全唐诗/poet.song.78000.json','["相從十日歡，預恐别淚滴。", "重謀訪林壑，庶復延晷刻。", "好山塵一舍，何惜蠟兩屐。", "東湖浸坤軸，浩蕩鵾鵬擊。", "方舟穩睡餘，帆已收硖石。", "東山號紫微，數殿聳金碧。", "我祖鍊金膏，井湫湛寒色。", "飈輪已仙去，千古留玉液。", "當年善逝師，福壤眼獨識。", "上方子亭高，俯睨衆山脊。", "空濛雲海寬，想像人境隔。", "夜投涵虛閣，萬籟森已寂。", "軟脚旋呼尊，亦復兩顴赤。", "黎明登西山，岌嶪動人魄。", "華榜揭靈池，審公存故迹。", "高堂坐白衣，巍巍妙智力。", "道傍兩精舍，聯步遍遊陟。", "讚山特超峻，四雙舊飛錫。", "綠猗環高竿，蒼髯矯千尺。", "吳越峰巒秀，羅列在几席。", "情賞未云厭，六龍俄已昃。", "轉溪遂分袂，惻愴不能食。", "還家得詩筒，妙語粲珠璧。", "具載黄灣遊，恨不逐飛翼。"]'),
('ebce7e97-2f2a-404b-b983-4e7344c0ee6d','硤石寺聞繫豬明不能食','葛勝仲','宋','宋诗','song-poetry','','[]','夜聞刺豕聲，哀號欲趨死。',48,'全唐诗/poet.song.78000.json','["夜聞刺豕聲，哀號欲趨死。", "黎明肉入饌，念之難啟齒。", "口腹我可賖，性命彼所恃。", "右軍惋烹鵝，東家嗅供雉。"]'),
('73b33b32-7754-4560-97a8-c32483ca303d','七月一日招道祖劇飲','葛勝仲','宋','宋诗','song-poetry','','[]','長卿已倦遊，十年安澤國。',192,'全唐诗/poet.song.78000.json','["長卿已倦遊，十年安澤國。", "越鳥巢欲南，鷓鴣飛懶北。", "會予亦蹭蹬，從子寄岑寂。", "有酒時相邀，歡飲終未劇。", "今當大火流，似聞姊喪釋。", "羽書靜追呼，樂禁通考擊。", "掃除北窗凉，招速東床客。", "暫勤車騎都，來輟春秋癖。", "白啖苦無賴，紅顔因暫惜。", "畦蔬擷菘韭，園果剥梨棘。", "金虀薦子鵝，銀條膾玄鯽。", "弓彎舞袖寬，珠貫歌聲激。", "景升陋三雅，淳于能一石。", "擬取醉轄投，慵持詩燭刻。", "浮生百年幻，且盡一朝適。", "莫待佐稽山，對案空相憶。"]'),
('98a3ba15-69c1-4de2-9223-49203af7cc66','諸人見和復次韻','葛勝仲','宋','宋诗','song-poetry','','[]','淵明事獨往，謀酒不謀國。',192,'全唐诗/poet.song.78000.json','["淵明事獨往，謀酒不謀國。", "引壺自酌罷，高卧幽窗北。", "孤松供盤桓，五柳伴幽寂。", "時赴中道邀，未覺體小劇。", "八旬棄縣令，忻若重負釋。", "安石登冶城，清談工剖擊。", "竹林事遊燕，百金費羣客。", "絲竹聊寫情，副此桮鐺癖。", "歲晚白雞夢，頽齡天不惜。", "二士俱好飲，世運屬艱棘。", "身今掃閒軒，紅蕖蔭魴鯽。", "遠挹環峰秀，下臨湍水激。", "得酒且盡歡，何人壽金石。", "不如更添燭，夜漏淹晷刻。", "醺酣便逃禅，酩酊非閼適。", "從教醉謬誤，黎明不能憶。"]'),
('40b4808e-0d4a-4607-b7eb-e6a7f829093f','次韻章壻道祖倧山居','葛勝仲','宋','宋诗','song-poetry','','[]','我本丘壑人，負乘輙致寇。',120,'全唐诗/poet.song.78000.json','["我本丘壑人，負乘輙致寇。", "歸來臥湖海，夢斷三接晝。", "尚餘憂國心，带眼日驚痩。", "騰装居景山，飄飄雲出岫。", "門無長者轍，相見誰肯就。", "吾甥相國孫，款我裹糧糗。", "禅關有聖解，已語則無咎。", "兩庵同相攸，卜鄰殆天授。", "登盤無檳榔，客居必見宥。", "富貴應自知，不詢唐舉壽。"]'),
('a9226b8e-e931-452f-9a5c-0ff5ea39e17d','病起二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','春風散頑陰，我亦除積痾。',48,'全唐诗/poet.song.78000.json','["春風散頑陰，我亦除積痾。", "客居有園林，得暇輙一過。", "殘梅雪尚積，曲沼春已波。", "儻或不近酒，如此推遷何。"]'),
('8a6a26de-c90c-46e3-9b4e-05fca9028b3b','病起二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','人生身後名，孰得還孰失。',60,'全唐诗/poet.song.78000.json','["人生身後名，孰得還孰失。", "豈若一杯酒，聊復得永日。", "如何杜陵老，感難百憂集。", "不飲孰忘憂，飲多或生疾。", "惟其疾之憂，已矣兩相直。"]'),
('dcb6d815-6d4f-460b-8f8e-6787c8d3526b','立方和韻復和一首','葛勝仲','宋','宋诗','song-poetry','','[]','屬疾大廢食，始進一麥麻。',168,'全唐诗/poet.song.78000.json','["屬疾大廢食，始進一麥麻。", "客至闕均禮，呼兒辦瓜茶。", "冷落乏勝事，病苦将日加。", "兒曹解人意，爲潑閩嶺芽。", "山深生意足，香味冠百嘉。", "依稀仙掌露，彷彿石橋花。", "過盞謝新法，失杯戒憎蛇。", "甘我舌三寸，澆我書五車。", "餘瀝均學子，少長各有差。", "何須待鞠卺，此段固已佳。", "人生草頭露，迅晷堪驚嗟。", "適意貧亦樂，鍾鼎來何賖。", "今朝復何幸，濯暑分流霞。", "蘇息問蒼生，欲泛牽牛槎。"]'),
('3a949dfe-d313-472e-a2f1-c410cd140981','錢氏通惠泉','葛勝仲','宋','宋诗','song-poetry','','[]','山翁徹骨清，日飲一瓢水。',144,'全唐诗/poet.song.78000.json','["山翁徹骨清，日飲一瓢水。", "天公隱其窮，殆将貽石髓。", "先敕西神君，一派疏清泚。", "初驚石罅出，盈科來未已。", "其瀦爲淵潭，其滙則沼沚。", "酌比九隴泉，餳味參差是。", "一甌紫筍春，牙頰留甘美。", "餘波共濯纓，濺沫邀洗耳。", "山中有異事，喜甚屐折齒。", "長安昊天觀，秦吳隔千里。", "妄云脉絡通，道人真疏矣。", "寄語贊黄公，未應停水遞。"]'),
('3ab73f2c-b8d5-424d-bec7-044f8b24f0c7','謝興之餉魚肉二醤二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','貧厨不舉火，素拙沒與乾。',72,'全唐诗/poet.song.78000.json','["貧厨不舉火，素拙沒與乾。", "拾煤未爲饑，猶有食一簞。", "拜嘉欣二醤，顧尚闕晨餐。", "快啗亂蒸肫，那學武子奢。", "瓶中乏儲米，請粟望子華。", "佳醢得新味，羞豆應當加。"]'),
('81e91e03-47ab-4e5b-81a3-c237c91ae761','謝興之餉魚肉二醤二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','盎盎鵝兒酒，風巵起微浪。',72,'全唐诗/poet.song.78000.json','["盎盎鵝兒酒，風巵起微浪。", "何以侑芳樽，蓴羮調得醤。", "彘肩與魚乙，佳惠過臺餉。", "黄雀釀披綿，江鱘斫玉板。", "對之無留觴，固已號佳饌。", "持此配藜羮，更增貧士赧。"]'),
('db2b2846-468b-4be4-9980-8f92dadf7dd0','送同郡識上人遊圓覺問道慈受','葛勝仲','宋','宋诗','song-poetry','','[]','道人獨往韻，半生服行衣。',120,'全唐诗/poet.song.78000.json','["道人獨往韻，半生服行衣。", "專門施氏易，編脱屢絕韋。", "文詞粲藻火，片語不救饑。", "棄家學心法，感歎悟昨非。", "兩年飽三白，屏棄甘與肥。", "南行訪道師，芒屩常輕飛。", "側聞長者寺，塔廟俱巍巍。", "堂堂第一代，龍天共瞻依。", "騰装來見語，舍是将安歸。", "勉旃叩玄旨，心花發清輝。"]'),
('e6177877-8f69-4710-9000-ee61fd74a536','東荘院','葛勝仲','宋','宋诗','song-poetry','','[]','此君如佳士，得一不爲少。',144,'全唐诗/poet.song.78000.json','["此君如佳士，得一不爲少。", "如何彌崗巒，十里青未了。", "泉源湛山椒，紅亭藏縹緲。", "奔流瀉萬丈，穿林下縈繞。", "居僧惜泉出，少借作溪沼。", "冰霜濺沫亂，琴筑仙音杳。", "水竹自莫逆，獨厭逋客擾。", "我亦願結交，禅房寄深窈。", "門前石盆潭，奩鏡澄不撓。", "寺後仙人壁，崚嶒插雲表。", "卜遊已經年，此志幸不夭。", "菟裘在何許，清境吾将老。"]'),
('934e1c6b-f8bf-4254-bc44-b5f78dc8e223','中秋無月與伸仲飲書齋書呈伸仲','葛勝仲','宋','宋诗','song-poetry','','[]','我生不如意，十事常七八。',132,'全唐诗/poet.song.78000.json','["我生不如意，十事常七八。", "窮巷屬中秋，乃有長者轍。", "相逢急呼酒，坐待盛滿月。", "那知天所閟，不吐冰輪潔。", "王孫神膚清，與月真莫逆。", "牛渚舫中人，武昌樓上客。", "千古明月句，腹中無一闕。", "我窮輙相累，昏燈照愁絕。", "窗蕉響疏雨，杯負琉璃滑。", "豈無仍圓夜，又恐間何闊。", "呼童歌嗚嗚，一笑助耳熱。"]'),
('8ad3f818-c799-40df-8119-be717907710d','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','僑居始定交，寄誠用縞紵。',72,'全唐诗/poet.song.78000.json','["僑居始定交，寄誠用縞紵。", "命駕輕千里，次亦推嵇吕。", "衰俗日益偷，此道棄如土。", "如何五載間，七返慰羈旅。", "崢嶸聽崇論，璀璨驚韻語。", "江湖風浪高，愧子蛟龍苦。"]'),
('29bfccba-7674-4c59-b798-0eb998f654b2','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','家貧困百須，禄廪不時給。',72,'全唐诗/poet.song.78000.json','["家貧困百須，禄廪不時給。", "接淅不漬糠，孤斟但飲濕。", "長者車轍至，園蔬親掇拾。", "主禮不如意，八九更論十。", "牛心餉會稽，猪肝售安邑。", "兹事固么麽，力亦不能及。"]'),
('37075b38-c43a-4867-84bb-8a9026f772c2','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','聚書三萬卷，斷自典與墳。',84,'全唐诗/poet.song.78000.json','["聚書三萬卷，斷自典與墳。", "籯金固已多，是家那得貧。", "平生謝雜好，童習至白紛。", "幽經與怪牒，一一儲心君。", "坐令說今古，奮袖真如雲。", "何當過藏室，手披至宵分。", "時時咀熊膽，辛苦以佐勤。"]'),
('c885fc28-fc20-445a-84da-d451fa29141e','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','君家髯御史，百疏嬰龍鱗。',72,'全唐诗/poet.song.78000.json','["君家髯御史，百疏嬰龍鱗。", "死喜作忠鬼，生甘爲旅人。", "高節渠無繼，從子蓋其倫。", "危言對便坐，骯髒不顧身。", "重道輕禄仕，無寜常隱淪。", "它年青史上，牽聯書直臣。"]'),
('576b712d-820e-431c-8139-b0c0b96ed86e','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其五','葛勝仲','宋','宋诗','song-poetry','','[]','潛山賦歸來，卜築聊自憇。',72,'全唐诗/poet.song.78000.json','["潛山賦歸來，卜築聊自憇。", "巖壑發天藏，桐竹如手蓺。", "寒泉西神派，那復問水遞。", "割甘餉兒女，伐木課童隸。", "意行及趺坐，宴然契真際。", "誠從古人求，三隱真可繼。"]'),
('14e27987-20ff-40be-8cfc-94fd9dc21fa8','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其六','葛勝仲','宋','宋诗','song-poetry','','[]','中年燈火讀，閲遍汗簡青。',48,'全唐诗/poet.song.78000.json','["中年燈火讀，閲遍汗簡青。", "歲晚得奥境，領略在六經。", "肯薰班馬馥，要續丘軻燈。", "只今未康濟，斯人尚郊坰。"]'),
('ab50da27-d14e-4b2b-a41f-5128f61209f1','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其七','葛勝仲','宋','宋诗','song-poetry','','[]','亂後等蓬轉，風雨摧敝廬。',84,'全唐诗/poet.song.78000.json','["亂後等蓬轉，風雨摧敝廬。", "寄身菰城南，誅茅縛幽居。", "家山在何許，清夢時一如。", "南鳥毎懷越，北馬常嘶胡。", "天狼今未落，中原猶羽書。", "歸歟不即賦，此心耿朝晡。", "一廛肯相容，卜室終桑榆。"]'),
('a9ecde44-59a0-4383-ab6d-2d70a3157352','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其八','葛勝仲','宋','宋诗','song-poetry','','[]','失勢水投石，得時山壓卵。',72,'全唐诗/poet.song.78000.json','["失勢水投石，得時山壓卵。", "富貴親眷稠，貧賤交情斷。", "叔世澆薄中，風誼如君罕。", "生涯一舸風，何門不堪款。", "龍坂不著脚，乃數訪幽散。", "語離大匆匆，寸心常不滿。"]'),
('bc1700ca-db77-4bb3-a376-51de70c6ad17','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其九','葛勝仲','宋','宋诗','song-poetry','','[]','皦皦常易污，容容毎多福。',60,'全唐诗/poet.song.78000.json','["皦皦常易污，容容毎多福。", "爲嫌狙賦三，乃作龜藏六。", "平生經綸手，都在十圍腹。", "似聞紗籠人，盡力欲推轂。", "柬之今已老，鶴頭來要速。"]'),
('d35cc9ed-decd-436f-80e3-d6e2a86b6841','送伸仲歸漆塘以語及君臣際經書滿腹中爲韻十首  其一○','葛勝仲','宋','宋诗','song-poetry','','[]','頃年官黄岡，清俸緣手空。',84,'全唐诗/poet.song.78000.json','["頃年官黄岡，清俸緣手空。", "飽暖到惸獨，吾寜守其窮。", "朅來漆塘山，𥝧稏收横縱。", "自言畏多累，不復愛畝鍾。", "負郭鄙蘇子，沉舟似龐翁。", "絕勝南陽人，辛苦耕隆中。", "遺後但清德，有子人中龍。"]'),
('36fc93a4-329a-4075-b3dd-bd06e76563be','明日元舉赴召見别用前韻送行','葛勝仲','宋','宋诗','song-poetry','','[]','吾君急升平，元凱登二八。',144,'全唐诗/poet.song.78000.json','["吾君急升平，元凱登二八。", "赤墀擁豪俊，青雲啟塗轍。", "巖居及川觀，號召無虗月。", "徴君筆瑞世，制行圭玉潔。", "向來端神羊，不畏龍麟逆。", "嶠南歸興動，只作數旬客。", "跡雖遁煙壑，名常藹雲闕。", "果膺尺一書，赴隴催装發。", "遂恐長烏府，席與羣工絕。", "眷言國步艱，敢惮泥塗滑。", "牛刀剸繁劇，鵬翅摩空闊。", "相期扶中興，何止得官熱。"]'),
('ad39fdda-2361-4528-b5fc-ca409f11e3e3','丁巳遊大雄寺有陳朝檜','葛勝仲','宋','宋诗','song-poetry','','[]','古殿藻井高，榱桷窮壮麗。',132,'全唐诗/poet.song.78000.json','["古殿藻井高，榱桷窮壮麗。", "黄金四佛榜，煌煌曼卿字。", "廷中檜異状，封植天嘉歲。", "直幹龜鶴年，樛枝龍蛇勢。", "陰森歷九朝，知閲幾興廢。", "石根青銅柯，孤高方得地。", "應笑凡草木，俛仰見癯瘁。", "緬懷陳季年，三閣事瓌異。", "後庭唱未闋，已作墮井計。", "獨此歲寒姿，與佛常閲世。", "寄謝青牛宫，勿輕大雄寺。"]'),
('7238c59b-cc98-4b44-a7db-8b24ce681ab6','赭山承慶報慈禅院劉希範資政墳寺張參預爲神道碑','葛勝仲','宋','宋诗','song-poetry','','[]','故人具鷄黍，相携登赭山。',144,'全唐诗/poet.song.78000.json','["故人具鷄黍，相携登赭山。", "松桂蔚回舍，上已煙霄干。", "陰風起天籟，誤聽號驚湍。", "新寺粲碧瓦，突兀數十間。", "君恩錫香火，以報顧復艱。", "亭亭無愧碑，銀鈎墨初乾。", "蓼莪避顧孝，汝墳起周盤。", "罔極疇不念，致此良獨難。", "彭城廊廟姿，報國劍鋒寒。", "末途禦魑魅，鳶墮隔生還。", "榮枯信反衍，誰能保常安。", "徘徊積慶堂，老鼻一辛酸。"]'),
('be3c391f-ca5e-4456-a687-5583babb35d0','戊午出長興郭泛西溪至清果院','葛勝仲','宋','宋诗','song-poetry','','[]','朱藤花墮影，罨畫因名溪。',120,'全唐诗/poet.song.78000.json','["朱藤花墮影，罨畫因名溪。", "林壑莽參錯，鵜鴂挾春啼。", "刺船未云久，眼明古招提。", "入門赤泥亭，石梁亦可躋。", "佛殿制淳古，凌空飛拱枅。", "凄其念陳祖，此境嘗幽棲。", "蝦灘弄竿綫，龍卧聊蟠泥。", "一朝風雲會，起舞隨荒雞。", "興王豈細事，荒陵出金犀。", "賢愚同一丘，莫厭青鞋胝。"]'),
('60bb2be8-d531-4766-873e-c082986c2ae1','戊午次吳山解空院乃端師子道場是日上已呈法中禅老','葛勝仲','宋','宋诗','song-poetry','','[]','尋幽勇鼓枻，兹山初問津。',120,'全唐诗/poet.song.78000.json','["尋幽勇鼓枻，兹山初問津。", "雲煙落吾手，若水清潾潾。", "蒼官舊千章，類不赦斧斤。", "以兹海藏湧，突兀干蒼旻。", "獨餘三大夫，欹蓋皴龍鱗。", "下閲往來輩，蜉蝣不知春。", "迎賓上人者，貎古意甚真。", "豈惟嗣老端，勢到粲忍親。", "陟巘既幽絕，飛談復清新。", "何庸浥寒波，更祓元規塵。"]'),
('9609e05a-3a89-445a-b271-0d62b985fc04','己未次廣惠院','葛勝仲','宋','宋诗','song-poetry','','[]','下若水沄沄，佛寺古邑西。',132,'全唐诗/poet.song.78000.json','["下若水沄沄，佛寺古邑西。", "開帆但五里，不到将噬臍。", "懷古展清眺，崇閣聊攀躋。", "法生有鼻祖，樂此山與溪。", "自言孫子賢，兹地興王基。", "覇主受九錫，二紀承梁齊。", "空餘陽烏阜，石人卧荒蹊。", "綠滿天隨家，巖花伴幽棲。", "留傳杞菊堂，墨妙懸榱題。", "秀色有他嶺，招尋更杖藜。", "山林且放誕，邊城多鼓鼙。"]'),
('4f9d4e93-16a0-494b-a94c-bdc7a536e3fe','次吳粹老觀我齋詩','葛勝仲','宋','宋诗','song-poetry','','[]','立我謹外揵，逐物戒內熱。',96,'全唐诗/poet.song.78000.json','["立我謹外揵，逐物戒內熱。", "樊然辨物我，此意猶屑屑。", "是身本虚空，何者爲六結。", "雖慧念不起，雖定照不滅。", "無我與我所，觀亦于何設。", "右臂弹已化，左肘柳方蘖。", "顧君進此道，遺我自朝徹。", "不見魯東家，意與我俱絕。"]'),
('6b5c83ef-a361-4b6b-8078-97a8cbf8d2a9','同子充遊堯祠見交代李行正詩追用李太白舊韻因亦次韻呈子充','葛勝仲','宋','宋诗','song-poetry','','[]','俗物敗人意，作吏七不堪。',383,'全唐诗/poet.song.78000.json','["俗物敗人意，作吏七不堪。", "朅來東蒙遇歡友，角立傑出推江南。", "英材百汰揮利刃，夷量萬頃澄寒潭。", "弱齡文采照金殿，荏苒立境衣猶藍。", "銅章來踏瑕丘鼓，邑屋歡康無疾苦。", "春風郊外正酣酣，笑指叢祠兩驂舞。", "猛抛簿領亂回回，戲看油碧聲如雷。", "不遣韶光浪湮滅，桃已蒸霞柳飛雪。", "超然危立俯河干，抱城清泗鳴驚湍。", "謫仙秀句但碑板，無復真跡龍蛇蟠。", "君不見聰明文思撫寰海，四表上下騰光彩。", "破椽欺魄爐無煙，豪氣英風亦何在。", "荒郊遺趾望中來，遐想千古令人哀。", "祖龍巡幸亦瑣瑣，從臣徒向蒼珉開。", "豪華豈復靈光殿，峻峗誰知季武臺。", "耿耿星河掛窗牖，未跨歸鞍猶捧手。", "同門早歲氣横秋，年大饑寒依秫酒。", "俗儒醒醉尚不分，金馬玉麟名遠聞。", "小縣鳴弦煩卓令，冷閣問字疲子雲。", "五斗不歸俱委瑣，邂逅爲僚天贊我。", "金蘭縞紵未足誇，嵇吕命駕何其賖。", "官寺相望無百步，泮林正對河陽花。", "坐令荘舄忘吟越，亦復無心存魏闕。", "蒲酒相從未有涯，祭竈請鄰纔一月。"]'),
('2299c465-fc26-42ac-ab4c-251192c0f572','記夢詩  其一','葛勝仲','宋','宋诗','song-poetry','','[]','頤堂晝卧清且閒，了無塵霿來相關。',128,'全唐诗/poet.song.78000.json','["頤堂晝卧清且閒，了無塵霿來相關。", "俄然正夢半山老，練裙葛帔泉石間。", "抵掌稱譚因餉硯，微凹浮墨光如電。", "自言繙經視草時，落紙雲烟皆倚辦。", "山頽梁壞空遺祠，覺讀其書寐見之。", "勉令勲德復藹藹，佳兆若此真非衰。", "少瑜昔夢青鏤筆，江淹重錦完成匹。", "明當辭藝驟驚人，千里從今期一日。"]'),
('b8b99043-cf5f-4d84-bad7-fca20d8c3505','記夢詩  其二','葛勝仲','宋','宋诗','song-poetry','','[]','元豐功成身退閒，鍾山小築掩松關。',128,'全唐诗/poet.song.78000.json','["元豐功成身退閒，鍾山小築掩松關。", "莘莘學子求卒業，說經閙若闤門間。", "木鐸兹文繄筆硯，紫綬垂腰眼巖電。", "似聞一日置心猿，道德功名無不辦。", "配食孔廟時烝祠，子生其後不識之。", "文章津源已默付，名爵豈待顔髪衰。", "向來李嶠夢雙筆，至今辭藻無倫匹。", "納鑑唾口難細論，謂言不信有如日。"]'),
('0a96899e-6b92-4898-bc5a-a54243e74a95','補之見和復次韻二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','仙曹無事身得閒，午睡絕惡呼當關。',128,'全唐诗/poet.song.78000.json','["仙曹無事身得閒，午睡絕惡呼當關。", "榻施籧篨獨展轉，夢覺不離周孔間。", "官出硯州初乏硯，過眼羅紋如過電。", "半生用一即墨侯，頗欲易之貧不辦。", "舊聞夢硯湘君祠，乃今神異真類之。", "秣陵真儒豈虚授，文字之祥昌不衰。", "擘牋亹亹稱名筆，正始微言欲儔匹。", "終當辭藻瑞朝廷，更請焚膏勤繼日。"]'),
('beb05308-c802-4133-b03a-93f26ebf46c7','補之見和復次韻二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','逸驥未遇虚王閑，鹽車垂耳猶間關。',128,'全唐诗/poet.song.78000.json','["逸驥未遇虚王閑，鹽車垂耳猶間關。", "夢中一眄逢伯樂，遺以舊物戃恍間。", "斧柯山神護珍硯，採琢往往興雷電。", "欲求潛璞滿書簏，顧豈咄嗟便能辦。", "禱求苦用中牢祠，何如假卧輙得之。", "池塘句好有神助，文字格力何因衰。", "莫嗟筮仕困刀筆，聘材行即肩羣匹。", "速将妙語醉衰翁，鸂鶒飛灘知不日。"]'),
('b0ceb573-ecb5-45d6-a8a8-4a791cf6e99e','從人求鰒魚','葛勝仲','宋','宋诗','song-poetry','','[]','海邦邾莒固多品，此族稱珍乃其伯。',128,'全唐诗/poet.song.78000.json','["海邦邾莒固多品，此族稱珍乃其伯。", "瀋泉湘瀹付饔宰，薑桂煎調奉佳客。", "視書已覺明病眼，點酒偏能醒醉魄。", "君看憂憤不眠人，快啗取厭亦何擇。", "豈如吾曹飲文字，輿臺不復霑餘瀝。", "昔官餘杭飽下筯，兩載杯盤厭凡核。", "朅來瑕丘問鮭菜，樽俎遍索未云獲。", "願從褚公棄千萬，免使劉郎鞭二百。"]'),
('c97612c5-a9ba-4e22-90db-82f306a58cc8','刁馬河上書事呈提舉張聖用','葛勝仲','宋','宋诗','song-poetry','','[]','稻人掌稼存周書，蕩以溝洫蓄以瀦。',384,'全唐诗/poet.song.78000.json','["稻人掌稼存周書，蕩以溝洫蓄以瀦。", "爲田一夫顧尚爾，有大於此其亡諸。", "所以當時多善歲，黍稌高下無萊汙。", "史公引漳變舄鹵，鄭國注洛通廞淤。", "寂寞井地已不復，二子興利猶居居。", "常平新書出聖考，歲積羡入爲留儲。", "毫釐不以給公上，補助力役寬農夫。", "意謂舍此欲富國，不幾緣木求淵魚。", "猗歟吾皇始即阼，駿惠成憲追前摹。", "民田利病特經意，詔俾海縣交修予。", "芻言輿議滿青匭，論及刁馬尤勤渠。", "一勞暫費不足憚，要使長利相乘除。", "水衡銜命出護役，使節適野同伻圖。", "勸勤警惰詔賞罰，尺一徑下隨都俞。", "擇材分幹自不乏，猶如采芑從菑畬。", "薨薨畚插事疏鑿，坎坎鉦鼓催勤劬。", "伍符尺籍用兵法，保受圑結從州閭。", "施功塹中毎絕蚓，得肉道上時銜烏。", "河流廣深事股引，清波漲綠涵靈胥。", "勸農使者舊京兆，眉嫵曾畫閨房姝。", "魯邦都尉古循吏，謀視韓許直庸奴。", "經營土功費心畫，埤益王事成仙臞。", "清明不歸對花柳，獨冐埃壒馳軺車。", "香名巍巍鏤翠琰，績用藹藹飛皇都。"]'),
('2d3757ce-516c-4a04-a131-fff4fb629110','謝人惠筍','葛勝仲','宋','宋诗','song-poetry','','[]','籜龍初萌豹文點，味闕盤飱心正慊。',128,'全唐诗/poet.song.78000.json','["籜龍初萌豹文點，味闕盤飱心正慊。", "二公好事爲髠鋤，一日分甘香掩冉。", "小靳全勝沈道虔，縱取何殊范元琰。", "趣令庖宰事燒煮，未怕旁人呵聚斂。", "白醪赤米最相稱，紫蓼綠葵當少貶。", "驗長須知韓老嗜，稱冤却笑盧仝儉。", "遥憐萌出盛家林，豈不懷歸畏官檢。", "願君繼餉走輿隸，莫遣煙篁拂崖广。"]'),
('01e969e1-7415-4eab-8f25-12de3712fd4c','喜元舉歸','葛勝仲','宋','宋诗','song-poetry','','[]','溪東作舍已蓋茆，溪西築庵新立棟。',224,'全唐诗/poet.song.78000.json','["溪東作舍已蓋茆，溪西築庵新立棟。", "水雲參錯出十里，妙寄方嗟無與共。", "忽聞故交還五嶺，聊喜居鄰依二仲。", "臺評早歲冠神羊，儒館文華推白鳯。", "詔除毎下輙避寵，才術小試已驚衆。", "炎荒雖云去國遠，皇華要是爲時用。", "故爲懷歸逐我輩，露章求免疲護送。", "自言嶠南官不惡，峻峰危嶝頻飛鞚。", "挽葛屢上羅浮顛，披雲亦到朱明洞。", "看山却憶家林好，夜夜幽棲來旅夢。", "而今歸隱寄天放，却憶修途真定痛。", "猿鶴相向爲家禽，松菊未荒憐手種。", "碧鮮脱籜高遶屋，白墮敷醪香出甕。", "從今莫厭數招尋，持鰲共費宫祠俸。"]'),
('f1d8ccaa-02fe-4a09-964f-a083493c95df','試建溪新茶次元述韻','葛勝仲','宋','宋诗','song-poetry','','[]','舶舟初出建溪春，紅牋品題苞蒻葉。',160,'全唐诗/poet.song.78000.json','["舶舟初出建溪春，紅牋品題苞蒻葉。", "低昂輕重如美人，等衰銖較知難躐。", "格高玉雪瑩衷膓，品下膏油浮面頰。", "太丘胸中有涇渭，包裹携來充博帖。", "稍發下駟已驚眼，香味高奇光煒曄。", "不肯花前殺風景，憑花爲謝穿花蝶。", "更看正紫小方珪，價比連城真稱愜。", "病渴羌人洗煩滯，好睡兼旬便愁攝。", "異時風流貴公子，喜悦藏珍令口囁。", "莫辭七椀攪枯腸，有酒沽君夜燒蠟。"]'),
('7474735c-533d-4796-b68a-0706803cafe9','次韻去非謝前教授餉澤州瓦硯','葛勝仲','宋','宋诗','song-poetry','','[]','錫花蒸成一坏土，聯坳即墨元光舞。',128,'全唐诗/poet.song.78000.json','["錫花蒸成一坏土，聯坳即墨元光舞。", "飛鴛餘韻照文房，吕翁心機同刻楮。", "高平沃壤真土膏，硯與龍尾爲朋曹。", "剛柔得中不坯甈，共推妙手能甄陶。", "郎官小樣知名久，何須對面供十手。", "講郎尚有千載人，要此編摩論臧否。", "請加什襲傳後昆，阿買不獨書八分。", "紗帷晝靜棐几滑，克肖鼻祖能綴文。"]'),
('1040c41a-28d0-4116-987a-05940cb607d1','次韻去非題紫邏洞','葛勝仲','宋','宋诗','song-poetry','','[]','一麾謬作東諸侯，邂逅兩玉陪遨遊。',128,'全唐诗/poet.song.78000.json','["一麾謬作東諸侯，邂逅兩玉陪遨遊。", "引泉疊山作竹洞，持以奉客充淹留。", "㶁㶁清流出潭底，辟疆萬箇那勝此。", "奇礓文六照幽亭，雅稱幼輿巖石裏。", "人所應無君盡無，哦詩擁卷窮晨晡。", "指物程形直題署，便欲相稱詩董狐。", "雲水相從樂復樂，汝陽太守自賓幕。", "不用飛章乞會稽，聳秀交流看巖壑。"]'),
('ce433318-ddb5-4bb2-8f6b-50ebe87aef83','次韻去非梅花','葛勝仲','宋','宋诗','song-poetry','','[]','造化小兒心戀嫪，偏向冰花施巧妙。',160,'全唐诗/poet.song.78000.json','["造化小兒心戀嫪，偏向冰花施巧妙。", "冷禁霜带曉寒飄，清宜月綴微雲照。", "已與鳴鳩傳酒信，更乞遊蜂供蜜料。", "交情萬里寄春色，度曲五更吹怨調。", "半樹臨溪抵死香，一枝倚竹嫣然笑。", "寒姿疏影太幽獨，靜女貧姝真窈窕。", "世言嘉卉出靈山，我疑異種來圓嶠。", "肯挑俗子炫穠麗，只約騷人伴吟嘯。", "少陵牽興催衰白，廣平被惱回剛峭。", "徑須相過壽此花，市遠無肴只藜藋。"]'),
('88ff6ce7-4f8c-4c71-9e72-9b3960fc7e91','次韻去非留别','葛勝仲','宋','宋诗','song-poetry','','[]','餘子碌碌不足數，太丘晚出吾所許。',160,'全唐诗/poet.song.78000.json','["餘子碌碌不足數，太丘晚出吾所許。", "淹盤此境未金馬，邂逅相逢慰銅虎。", "與超宗語不知寒，從季遠遊那覺暑。", "祥琴臯月歘戒行，征馬譙門聊出祖。", "平生種學與績文，自信扶珪兼綴組。", "分無桃葉把歌扇，只有松枝當談麈。", "行装未辦纒頭帛，衣食何施擇木羽。", "從來文豹深隱霧，此去老蛟真得雨。", "長卿蜀肆初滌器，伯鸞吳廡曾舂杵。", "青雲直上不作難，那復笑人憂鄧禹。"]'),
('ec7ac8cb-dd08-4af8-aa32-71e221776ed6','喜宗丞姪病愈','葛勝仲','宋','宋诗','song-poetry','','[]','向來聞汝拙将理，五日寝瘵未藥喜。',64,'全唐诗/poet.song.78000.json','["向來聞汝拙将理，五日寝瘵未藥喜。", "醫良未遇肱三折，愛切徒勞夜十起。", "欣聞安泰風愈檄，莫嘆清癯肉消髀。", "徑須營度還詩債，要看筆端翻峽水。"]'),
('ce87eba4-61bb-4627-86d9-b57ea5ae0131','奉同李倅安上賦崔白沐猴杏花','葛勝仲','宋','宋诗','song-poetry','','[]','空山無人春風驕，撲撲晴杏開香苞。',160,'全唐诗/poet.song.78000.json','["空山無人春風驕，撲撲晴杏開香苞。", "巖深谷峻無與賞，攀枝騰踏帷飛猱。", "大梁崔白舊所見，絹素落手因揮毫。", "巧爲紅艶狼籍勢，撲蔌幡灑歸蓬蒿。", "王孫惜花有深意，預憂雨横兼風豪。", "故來跳觸看零亂，妙思臨寫形無逃。", "貴人錦囊舊藏貯，文闈傳玩叢英髦。", "東平儒仙首留詠，詩價與畫相爭高。", "直云何用辨真假，徑須對此呼香醪。", "誰知真花却時暫，不如丹粉還堅牢。"]'),
('ff53039b-b680-4c3e-aa8a-de451115c71d','高君贄兼數職奔走疲甚以詩勞苦之','葛勝仲','宋','宋诗','song-poetry','','[]','曉鼓逢逢天未白，呼火攝衣干典客。',160,'全唐诗/poet.song.78000.json','["曉鼓逢逢天未白，呼火攝衣干典客。", "青衫手板階石前，磬折擎拳若無骨。", "還将束矢聽情僞，更向團絲分枉直。", "糟漿逆鼻走兵厨，播糠眯目司平糴。", "翩翩輕轝行若飛，濯濯單紈汗如滌。", "趨局何曾過八塼，端居未暇移百甓。", "歸家往往犬迎吠，得肉時時鳥攫食。", "長材要自萬鵬程，初筮聊淹一雞肋。", "徑須黽勉弹其冠，未用低佪尤此幘。", "左馮舊事今復繼，敏手州人驚霹靂。"]'),
('ee98d0d0-86d3-47a5-8554-8f886fc84cd4','邑尉姜補之枉詩甚寵率爾酬和','葛勝仲','宋','宋诗','song-poetry','','[]','去年詔鎻春官闈，桓桓文陣如熊羆。',224,'全唐诗/poet.song.78000.json','["去年詔鎻春官闈，桓桓文陣如熊羆。", "激昂辭章爭自售，獵取豪俊幾無遺。", "五更榜帖亂人鬼，九衢姓字犇輪蹄。", "維時謬從宗伯後，喜子入彀名高垂。", "楓宸臚傳預供奉，杏苑開宴常追隨。", "那知巖邑大如斗，邂逅聯事同勞疲。", "民頑奊詬號難治，心怯畏縮将安施。", "幸蒙幹略整紛冗，間以文義相娯嬉。", "忘形未肯遽爾汝，執禮乃或論生師。", "固知風味去人遠，九牛何止爭毫釐。", "平生最喜我輩士，角巾野服同委蛇。", "爾來亭午已休吏，五百彌月閒鞭笞。", "城南桐竹富蕭瑟，城北溪漲清淪漪。", "頗願吾僚哀老子，遨遊使得時伸眉。"]'),
('fc7d8f81-d531-43bf-b5e9-82a051ccf664','送許師德','葛勝仲','宋','宋诗','song-poetry','','[]','訪我金溪船繫柳，一杯醑我真天酒。',128,'全唐诗/poet.song.78000.json','["訪我金溪船繫柳，一杯醑我真天酒。", "騰装欲赴清油幕，纔得伸眉俄振手。", "家聲文采照東南，洛師吳郡乃所監。", "羔纁繼辟不容避，聊脱黄帽穿征衫。", "元戎器業光鼎軸，百萬貔貅爲部曲。", "仰分憂顧新登壇，慎柬英僚佐推轂。", "平生韜略攄一朝，佇看烽静無氛妖。", "将軍三箭天山定，千羣塞馬嘶風驕。"]'),
('683cc155-1b39-487d-9d5c-adb394cf4456','少川兄貧悴甚見屬求寓舘未遇好事者聊作詩以寄因以速之','葛勝仲','宋','宋诗','song-poetry','','[]','我兄弱齡推了了，手不停披今髮縞。',96,'全唐诗/poet.song.78000.json','["我兄弱齡推了了，手不停披今髮縞。", "人中滯論能立判，筆下陳言皆力掃。", "多如雞跖歎積學，大似牛腰看屬藁。", "敗絮自擁不言寒，書床坐穴那知老。", "逆旅無人識馬周，除舍何當館孫寶。", "水波未合急相過，漱醪聊緩憂心擣。"]'),
('fd88d987-1d7e-4e98-a69d-f1525c9cae02','寄題吳江王文孺解元臞庵','葛勝仲','宋','宋诗','song-poetry','','[]','臞庵散人築隱居，自稱山澤之臞儒。',160,'全唐诗/poet.song.78000.json','["臞庵散人築隱居，自稱山澤之臞儒。", "邀風貯月有亭觀，以道自廣何其臞。", "三江雪浪魚龍窟，千古浮天仍浴日。", "乍吞涯涘歸醉胸，時卷波瀾入吟筆。", "天儲此景非寒窘，經營傑觀規相凖。", "萬株蒼石雲斸根，十頃紅蕖波照影。", "異時璧沼摇毛錐，同門太半通金閨。", "一班一級何足道，賦歸有此知爲誰。", "境清恍與塵寰隔，彷彿天隨舊行迹。", "聞道朱黄近筆牀，定有叢書增笠澤。"]'),
('d8308ccd-de46-4494-8513-20e03c3bcbde','次韻慶善九日','葛勝仲','宋','宋诗','song-poetry','','[]','舍南自灌五畝園，滿種黄花待親識。',64,'全唐诗/poet.song.78000.json','["舍南自灌五畝園，滿種黄花待親識。", "明朝酒熟當壽君，卷白不許餘涓滴。", "湖海浮家作寓公，醉醒幸與騷人同。", "一座盡傾塵表物，不須舉扇障西風。"]'),
('04a8986e-5841-453b-be28-de231aa0389b','再和慶善','葛勝仲','宋','宋诗','song-poetry','','[]','但将詩酒樂重陽，呫囁深嫌程不識。',64,'全唐诗/poet.song.78000.json','["但将詩酒樂重陽，呫囁深嫌程不識。", "已呼明月倒芳樽，更浥滄波供硯滴。", "多聞素仰百六公，飄零邂逅笑語同。", "明當數助擊鮮品，鼻頭出火耳生風。"]'),
('d7374d3b-55e7-4c3d-8652-9b5cce447866','送慶善之江陰','葛勝仲','宋','宋诗','song-poetry','','[]','南州地氣真火維，午暑勢若遭蒸炊。',192,'全唐诗/poet.song.78000.json','["南州地氣真火維，午暑勢若遭蒸炊。", "風亭水榭不救暍，如何泛役衝炎曦。", "四年遵路俱六月，叩門急義非君誰。", "小蓬暑行分不免，著書暫卷春秋帷。", "借船屢枉逸少字，質錢敢以班史辭。", "一麾尚與數人共，西江得水知何時。", "况復外事繼嬰擾，主孟頻歌烹伏雌。", "天其或者降大任，必先空乏其儲貲。", "老人索居寓澤國，蛙黽同處時迎毉。", "麥麴芎藭兩未效，政須健論扶衰疲。", "君今捨我那遽反，落寞何用伸吾眉。", "大恐尺一亟招選，徑從儳道趨天墀。"]'),
('a2178761-9057-4f46-b708-ae1d62c4045b','嘲淵明代答','葛勝仲','宋','宋诗','song-poetry','','[]','君不見七百石了麴蘖事，二千石充雀鼠耗。',53,'全唐诗/poet.song.78000.json','["君不見七百石了麴蘖事，二千石充雀鼠耗。", "澆腸果腹固有餘，糟丘米山何足道。", "不如酒盡仍從酒家覓，瓶中粟空聊乞食。"]'),
('278afa18-ff70-4313-92b6-bfac29c84f4e','依韻和子有教授姪寄雪詩','葛勝仲','宋','宋诗','song-poetry','','[]','空中紛霏誰剪水，夜半天窗明蠟紙。',128,'全唐诗/poet.song.78000.json','["空中紛霏誰剪水，夜半天窗明蠟紙。", "天将奇寶借詞客，使酒驅詩難但已。", "紅爐活火然松明，閒施博局呼明瓊。", "區中無此清絕境，疑是縮地來蓬瀛。", "從來聞說三吳道，飄瞥郊原看最好。", "且願留爲不夜城，揮戈却日還穹昊。", "講郎才韻今可人，聞客欲至顔津津。", "急掃堦庭施木屑，跋馬去作陶家賓。"]'),
('53a0ef5e-c8ca-4baa-9621-93094bd1094a','衛卿弟和詩佳甚復和一首','葛勝仲','宋','宋诗','song-poetry','','[]','俗人雪句如翻水，陳言堪弔剡藤紙。',128,'全唐诗/poet.song.78000.json','["俗人雪句如翻水，陳言堪弔剡藤紙。", "子詩清如扇上讚，使我三歎不能已。", "妍姿與雪爭輕明，白戰不道飛瑶瓊。", "西神山畔芙蓉水，好招煙艇浮澄瀛。", "千巖不必山陰道，何處輕飄看不好。", "百觚判斷速呼客，莫待睍消還畀昊。", "天儲此景娯閒人，貯瓶潑茗甘流津。", "茅簷從此便歸隱，不待人呼祁孔賓。"]'),
('01893326-b6cd-4e25-b3dd-46d7c88fb833','衛卿弟賦詩見貽和答一首時有從軍之興','葛勝仲','宋','宋诗','song-poetry','','[]','我如老屋人多閲，骯髒如君真可悦。',128,'全唐诗/poet.song.78000.json','["我如老屋人多閲，骯髒如君真可悦。", "長塗未騁駒伏轅，窘步無堪鮒依轍。", "諸賢衮衮位華顯，獨子棲棲困巖穴。", "何妨虎子聊一探，况是龍泉未虞缺。", "前時羮稀客告去，爾日瓶空糧又絕。", "不緣閔已賦牢愁，獨爲傷時拭清血。", "燕頷食肉骨素奇，龍額封侯計非拙。", "勉旃矍鑠出據鞍，收卷毛錐從此决。"]'),
('7c1e4ff0-c0d1-4ba4-b413-e3343f36ded5','次韻鄭維心遊西余山','葛勝仲','宋','宋诗','song-poetry','','[]','雲巘瓌奇甲震州，不須幽境更旁捜。',128,'全唐诗/poet.song.78000.json','["雲巘瓌奇甲震州，不須幽境更旁捜。", "從來知是通侯國，此段方從勝客遊。", "閏歲春遲空水樹，雨時溪漲失沙洲。", "吾衰久矣欲何適，更爲前山一上樓。", "顧余峰好鏁雲烟，入寺窺臨信所傳。", "衣袒右肩從衲子，屐除前齒陟山巔。", "一杯相屬真宜釂，四者難并偶幸全。", "亭號弄雲誰作記，紫樞當日筆如椽。"]'),
('658b165d-8cd4-4add-80c4-74da8389c048','明月峽','葛勝仲','宋','宋诗','song-poetry','','[]','李庇山記皮陸詩，紀述茶事真歷歷。',160,'全唐诗/poet.song.78000.json','["李庇山記皮陸詩，紀述茶事真歷歷。", "枕流亭北池七里，萬仞插天雙石壁。", "懸崖倒掛天銀河，武敏尚存西楚迹。", "昔賢招尋多好事，例以姓字刊巖石。", "青瓊綠髓茶始生，報春鳥鳴山晝寂。", "茶民研膏柏黑粘，香焙鑿山深二尺。", "急程苞貢御簾開，宫娥進水傾寒碧。", "只今玉食歲不供，舊事獨有山英識。", "羈人水厄不厭數，耿耿不寐幾通昔。", "他日重來覓舊題，應嘆流年如矢激。"]'),
('aa399457-3125-47d3-a451-584c8c6e5077','工部兄新治小閣壘土爲火爐戲作勸召客','葛勝仲','宋','宋诗','song-poetry','','[]','簡許開尊殺青竹，俎有肥羜簋饛粟。',128,'全唐诗/poet.song.78000.json','["簡許開尊殺青竹，俎有肥羜簋饛粟。", "招呼未聽洗醆聲，故復吟哦小詩促。", "能使将軍賞不貧，請召宗姓仍及身。", "擁爐便是入窟室，於粲灑掃情無文。", "我今愁如居廣柳，萬斛量之應更有。", "內典暫輟算海沙，羣經尤慵開户牖。", "政欲酣暢融心神，村郊魚鳥皆來親。", "不憂坐上無武子，羣從一一天麒麟。"]'),
('1e72c5eb-b0e0-4cd9-b149-7f8c408ea944','大父通議無恙日開軒燕處有桐孤峙因名琴軒初不措琴嘗作記叙意而偶失藁本故今家集不載比者興之姪閲故書得之見貺喜而成詠呈六兄工部兼簡弟姪','葛勝仲','宋','宋诗','song-poetry','','[]','嶧陽奇軒高參天，對以華屋名琴軒。',128,'全唐诗/poet.song.78000.json','["嶧陽奇軒高參天，對以華屋名琴軒。", "軒中寄傲隱君子，方瞳鶴髪臞儒仙。", "閒中默契絲桐理，不待徽絃出宫徴。", "柳惲筆捶佐屬文，淵明手撫聊寄意。", "一篇叙此藏巾箱，歘爾六丁下取将。", "世無安世誰默識，才異束晳孰補亡。", "神物護持今復出，數紙蛟蛇親手澤。", "敢辭援筆補遺編，謾致區區貽厥力。"]'),
('f007462b-d40c-4810-975e-86326c8caa04','諸人各見和復和一首','葛勝仲','宋','宋诗','song-poetry','','[]','我祖還笏歸樂天，不羡戴冕兼乘軒。',128,'全唐诗/poet.song.78000.json','["我祖還笏歸樂天，不羡戴冕兼乘軒。", "掃門笑傲寄元趣，一龕相對惟金仙。", "辭藻翩翩能析理，字字清奇中商徴。", "響泉韻磬初不施，見色聞聲自真意。", "從來家學傳青箱，禄侈萬石今方将。", "此篇不愁暫飛去，天相斯文終不亡。", "孫曾秀傑今層出，餘慶仰承君子澤。", "莫言臨絕似獲麟，請看筆頭扛鼎力。"]'),
('31a63859-2cd7-4bcf-bbc4-058618ff4cd6','沈必先殿院用策字韻賦詩見贈謹依韻和時居盛林','葛勝仲','宋','宋诗','song-poetry','','[]','菁山遽用檀公策，水村來作浮家客。',112,'全唐诗/poet.song.78000.json','["菁山遽用檀公策，水村來作浮家客。", "五年霄漢隔音塵，此假相逢喜折屐。", "荒陂難覓鈷鉧潭，胸中丘壑有人傑。", "烏臺坐逼癡牀南，見事風生勇成癖。", "逆耳爭先貢皂囊，造膝仍頻對宣室。", "只今道梗淹荒村，汲直未肯儕公孫。", "時平已見龜墨食，尺一行催覲文石。"]'),
('6c67b04d-8a57-43ee-b22b-2f2096a85ebe','蒙維心示謝必先尚書餉筆佳什時維心方刊正三國史輙依韻攀和','葛勝仲','宋','宋诗','song-poetry','','[]','谷口之孫材刃銛，如針處囊立見尖。',224,'全唐诗/poet.song.78000.json','["谷口之孫材刃銛，如針處囊立見尖。", "平生苦心在墳索，入月猶未高騎蟾。", "若嫌壽史六十五，論次未必三長兼。", "與時諱惡難僂指，爲米溢美堪掀髯。", "浪言張華爲輟筆，至今詆者口不箝。", "因持衆製事編削，管城雖老聊復拈。", "明明褒譏淆涇渭，欲向素王師謹嚴。", "已刪卧龍無将略，過實仍刊諸葛瞻。", "東陽尚書助述作，束穎分餉出寶奩。", "自言宸廷夙霑賜，今以歸奉餘不潛。", "鷄距鹿毛青鏤管，品制一一形標籤。", "昔冠神羊書白簡，痛擊姦佞如針砭。", "并與書法奉君子，大書特書不可淹。", "懸知南董奮直筆，首於三馬誅姦憸。"]'),
('1cb95c09-97ed-4cd1-91b4-8bd164f202a1','次韻王得之方池父子翫月','葛勝仲','宋','宋诗','song-poetry','','[]','先生夜不眠，愛月真癡絕。',152,'全唐诗/poet.song.78000.json','["先生夜不眠，愛月真癡絕。", "呼兒飲文字，桃黍聊一雪。", "清光入酒墮胸次，照見萬卷非涉躐。", "商容顥氣寒徹骨，况是冰輪圓不缺。", "中宵影倒萬頃池，上下金盤兩澄徹。", "廣寒靈媛多飛瓊，煙凝露曖收羣聲。", "魚冷跳波聞靜岸，鵲驚遶樹當前楹。", "辭直道山來膝上，郎君吟興紛縱横。", "詩成父子定知已，門有佳兒真寜馨。", "不須靈液玻璃盌，一夢瑶臺亦非遠。"]'),
('6c02786f-dddb-4ca4-a857-98fc0f69e0f5','楊泰初權縣丞數寄示詩文作詩紀謝','葛勝仲','宋','宋诗','song-poetry','','[]','關西家世東都相，褫褐十年今始壮。',128,'全唐诗/poet.song.78000.json','["關西家世東都相，褫褐十年今始壮。", "一官棲棲百僚底，衆製翹翹萬夫上。", "憶昔曲臺尸列卿，謬厠春闈慚哲匠。", "英俊下沉勢欲拔，文章横流期少障。", "榜中上第溷元結，堂下一言驚叔向。", "頻蒙古錦倒清篇，更枉長鬚問無恙。", "詳觀歎賞欲投筆，退恧粗疏堪覆醤。", "吾衰文意已蹉跎，鳯閣當求舍人樣。"]'),
('ff0605a0-d545-4ebc-802c-c92743097261','程良器嘉量解元許爲寫照作詩求之','葛勝仲','宋','宋诗','song-poetry','','[]','虎頭千古丹青傑，誰言黠中有癡絕。',160,'全唐诗/poet.song.78000.json','["虎頭千古丹青傑，誰言黠中有癡絕。", "手揮五絃真勝詣，頰染三毫更超越。", "自言四體媸或妍，顧與妙處無相關。", "炯炯雙瞳點圓碧，筆下頓覺神明還。", "程郎言語妙天下，畫復通靈能變化。", "掃除俗骨畫如詩，摹寫天機詩似畫。", "竹齋溪嶼數相從，似蒙儃儃窺塵容。", "詆呵衆史露拙迹，疑有心畫藏胸中。", "寒鄉鼠目麞頭子，葛帔練裙謝龜紫。", "幼輿政自丘壑人，試爲寫傳巖石裏。"]'),
('c8a110ba-ccdc-4fef-b176-87e7281ec945','次韻范昌齡慶新居','葛勝仲','宋','宋诗','song-poetry','','[]','我家渺在澄江浦，泛宅來依白蘋渚。',112,'全唐诗/poet.song.78000.json','["我家渺在澄江浦，泛宅來依白蘋渚。", "客居十載席爲門，上蓋茅茨下榛楚。", "邇來作舍倒歸貲，聊爲兒曹庇寒暑。", "千巖萬壑相嫵媚，似以身嘗爲地主。", "樓外煙霞邀吐句，堂中墳史供稽古。", "歲晚居身可否間，簪裳束閣饒安閒。", "深愧詞人相俎豆，鶴書應不愧鍾山。"]'),
('5a780b9c-c601-4630-a012-38215a2aba74','先君忌飯僧悟空興之姪有詩和韻','葛勝仲','宋','宋诗','song-poetry','','[]','君不見毗耶居士人天英，化佛億萬文室盈。',118,'全唐诗/poet.song.78000.json','["君不見毗耶居士人天英，化佛億萬文室盈。", "清晨香積一盂食，厭足一切緊法力。", "又不見手捉麈尾生公廬，說經妙藴幾無餘。", "豈惟緇素日會面，粉碎虚空雨花片。", "我生歸命海潮音，况復劬勞諱日臨。", "三孤遺像涕沾臆，建齋達觀趨禅閾。", "悟空誰是悟真空，門前灌木吟悲風。"]'),
('7c803b05-cad6-4232-b48e-1509b165b56e','贈星洲僧了然','葛勝仲','宋','宋诗','song-poetry','','[]','禅林古有一宿覺，講席嘗聞一遍照。',112,'全唐诗/poet.song.78000.json','["禅林古有一宿覺，講席嘗聞一遍照。", "凡馬十駕及駿骨，況子秀穎顔齒少。", "星洲巖壑鎖煙雲，千柱浮空覺王廟。", "似聞焠掌作書淫，乍或横肱究心要。", "明窗淨几學參玄，二塗一得可前料。", "香浮牛首禮圓光，唄似魚山勝長嘯。", "聞熏大士豈忘言，機鋒嘿贊潮音妙。"]'),
('9b8a274d-3e96-4ce6-993b-0f4d0f7a45db','和陳簡齋韻','葛勝仲','宋','宋诗','song-poetry','','[]','馬鞭雖長不及腹，山林朝市兩角逐。',134,'全唐诗/poet.song.78000.json','["馬鞭雖長不及腹，山林朝市兩角逐。", "華堂誰掛元吉麞，坐使朱門變林谷。", "龍章鳯姿自有種，山野頭顱未爲辱。", "長沙寫真得天趣，下眎馮尹皆奴僕。", "君不見青州劉幡得異草，能遣死麕骨再肉。", "又不見廣平射麕變浮屠，因罷校獵投金鏃。", "兩幅陵陂槲葉香，儔侣共樂春草長。", "昂頭妥尾無所畏，窘拘知勝觸藩羊。"]'),
('446fc0ba-c9d5-4528-8d59-543eaa02b0fb','依韻和興之姪','葛勝仲','宋','宋诗','song-poetry','','[]','一真那有黑白業，佛槖枉用爲書篋。',112,'全唐诗/poet.song.78000.json','["一真那有黑白業，佛槖枉用爲書篋。", "人人反照自圖成，說甚一花開五葉。", "了無結習便超脱，因有罣礙生怖懾。", "山鬼窟中求活計，玄關欲透知何劫。", "匝天遍地自心源，若解承當真要捷。", "樹林水鳥皆法音，露柱幡竿光煒燁。", "世上盲聾喑啞人，試問道師作麽接。"]'),
('bd672a2c-169f-40f1-9a31-1fa77b29ccf8','寄題伸仲芳美亭','葛勝仲','宋','宋诗','song-poetry','','[]','漁舟一出桃源路，煙鎻雲埋迷舊處。',96,'全唐诗/poet.song.78000.json','["漁舟一出桃源路，煙鎻雲埋迷舊處。", "那知九龍有仙村，漫山灼灼花無數。", "人言却老是此花，只今已似劉晨家。", "微風披拂飛紅雨，杲日照耀蒸紅霞。", "似聞花間新結宇，醉吟多是神仙侣。", "更求人面相映紅，我欲叩門求雪黍。"]'),
('80cc8e86-6e95-4ee4-ad7d-cf410033f646','圓復師将遊四明用道祖韻作詩贈行','葛勝仲','宋','宋诗','song-poetry','','[]','禅宗不減宿一覺，文性還同照一遍。',128,'全唐诗/poet.song.78000.json','["禅宗不減宿一覺，文性還同照一遍。", "啞羊豈是一流人，漆瞳爛爛巖中電。", "機緣未遇閟金提，雲水光中挂衲衣。", "定回時起橐駞坐，秀句一吐胸中奇。", "過我郡齋那聽去，衮衮談玄侵日暮。", "西風吹面作新凉，騰装欲指鄞江路。", "一庵錢料山幽深，欲抛印綬聊招尋。", "倦遊歸來問無恙，東第飄然正角巾。"]'),
('dbb95ba1-bf92-400a-a5f1-278b586949d3','招道祖簽判嘗暑酎辱示佳篇紀事輙依韻奉和且約再冰釀云','葛勝仲','宋','宋诗','song-poetry','','[]','君不見兵火連年擾江漢，一介藎臣無斷斷。',203,'全唐诗/poet.song.78000.json','["君不見兵火連年擾江漢，一介藎臣無斷斷。", "列城守将遁或降，那得捐軀顔與叚。", "鏖兵喋血八年間，西失平夏北折蘭。", "犇軍知是何雞狗，坐想飛将張與關。", "草莽臣謀未云獲，且復澆愁傾大白。", "平時徒有扇障塵，一笑未辨鬚纒帛。", "相邀聊共聖賢中，但愁燭跋鴟夷空。", "沉酣不畏輕出舌，驚懼懸知不入胸。", "午夜醉歸聞踏月，林影灘聲助清絕。", "糟兵好向水村營，壑谷正爲吾曹設。", "儒生嗜酒多有之，高陽酩酊無所缺。", "莫言酌我慎無多，休弹賀若唱回波，騰騰相送入無何。"]'),
('abd07e13-c919-4091-b977-d8dc2d3440b6','二十五日道祖滄浪亭落成召會','葛勝仲','宋','宋诗','song-poetry','','[]','東園延袤不論畝，樹梓成行俱楚楚。',192,'全唐诗/poet.song.78000.json','["東園延袤不論畝，樹梓成行俱楚楚。", "方池瀰漫漲漣漪，藕花清酣嬌欲語。", "臨流新築滄浪亭，斧斤斷手邀落成。", "蘇家風月舊無價，千金買得亭和名。", "穹廬飲馬吳江水，長洲萬井紅烟起。", "齊雲樓觀委寒灰，那有相家歌舞地。", "稽山别乘今豪英，肯将勝事頽家聲。", "青氊舊物今在眼，彷彿北牖仍東榮。", "把盞聊爲主人壽，亂離已往空搔首。", "請看前日閙巫毉，豈有閒情舉樽酒。", "朝來大火落南躔，已覺病骨蘇凉天。", "剩擣橙虀斫鱸鱠，全家醉倒秋風前。"]'),
('6a1c31b6-a1e1-41c6-8f97-a0e21f909be1','流杯','葛勝仲','宋','宋诗','song-poetry','','[]','美哉洋洋曲流水，碧可染衣清徹底。',128,'全唐诗/poet.song.78000.json','["美哉洋洋曲流水，碧可染衣清徹底。", "我傾山資結茅舍，兩載經營端爲此。", "春風上已一月前，小試禊事來水邊。", "胡床醉坐略少長，羽觴輕泛隨洄沿。", "道人護戒無酒欲，笑挹清波作醽醁。", "崖蜜相和代引滿，自言過免三十六。", "隨緣戲劇亦何嫌，勝遊從來支許兼。", "久知世味如嚼蠟，未應貪著中邊甜。"]'),
('720c1d12-500d-4df2-a60c-d450539c2e9a','次韻道祖大水','葛勝仲','宋','宋诗','song-poetry','','[]','君不見綠槐蔭夏摇千門，移秧遍野繰盈盆。',131,'全唐诗/poet.song.78000.json','["君不見綠槐蔭夏摇千門，移秧遍野繰盈盆。", "天公忽作彌月雨，憂歲上勤黄屋尊。", "我家茆廬劣容膝，隨水傾摧非瑞室。", "街衢生魚堪佐饔，簷霤垂龍欲穿石。", "仰天又見興油雲，乾雨誤點波連村。", "馬牛不辯固其理，鼃黽同處何容論。", "休歎棲苴接飛翼，林端會見賓紅日。", "木饑水毁儻時運，救灾行看恩洋溢。"]'),
('36cbbc6a-26a7-4872-aea9-b5d379e47ade','同道祖及子舍遊茶山歸因成','葛勝仲','宋','宋诗','song-poetry','','[]','寒窗送曙雞一鳴，尋山蓐食天初晴。',208,'全唐诗/poet.song.78000.json','["寒窗送曙雞一鳴，尋山蓐食天初晴。", "水口溪窮爲停棹，步携東坦仍添丁。", "虎頭巖高山色好，竹輿遥睇眼爲青。", "花瀨濛濛勝紫氣，微花拂袵聞芳馨。", "岌峨懸臼與天接，脚力欲趁飛猱輕。", "此邦佳處遍尋陟，夫差所顧獨未經。", "兹遊野服穿不借，自勝五馬仍雙旌。", "憶昔貞元守修貢，木瓜堂廡輝山扃。", "兩邦歌舞競姝麗，穀雨不許遨頭醒。", "只今金沙雜榛莽，空照華髪垂星星。", "近澗喧豗泉㶁㶁，遠峰嬌膩雲英英。", "山僧意勤苞紫笋，傾蓋一笑無平生。", "息黥補劓有甘寝，夢覺起作遊山行。"]'),
('d28cfb49-7580-4bdd-96ca-4ed193c1df05','新池水涸股引于前溪辱道祖來觀','葛勝仲','宋','宋诗','song-poetry','','[]','吾廬新築薰風堂，其下方池手親掘。',128,'全唐诗/poet.song.78000.json','["吾廬新築薰風堂，其下方池手親掘。", "畚插初無鄰里相，垠隅那有波瀾闊。", "旱涸俄驚拆龜兆，灌輸未免翻龍骨。", "街南大浸卷滔滔，巷北小渠來汨汨。", "膠杯忽覺水痕漲，抱甕免嗟人力竭。", "已憐紅芰浹枯荄，更喜頳鱗救濡沫。", "幽居勝事快先睹，上客高軒爲輕出。", "蛟龍好在且泥蟠，他年豈復池中物。"]'),
('0e1c93a7-0348-446b-a804-599e912fac5b','初得庵基於青山用立方韻請道祖同賦','葛勝仲','宋','宋诗','song-poetry','','[]','身閒那贈繞朝策，來作菁山數旬客。',128,'全唐诗/poet.song.78000.json','["身閒那贈繞朝策，來作菁山數旬客。", "結庵痛謝九流賓，輕重嫌人分履屐。", "才通箭道菖蒲潭，幼輿政合居山巖。", "鬭健更須升絕頂，接天巨浸浮東南。", "從來不辦王濟癖，石磴騎危甘脚歷。", "欲将土木化荆榛，坐嘆清風來入室。", "練裙葛帔居山村，共怪膏粱相國孫。", "祝雞爲鄰言不食，自此相從煮白石。"]'),
('9e791f8e-6adb-4b66-9f0d-d5e7426e1eeb','道祖見和復賦一首','葛勝仲','宋','宋诗','song-poetry','','[]','人言不飲第一策，况我携貧來作客。',128,'全唐诗/poet.song.78000.json','["人言不飲第一策，况我携貧來作客。", "破衣任笑頻見肘，斷鞋不辦時新屐。", "公材公望非丁潭，世人誰許瞻巖巖。", "豺狼滿道生理窄，立錐方卜南山南。", "十年丘壑幾成癖，澄懷坐想真歷歷。", "難希蒋詡開三徑，且學陳蕃事一室。", "時危花柳自村村，未害含飴仍弄孫。", "淡飯且安禅悦食，儲錢更買奇礓石。"]'),
('17b2a944-d8a3-48ef-a6be-e749743b76c7','大暑新居納凉和小子韻','葛勝仲','宋','宋诗','song-poetry','','[]','至後金柔伏日三，旱氣焚宣勢如惔。',160,'全唐诗/poet.song.78000.json','["至後金柔伏日三，旱氣焚宣勢如惔。", "火井湧沸烟生嵐，鶴髪遺老素未諳。", "我居瀕澤深眈眈，修廊飛廡賢僧庵。", "薰然好風來自南，如甘露門開瞿曇。", "如客懷冰吐清談，有亭自雨臨深潭。", "不假凉草生毵毵，天日炎赫反所貪。", "我窮儲無石與甔，枵然饑腹空婪酣。", "后皇矜憐百不堪，免使熟爛聊包涵。", "王城衮衮穿朝衫，跨馬揮汗流朱藍。", "獨逃靡盬侍魚泔，坐享逸樂捫心慚。"]'),
('81ee7a38-e0ee-4dde-aba5-300bd5454f4c','用立方韻二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','山村艱食宇晝合，齋鉢相呼坐僧榻。',64,'全唐诗/poet.song.78000.json','["山村艱食宇晝合，齋鉢相呼坐僧榻。", "今朝痩羊忽入饌，云是餕餘徹膢臘。", "年大才疏合退休，尚玷恩華只自羞。", "賞延亹亹來踵武，命服童孫尚羈午。"]'),
('64bd7cb4-2228-4214-a44e-01f63c67d0ca','用立方韻二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','仕宦由來須遇合，未遇杜門寜穴榻。',64,'全唐诗/poet.song.78000.json','["仕宦由來須遇合，未遇杜門寜穴榻。", "尊無泛蟻浪經春，突有懸貆偶乘臘。", "郡印還官得小休，桑樞席門何足羞。", "幽居不羡裴掌武，綠野堂前橋號午。"]'),
('4b4f1f42-8f99-4c7e-8c4e-6b8d499457ac','立方闢小閣附火興之姪作詩勸會客次韻','葛勝仲','宋','宋诗','song-poetry','','[]','吾兒玄學師老懷，嚴持月六八關齋。',128,'全唐诗/poet.song.78000.json','["吾兒玄學師老懷，嚴持月六八關齋。", "新來五辛不入口，坐使妻歎生不諧。", "自言丈室淨名量，惟期禅侣來存訪。", "栗里豈獨尊常空，亦乏秦聲亂舂相。", "朝來天雨瑶花霏，句如連璧來交輝。", "鹿柈茶果亦易具，不爾恐致膏肓譏。", "幻界政應頻燕喜，酒盡爲謀當更起。", "趨庭爲爾復緩頰，一盃既空難但已。"]'),
('297f7d90-f393-4770-a1e1-ee2ad4a29fe9','次韻大人待次吳陵邑五首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','待次吳陵邑，身修道日章。',48,'全唐诗/poet.song.78000.json','["待次吳陵邑，身修道日章。", "蘭陔留古郡，花縣得鄰鄉。", "未即摶扶上，端嫌代斵傷。", "蕭閒文墨外，樂趣問濠梁。"]'),
('c54b6984-afb4-4137-9b15-39ed461efde2','次韻大人待次吳陵邑五首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','待次吳陵邑，優哉閲歲年。',48,'全唐诗/poet.song.78000.json','["待次吳陵邑，優哉閲歲年。", "鳯池疏海角，鶠閣竦城顛。", "蒔藥時分穎，栽花自溉泉。", "新篇談笑就，寄自魯邦傅。"]'),
('efb5c277-9b86-411f-a150-275721e16220','次韻大人待次吳陵邑五首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','待次吳陵邑，行趨寶婺邦。',48,'全唐诗/poet.song.78000.json','["待次吳陵邑，行趨寶婺邦。", "蔥蘢連越岫，澄澈泳桐江。", "八詠風生座，雙林月映窗。", "勝遊知不晚，官履欲飛雙。"]'),
('61c08387-2136-4cac-8fb7-b50786c25d5f','次韻大人待次吳陵邑五首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','待次吳陵邑，常安揭小軒。',48,'全唐诗/poet.song.78000.json','["待次吳陵邑，常安揭小軒。", "祗從支遁隱，不問景純言。", "顔巷居多樂，陶廬似少喧。", "朝歌屈虞詡，清切未殊恩。"]'),
('7f27c85c-f673-4160-9949-3707fa108960','次韻大人待次吳陵邑五首  其五','葛勝仲','宋','宋诗','song-poetry','','[]','待次吳陵邑，鸝黄報早春。',48,'全唐诗/poet.song.78000.json','["待次吳陵邑，鸝黄報早春。", "紅歸花蕾淺，青到柳梢新。", "窮約那趨俗，虗緣自葆真。", "榮枯多反衍，坐笑黨頻頻。"]'),
('a156274e-f69d-445e-a50f-e8b4fca7548d','和送張元方南京掾','葛勝仲','宋','宋诗','song-poetry','','[]','下位沉英俊，青編樂自多。',48,'全唐诗/poet.song.78000.json','["下位沉英俊，青編樂自多。", "官曹依綠水，詞筆注黄河。", "初日嗟貪鼠，今年未飲鵝。", "陪京資禄養，何計免奔波。"]'),
('4c7c3ec2-fc7c-4e4f-9975-50a73235020c','題横林館','葛勝仲','宋','宋诗','song-poetry','','[]','治劇知非稱，投閒得退棲。',48,'全唐诗/poet.song.78000.json','["治劇知非稱，投閒得退棲。", "聊從詩酒污，頓免簿書迷。", "幻界榮枯小，真乘寵辱齊。", "横林孤館靜，辰發踏荒雞。"]'),
('08e4c6d5-cf06-4af6-9b6b-e481061fb1d7','題須江驛','葛勝仲','宋','宋诗','song-poetry','','[]','寓館飄風雨，高文耀日星。',48,'全唐诗/poet.song.78000.json','["寓館飄風雨，高文耀日星。", "閒身關歷覧，左宦在零丁。", "不見雌雄行，空存長短亭。", "襄陽知漸近，峴首映寒坰。"]'),
('f6a97ccb-53ae-4586-be18-8b47b1c3253a','次韻李子京宋城道中詩三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','沙岡牛酒市，渺岸指前程。',48,'全唐诗/poet.song.78000.json','["沙岡牛酒市，渺岸指前程。", "斷梗隨鷗遠，殘霞與鶩平。", "村聲喧坱莽，林影倒澄瀛。", "俗物難遮眼，支離病骨輕。"]'),
('4b22a4a6-e9e4-4e4a-9829-f43bc537c3f8','次韻李子京宋城道中詩三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','通塗了無畏，清世足章程。',48,'全唐诗/poet.song.78000.json','["通塗了無畏，清世足章程。", "擊壤民風樂，持衡國勢平。", "米鹽豐道路，桴鼓靜寰瀛。", "佳氣葱葱近，心隨過鳥輕。"]'),
('9c2aecd2-4889-49ec-9c0a-302a13b167a6','次韻李子京宋城道中詩三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','積累三冬學，淹通萬古程。',48,'全唐诗/poet.song.78000.json','["積累三冬學，淹通萬古程。", "孤高吳子札，該洽蜀君平。", "曹事今司李，官封近接瀛。", "公侯階有漸，五斗未容輕。"]'),
('8a0c628f-fd43-4b08-82f6-c47a726c8a2d','寄題海會晚實軒','葛勝仲','宋','宋诗','song-poetry','','[]','素節清霜重，金苞照座隅。',48,'全唐诗/poet.song.78000.json','["素節清霜重，金苞照座隅。", "根深容四老，品貴入三都。", "騷客真宜友，侯封未易奴。", "舊時書兩廟，感亊涕沾濡。"]'),
('b5a4c293-9a96-4781-85d7-99b2328f578f','登攙雲亭和工部兄韻','葛勝仲','宋','宋诗','song-poetry','','[]','危亭聳山巔，縈紆一徑穿。',48,'全唐诗/poet.song.78000.json','["危亭聳山巔，縈紆一徑穿。", "林深将蔽日，濤怒欲浮天。", "江北迷堤樹，淮南起餉煙。", "結庵容寄傲，從此息攀緣。"]'),
('448ca066-0a78-4f98-abaa-d045ee15abe8','次韻和慶善遊圓覺寺歸四首時僕亦方自徑山歸  其一','葛勝仲','宋','宋诗','song-poetry','','[]','青鞋訪雲水，僧饌飫茭蒲。',48,'全唐诗/poet.song.78000.json','["青鞋訪雲水，僧饌飫茭蒲。", "落拓人誰識，迂愚世所無。", "鷃鵬從物化，牛馬任人呼。", "世事何須問，諸公在禁途。"]'),
('29b8ae8d-31dc-40a6-b77e-77c27e63e31e','次韻和慶善遊圓覺寺歸四首時僕亦方自徑山歸  其二','葛勝仲','宋','宋诗','song-poetry','','[]','步屧尋幽子，談玄孰造微。',48,'全唐诗/poet.song.78000.json','["步屧尋幽子，談玄孰造微。", "離羣雖念獨，選勝遂忘歸。", "世路從爭席，年華逼授衣。", "平生付雙瑣，手撫送鴻飛。"]'),
('5c421afd-8eac-4cbb-bfe8-d9a3d4476871','次韻和慶善遊圓覺寺歸四首時僕亦方自徑山歸  其三','葛勝仲','宋','宋诗','song-poetry','','[]','招提行問道，末學倦編蒲。',48,'全唐诗/poet.song.78000.json','["招提行問道，末學倦編蒲。", "不際方爲際，應無令盡無。", "歸來聊自賦，隱去謝人呼。", "宦路分夷險，平生誰識途。"]'),
('c4fe33ef-af6d-488c-82ab-48dbfe1f8b3b','次韻和慶善遊圓覺寺歸四首時僕亦方自徑山歸  其四','葛勝仲','宋','宋诗','song-poetry','','[]','黄花兼露重，白鳥带烟微。',48,'全唐诗/poet.song.78000.json','["黄花兼露重，白鳥带烟微。", "雲伴淵明出，風隨曾點歸。", "經丘携芰製，視膳輟蘭衣。", "景物供清興，詩高直欲飛。"]'),
('8a67154f-c9ac-459b-a907-e1858ceddc36','夜歸不寐','葛勝仲','宋','宋诗','song-poetry','','[]','流鶯驚節物，樂事二毛前。',48,'全唐诗/poet.song.78000.json','["流鶯驚節物，樂事二毛前。", "山簡不堪醉，淵明方欲眠。", "談餘愁似繭，坐久腹如蟬。", "日出重遊衍，殘花有杜鵑。"]'),
('5a418590-b515-4e17-acbc-62951d7c44db','次韻慶善九日','葛勝仲','宋','宋诗','song-poetry','','[]','二九依辰至，追歡付麴生。',48,'全唐诗/poet.song.78000.json','["二九依辰至，追歡付麴生。", "竹根拚醉卧，菊蘂正牽情。", "杜曲酬佳節，陶翁愛此名。", "吹花更吹帽，相值得豪英。"]'),
('fbf42c99-0a33-4409-9885-054708fe6226','慶善再和復和','葛勝仲','宋','宋诗','song-poetry','','[]','異縣逢佳節，羈愁太痩生。',48,'全唐诗/poet.song.78000.json','["異縣逢佳節，羈愁太痩生。", "黄花真解事，白首緩傷情。", "十日尚堪醉，一杯猶有名。", "眼前多勝士，何必洛中英。"]'),
('3b092ff0-68ef-4f78-b946-d4fc47f873c9','幽居二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','幽居無俗韻，勝事特關心。',48,'全唐诗/poet.song.78000.json','["幽居無俗韻，勝事特關心。", "研度疲三豕，床敷戲一禽。", "覆舟棋自戒，中聖酒時斟。", "蕭灑侯來訪，窗前綠透林。"]'),
('abe6283a-e5d8-4ba4-9b23-38a200fa7984','幽居二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','名勝音塵隔，懷賢自渴饑。',48,'全唐诗/poet.song.78000.json','["名勝音塵隔，懷賢自渴饑。", "千巖聳秀處，一榻獨懸時。", "盛夏衣裳懶，深林枕簟宜。", "招邀何以待，數卷謫仙詩。"]'),
('e67c5da1-6355-4f49-9785-7903653bea49','即事二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','四月麥已熟，清寒久不禁。',48,'全唐诗/poet.song.78000.json','["四月麥已熟，清寒久不禁。", "林深來蜀魄，屋破絕燕禽。", "幽屏兒仍出，貧居病更侵。", "蕭然北窗下，趺坐獨求心。"]'),
('70ac1213-4bd7-4f43-af01-1f74715d7c30','即事二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','巷轉柔桑陌，門依綠柳橋。',48,'全唐诗/poet.song.78000.json','["巷轉柔桑陌，門依綠柳橋。", "因人嫌碌碌，拔俗自超超。", "嫩碧半篙漲，殘紅一眼飄。", "卑棲有微分，斥鷃得逍遥。"]'),
('9b1e759a-f86e-4475-902b-39523b35e652','試墨','葛勝仲','宋','宋诗','song-poetry','','[]','爲適閒中趣，晴窗試墨卿。',48,'全唐诗/poet.song.78000.json','["爲適閒中趣，晴窗試墨卿。", "磨研輕有暈，條暢細無聲。", "紫玉浮雲净，寒煙點漆明。", "鳥鳴春晝寂，一笑萬緣輕。"]'),
('e87a35c1-062a-4fb0-ba6b-8a38aa9bca6b','微雨小飲客至閽人辭以出令追路已不及偶作','葛勝仲','宋','宋诗','song-poetry','','[]','昨日持三白，今朝解八支。',48,'全唐诗/poet.song.78000.json','["昨日持三白，今朝解八支。", "聊爲犀首飲，儘笑虎頭癡。", "冠履從來懶，杯鐺且自持。", "是中多樂趣，勿遣外人知。"]'),
('42e03f00-b035-4905-b709-457cd5a2231b','題庵壁','葛勝仲','宋','宋诗','song-poetry','','[]','葛翁携葛姓，小愒葛橋邊。',48,'全唐诗/poet.song.78000.json','["葛翁携葛姓，小愒葛橋邊。", "葛泉出蘿葛，一派自潺湲。", "咫尺葛山觀，金丹問葛仙。", "耳孫忝瓜葛，行隱葛山巔。"]'),
('8557728a-61ff-440e-a4ff-6a4a425cf313','龍井','葛勝仲','宋','宋诗','song-poetry','','[]','古甃泓澄淺，涓涓似有源。',48,'全唐诗/poet.song.78000.json','["古甃泓澄淺，涓涓似有源。", "蒸雲驟遊宇，吹雨忽翻盆。", "泉伏微如蠋，泥蟠肆任蚖。", "嶄然頭角見，坐禠葉公魂。"]'),
('1f5f09fc-bab6-4996-b989-a37e5782c4ab','龍堂','葛勝仲','宋','宋诗','song-poetry','','[]','一室飛山腹，蜿蜒像設精。',48,'全唐诗/poet.song.78000.json','["一室飛山腹，蜿蜒像設精。", "班傳五色貴，食辨百花名。", "睡頷應難探，雲鱗詎可嬰。", "從祈得甘澤，棲壁有碑銘。"]'),
('1c8968b6-0719-4420-9e5e-e693feb5f89c','觀山謁蒋叔明趙鄰叔二墳','葛勝仲','宋','宋诗','song-poetry','','[]','寒食觀山道，佳城隔壠分。',48,'全唐诗/poet.song.78000.json','["寒食觀山道，佳城隔壠分。", "趙公今不武，蒋老去修文。", "歌薤猶前日，栽松已插雲。", "生平各投分，絮酒薦蒿焄。"]'),
('5e4c63cb-e442-49ca-9cdd-0cb51dd97089','昭懷皇后挽歌詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','天作元符合，哀榮極始終。',48,'全唐诗/poet.song.78000.json','["天作元符合，哀榮極始終。", "陵陪永泰近，禮視孝章隆。", "匰主躋新廟，廞衣賁下宫。", "柏城連獻愍，蕭瑟夜臺風。"]'),
('dabb536b-3621-4f49-bee3-f62039886dee','昭懷皇后挽歌詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','寂寞崇恩殿，飈輪去弗還。',48,'全唐诗/poet.song.78000.json','["寂寞崇恩殿，飈輪去弗還。", "尊名千古外，顯冊兩朝間。", "座冷金釭暖，香消玉釡閒。", "神遊返姑射，脱屣謝塵寰。"]'),
('91b02a11-ea4a-4ffd-989f-f48dd73658b0','李楚老尚書挽歌詞三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','席寵三台後，疏恩八座榮。',48,'全唐诗/poet.song.78000.json','["席寵三台後，疏恩八座榮。", "朝廷真大蔡，邊鄙更長城。", "戾社符刀夢，王墀識履聲。", "陰功歸壤子，衮衮出名卿。"]'),
('b9b3a3b3-064a-41d8-bb2b-9a97e6e85cd1','李楚老尚書挽歌詞三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','東里推人傑，西清列從班。',48,'全唐诗/poet.song.78000.json','["東里推人傑，西清列從班。", "袴襦康二蜀，裘带靖三關。", "赤白囊無警，朱丹轂遂還。", "登龍門舊貴，奕葉道家山。"]'),
('5ea64284-8fd4-4ce9-ad01-85e818f0b81a','李楚老尚書挽歌詞三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','得謝恩重起，追榮爵更崇。',48,'全唐诗/poet.song.78000.json','["得謝恩重起，追榮爵更崇。", "龍蛇新歲忌，鵷鷺舊行空。", "圖象人懷惠，尊名帝念功。", "遭時淹陳寔，大耋偶相同。"]'),
('a7239d9f-edb6-41d0-9714-18adb203ae2f','方待制挽詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','瑣闥樞機地，儲闈羽翼人。',48,'全唐诗/poet.song.78000.json','["瑣闥樞機地，儲闈羽翼人。", "蕝儀容典備，校歷閏餘親。", "雲路箕乘說，泉臺嶽返申。", "荀龍行濟美，交舊獨傷神。"]'),
('49207843-7301-426e-8eb5-93847fec348e','方待制挽詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','佳城釃酒奠，長夜殞星知。',48,'全唐诗/poet.song.78000.json','["佳城釃酒奠，長夜殞星知。", "今代儒林傳，諸方德政碑。", "朝廷躬蹇蹇，丘壑自怡怡。", "安得研幾士，推窮妙萬蓍。"]'),
('c44133bb-a697-4cff-9b09-4d592bd387aa','莫子憲中奉挽歌詞三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','嗜學唯何甚，飛聲實久如。',48,'全唐诗/poet.song.78000.json','["嗜學唯何甚，飛聲實久如。", "郎星頻省户，卿月轉周廬。", "桂奠房祠酒，芸殘冊府書。", "音容千古外，墳檟閟南徐。"]'),
('fdc8dd25-81ba-422f-9883-97f2e52a7f78','莫子憲中奉挽歌詞三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','材資合黄閣，器業偃朱轓。',48,'全唐诗/poet.song.78000.json','["材資合黄閣，器業偃朱轓。", "教府依模範，樞庭驗討論。", "成梁繄杜預，障水幸王尊。", "二紀朋僚舊，追懷慟寝門。"]'),
('1ba222d4-0b2e-4d0e-8d5d-35af4a395b4b','莫子憲中奉挽歌詞三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','令子承家學，諸儒擁後塵。',48,'全唐诗/poet.song.78000.json','["令子承家學，諸儒擁後塵。", "無雙問江夏，第一擢平津。", "宣諭傳黄甲，褒稱對紫宸。", "公師有追賁，行慶密章新。"]'),
('fe64b56c-679a-4f81-80b2-9a1dc739bcf5','致政朝奉親家丁公挽歌詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','節概松千丈，聲華桂一枝。',48,'全唐诗/poet.song.78000.json','["節概松千丈，聲華桂一枝。", "牽絲始遊宦，解組遽安時。", "人美抛官早，身嫌了事遲。", "反真聊示病，曾不謁巫毉。"]'),
('fcbf267b-9f36-47ea-b6df-3e99ea1b0a09','致政朝奉親家丁公挽歌詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','貫籍明光殿，頤神通德門。',48,'全唐诗/poet.song.78000.json','["貫籍明光殿，頤神通德門。", "慶源來化鶴，高隱謝驚猿。", "冕紱承前範，箕裘付後昆。", "論婚情義重，祖載獨傷魂。"]'),
('afd229ec-77c4-46e7-b6fe-66dd429fa30e','胡誠甫朝散挽歌辭','葛勝仲','宋','宋诗','song-poetry','','[]','學擅尃門邃，年躋賜几尊。',48,'全唐诗/poet.song.78000.json','["學擅尃門邃，年躋賜几尊。", "降崧鍾秀氣，遊岱返英魂。", "宰樹黄巖拱，房祠赤紱昏。", "密章行胙國，有子大公門。"]'),
('35a01f80-50b5-459a-a57d-0ef2db40fc14','凌丞事挽詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','銓材今秀孝，較德古沉冥。',48,'全唐诗/poet.song.78000.json','["銓材今秀孝，較德古沉冥。", "已悟桃花理，猶繙貝葉經。", "妙觀存述造，陰德有平停。", "今夜稽山道，天沉處士星。"]'),
('0d1e2362-7bc8-486d-a30e-31bc054c3bfd','凌丞事挽詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','紫誥恩華重，青綸命服榮。',48,'全唐诗/poet.song.78000.json','["紫誥恩華重，青綸命服榮。", "無香然玉釡，有子勝金籝。", "禅解超尊宿，鄉評服老成。", "棘人深孺慕，捧土作佳城。"]'),
('8d8f9677-def4-4256-8d29-4c209f23bfc9','許處士挽詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','場籍聲華茂，家庭志意修。',48,'全唐诗/poet.song.78000.json','["場籍聲華茂，家庭志意修。", "光陰歸翰墨，器業謾林丘。", "學府空雞蹠，賢書誤鶴頭。", "門基多克荷，衮衮出公侯。"]'),
('dc95610e-bbdb-411b-a0a0-fa9c8d7ad84f','許處士挽詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','濉陽忠烈後，泊水老成人。',48,'全唐诗/poet.song.78000.json','["濉陽忠烈後，泊水老成人。", "庠校推模表，州閭訓睦婣。", "决疑辭郭璞，營急似陳遵。", "碑字深無愧，鑾坡得從臣。"]'),
('cca28f2a-79b2-45d6-8d11-dabb199db631','魯國太夫人楊氏挽歌詞四首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','教子青雲上，持身白業中。',48,'全唐诗/poet.song.78000.json','["教子青雲上，持身白業中。", "挟醫來相第，賜襚出宸衷。", "鸞誥前恩在，魚軒舊轍空。", "東方妙喜國，斷取作幽宫。"]'),
('e45e219b-1691-4580-922f-887d6fee93b6','魯國太夫人楊氏挽歌詞四首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','未肖甘泉像，先疏曲阜封。',48,'全唐诗/poet.song.78000.json','["未肖甘泉像，先疏曲阜封。", "春秋綿六紀，甘毳極千鍾。", "遠日朝廷趣，容車郡國供。", "吳人交惻楚，相杵夜停舂。"]'),
('deb2f6ea-665d-473d-8d2f-32e78e7c7d94','魯國太夫人楊氏挽歌詞四首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','鱣堂推胄貴，蝉冕嫓夫榮。',48,'全唐诗/poet.song.78000.json','["鱣堂推胄貴，蝉冕嫓夫榮。", "玉釡香無驗，金輝館已迎。", "鵲梁占胙土，龜墨報佳城。", "今代誰詞伯，刊碑遠德聲。"]'),
('dc853666-53c2-417f-9792-ab7e572cd3c7','魯國太夫人楊氏挽歌詞四首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','子貴今台輔，才高古藎臣。',48,'全唐诗/poet.song.78000.json','["子貴今台輔，才高古藎臣。", "與民開壽域，爲國斡洪鈞。", "會友傷陶髪，迎師憶孟鄰。", "欒欒親負土，腸斷冢邊麟。"]'),
('7775cf82-6f47-4b56-8df9-121336e8dc80','學正郭勉夫示詩次韻答之','葛勝仲','宋','宋诗','song-poetry','','[]','有道家聲遠，沉機足幹時。',240,'全唐诗/poet.song.78000.json','["有道家聲遠，沉機足幹時。", "松生非培塿，檀伐待淪漪。", "虎脊卑凡乘，蛾眉疾衆姬。", "一鳴驚伍舉，千里器王珪。", "德令温温著，名香藹藹馳。", "披荘問同異，執禮判嫌疑。", "操尙傾涓子，才華進客兒。", "適齊非鼓瑟，逃楚笑吹箎。", "藝苑高三絕，書庠肅五儀。", "涌泉推敏思，翻水播英辭。", "計吏趨蘭省，諸生偃璧池。", "行殊師也過，論鄙釋之卑。", "默識扳安世，多方劣惠施。", "風標寒似玉，機警利如錐。", "高翥千齡鶴，前知五總龜。", "碎金珍謝傅，餘錦夢丘遲。", "謬學邯郸步，工施渾沌眉。", "文科将赫奕，榮路即威夷。", "器業今爲重，功勲士所期。", "他年青竹上，凜凛看名垂。"]'),
('4bbf6917-21b3-4232-a930-51f21ad2c57d','勉夫示詩鳴其窮甚哀因次韻答之極其貧悴之態而卒勉之以科舉庶廣其意也','葛勝仲','宋','宋诗','song-poetry','','[]','落落超餘子，干時命未當。',240,'全唐诗/poet.song.78000.json','["落落超餘子，干時命未當。", "摧傷窘文陣，拓落尚書庠。", "賨貨無山積，毛羣欠谷量。", "蝸廬寒不展，龍具夜何長。", "牘謾三千富，年侵四十彊。", "有車乘下澤，無夢入高唐。", "藜糗甘珍薦，桑樞自峻堂。", "書傭跧淨院，舂賃寄修廊。", "異鬼時相笑，鄰家許借光。", "低佪涸轍鮒，進退觸藩羊。", "原憲貧非病，榮期樂處常。", "財雄劣程鄭，貲鉅笑秦楊。", "甫里田多潦，潯陽徑就荒。", "白駒嗟逸豫，黄鳥怨遺忘。", "薪乏支離束，錢空趙壹囊。", "晨餐煩乞米，夜讀待然糠。", "詞藝聞精敏，名聲已激揚。", "登榮将赫奕，處困暫徊徨。", "志氣宜軒翥，文辭忌怨傷。", "逐貧高賦就，豐廪換龜膓。"]'),
('1e2ebb0d-e405-47c3-9ac3-e3b30f4fefd3','中秋和韻','葛勝仲','宋','宋诗','song-poetry','','[]','凉夜清商半，層空素月初。',241,'全唐诗/poet.song.78000.json','["凉夜清商半，層空素月初。", "騰清來洞戶，委照入蓂空廬。", "銀海亭亭上，金波煜煜舒。", "纖阿今夕御，少昊昔年墟。", "魄射澄瀾倒，光涵脱葉疏。", "階蓂生乍足，庭桂落堪鋤。", "東鄙人摛藻，西園客燕胥。", "未高尤瀲灔，當午更踟躇。", "氣挟金飈爽，光從玉宇攄。", "鑑圓疑傍架，輪正若依輿。", "影挂千林上，明同萬里餘。", "雲開無點綴，火退覺虚徐。", "滉漾吞星彩，晶熒遡日車。", "驚枝翻異鵲，減腦謝遊魚。", "田凈瓊初種，窗明雪未除。", "胡牀情戀嫪，小舫興勤渠。", "珠盛輝兹水，潮高壮尾閭。", "傾寒滌肝胃，揚彩媚衣裾。", "郡古休敲榜，官閒置簡書。", "萬家興釂鼓，愷樂旐維旟。"]'),
('33b7bb88-feb5-4bfd-a052-05e8697c9110','次韻逢叔喜雪','葛勝仲','宋','宋诗','song-poetry','','[]','始見穿簾隙，俄驚照屋山。',120,'全唐诗/poet.song.78000.json','["始見穿簾隙，俄驚照屋山。", "春容先苑樹，夜色誤城關。", "砧積疑鋪練，盆消若盜環。", "酒醇懷泛蟻，詩敏過求鷴。", "滉漾迷珠澤，便娟掩玉顔。", "人饑氈共嚥，馬凍薦難慳。", "勢急因空亂，形移任地班。", "舞深爭巧黠，囀細弄幽閒。", "淮右提師入，山陰訪友還。", "江湖禽影斷，絃木未須彎。"]'),
('a1ea68c9-a85b-4c27-87c5-427188780b9a','次韻李倅安上喜雪','葛勝仲','宋','宋诗','song-poetry','','[]','兔苑佳賓集，龍山上瑞臻。',144,'全唐诗/poet.song.78000.json','["兔苑佳賓集，龍山上瑞臻。", "微飄方自弄，亂洒忽無垠。", "剪水層空墮，装春病枿新。", "繽翻投隙巧，歷亂點衣勻。", "急每隨風陣，高将擁日輪。", "階閒鋪六出，簷重壓千鈞。", "片落梅初謝，毬飄柳未顰。", "賞清疑不夜，驚晚誤司晨。", "朔漠寒沙起，湘吳美酎陳。", "地荒包委瑣，木朽蓋輪囷。", "舴艋尋幽客，蝸牛卧冷人。", "稍晴芳意動，散策共尋春。"]'),
('db3107a2-d09d-4ff7-8ecb-4a1f76b3c91d','再和','葛勝仲','宋','宋诗','song-poetry','','[]','皚皚盈尺瑞，及此臘前臻。',144,'全唐诗/poet.song.78000.json','["皚皚盈尺瑞，及此臘前臻。", "滉漾連三暮，縈盈遍九垠。", "青腰陰巧露，白帝羽儀新。", "坤軸埋藏厚，天潢瀉落勻。", "瑶林變園榭，縞带逐車輪。", "膏潤歸農畝，雕裁自化鈞。", "吟寒詩膽健，装冷嫵眉顰。", "點袖朝正日，侵鞾立仗晨。", "境同秋月淨，句鄙散鹽陳。", "白玉藏千室，黄雲卜萬囷。", "江臯迷宓女，姑射想神人。", "早晚晴光動，郊原探早春。"]'),
('5a78ccba-943a-4e9e-a884-24ab8ed3aee5','十二月初四日遊吳山院','葛勝仲','宋','宋诗','song-poetry','','[]','穩坐踰年矣，渾消髀肉頑。',120,'全唐诗/poet.song.78000.json','["穩坐踰年矣，渾消髀肉頑。", "兩兒挾籃轝，十里訪吳山。", "佛老聊施佞，官曹未畏瘝。", "煙林穿窈窈，巖溜揭潺潺。", "樓觀修篁外，招提翠麓間。", "嶝危愁憊力，潭凈怯衰顔。", "身縛何因脱，心紛得暫刪。", "歲窮嗟俛仰，境勝彊躋攀。", "臘出因休吏，晡歸及閉關。", "相将投此幘，永伴黑衣閒。"]'),
('d45cba6f-b3c2-4b48-ab79-f32bd8256d9e','走筆追記十二月九日潭頭之遊','葛勝仲','宋','宋诗','song-poetry','','[]','三益得豈易，一遊營亦難。',168,'全唐诗/poet.song.78000.json','["三益得豈易，一遊營亦難。", "地偏如避俗，春早自排寒。", "霖潦逢初霽，年華念欲单。", "搘笻卜遐眺，挈榼展清歡。", "茶塢千家密，梅林十里寬。", "幽尋窮窈窕，危陟遍巑岏。", "有地堪肥遁，幽人卜考槃。", "後前羅峻嶺，左右繞驚瀾。", "西望雙藤老，南瞻巨石盤。", "千章叢古木，九畹秀崇蘭。", "手板看蒼翠，軍持上激湍。", "醉鄉因蟻酎，水厄爲龍團。", "晚景雲低樹，歸途雨壓冠。", "明驚烽火逼，小艇起前灘。"]'),
('c4fc074b-a554-4340-a39d-b33b1e7947ef','十二月二十三日立春中散兄棣華第六會特盛是日天大雪小孫女出綵旛勝及花柳精巧夜漏且五鼓方罷既歸不得寐偶成律詩紀事拜呈中散兄兼簡公任阜民詳定侍郎道祖簽幕判院朝提轄奉議卿任寶錄待制','葛勝仲','宋','宋诗','song-poetry','','[]','異縣逢春啟，羈懷百不堪。',144,'全唐诗/poet.song.78000.json','["異縣逢春啟，羈懷百不堪。", "頻傾次道釀，聊喜阿雲談。", "棣蕚仍清集，辛盤助半酣。", "綵旛驚節物，玉屑瑞田蠶。", "太簇律初應，德星堂不慚。", "共誇筵秩秩，那羡府潭潭。", "濟美三公後，逃禅二老參。", "清歡時擇勝，冲操自廉貪。", "丹荔來閩部，黄魚出嶠南。", "雲泉烹賜茗，羅帕薦珍柑。", "經醉香浮座，言歸鍾動菴。", "蕭然文字飲，共賦鹿鳴三。"]'),
('d2ddc649-15e6-4f61-9138-163cf9ae4827','六月六日大暑市中無肉庖厨索然作六言三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','翠竹碧梧入望，紫茄白莧供槃。',28,'全唐诗/poet.song.78000.json','["翠竹碧梧入望，紫茄白莧供槃。", "未辦楚王雞跖，難求閔叔豬肝。"]'),
('07fae3df-39c2-40a5-8760-f122ef04cb7b','六月六日大暑市中無肉庖厨索然作六言三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','常饌素諳苜蓿，忍饑何必檳榔。',28,'全唐诗/poet.song.78000.json','["常饌素諳苜蓿，忍饑何必檳榔。", "自歎麞頭鼠目，難辭蝉腹龜膓。"]'),
('0c5b726d-1af8-4af9-aa5e-aaa085ba851b','六月六日大暑市中無肉庖厨索然作六言三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','三白舊甘蔬食，八關聊復齋支。',28,'全唐诗/poet.song.78000.json','["三白舊甘蔬食，八關聊復齋支。", "蟻酒似聞将熟，蟹螯應得重持。"]'),
('060f3a9b-bd3b-44ae-ad15-95b80154ef55','再和三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','晨飱僅有醢豆，夜飲應無燭槃。',28,'全唐诗/poet.song.78000.json','["晨飱僅有醢豆，夜飲應無燭槃。", "屬饜何取雞肋，委順甘爲鼠肝。"]'),
('b7fd7693-79be-4948-b96f-c64eab238974','再和三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','野步自鋤蘆菔，輕塵試煮桄榔。',28,'全唐诗/poet.song.78000.json','["野步自鋤蘆菔，輕塵試煮桄榔。", "坐喜青芻入眼，不須紫笋捜膓。"]'),
('b8487f97-16dd-44cc-8e84-9ff95b688ba8','再和三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','腊毒雖無後悔，轉雷已覺難支。',28,'全唐诗/poet.song.78000.json','["腊毒雖無後悔，轉雷已覺難支。", "異饌那施方文，寒泉且飲軍持。"]'),
('b8c367dc-9ed5-4c6c-bb44-23e5fc2fafd2','二陳作書懷詩亦次韻','葛勝仲','宋','宋诗','song-poetry','','[]','山城真稱著寒儒，遶屋青蒼似故居。',64,'全唐诗/poet.song.78000.json','["山城真稱著寒儒，遶屋青蒼似故居。", "吏牘糾紛慚磔鼠，齋厨蕭索待泔魚。", "懶如園令将移病，窮似虞卿合著書。", "賴是豐年民氣樂，夢回時見旐維旟。"]'),
('bbb1d4d1-70c9-4cd6-a751-e795e9de867a','圄空訟息復遇肆眚庭事蕭然蒙良器解元寵詩輙以二章爲謝  其一','葛勝仲','宋','宋诗','song-poetry','','[]','一官銅墨付疏頑，歲好人和偶未瘝。',64,'全唐诗/poet.song.78000.json','["一官銅墨付疏頑，歲好人和偶未瘝。", "東畝黄雲穈芑卧，北扉青草纆徽閒。", "鵠亭夜覺冤氛靜，蠅筆晨驚霈澤頒。", "倪耄歡謡歸帝力，風人溢美但赬顔。"]'),
('1d0db363-2cbd-4fa9-ad16-c593f981d701','圄空訟息復遇肆眚庭事蕭然蒙良器解元寵詩輙以二章爲謝  其二','葛勝仲','宋','宋诗','song-poetry','','[]','編户相安易得情，年來狴犴毎刑清。',64,'全唐诗/poet.song.78000.json','["編户相安易得情，年來狴犴毎刑清。", "庭閒不復施梧象，俗朴聊同示草纓。", "牘背僅能平枉橈，需頭那復覬褒榮。", "人言官事無由了，暫得居官事了名。"]'),
('80982e7b-4974-42cd-a617-39d5f41f0df2','次德林新亭詩韻','葛勝仲','宋','宋诗','song-poetry','','[]','缿訟無多得暫閒，結亭聊就碧鮮間。',64,'全唐诗/poet.song.78000.json','["缿訟無多得暫閒，結亭聊就碧鮮間。", "胡床寄目中宵月，手板支頤四面山。", "楂带水禽流淺瀨，帆隨煙艇轉前灣。", "登臨似與塵寰隔，况復朋從接笋班。"]'),
('b0fa6854-0e4d-47bc-9603-fafaaf91b7b2','次韻子充九日建天寜道場罷遂遊堯祠','葛勝仲','宋','宋诗','song-poetry','','[]','悒悒無聊坐學宫，銜杯阻共玉西東。',64,'全唐诗/poet.song.78000.json','["悒悒無聊坐學宫，銜杯阻共玉西東。", "祝延精舍臣心重，擇勝叢祠友好隆。", "休嘆青衫淹小縣，且從烏帽落商風。", "喜君句法無餻字，始信才華夢得同。"]'),
('f5c276f7-3760-4070-a16c-c8ca60e18e49','次韻德升遊堯廟','葛勝仲','宋','宋诗','song-poetry','','[]','頽垣老屋寄荒村，八彩修眉儼若存。',64,'全唐诗/poet.song.78000.json','["頽垣老屋寄荒村，八彩修眉儼若存。", "古砌荒凉無歷草，奠觴牢落想衢樽。", "雲山遶郭清如活，烟艇摇波渺欲翻。", "循牒歸來同勝賞，免煩諸友爲招魂。"]'),
('6dec895d-ea85-424f-b4b3-4158259f812c','九日汝明留郡中不遂同遊以詩見寄次韻','葛勝仲','宋','宋诗','song-poetry','','[]','三年卜築慕幽人，九日無歡愧病身。',64,'全唐诗/poet.song.78000.json','["三年卜築慕幽人，九日無歡愧病身。", "始謂窺臨陪勝友，那知岑寂度蕭辰。", "醪敷卷白欣初熟，菊蘂舒黄正斬新。", "聞道小蠻新教舞，歸時呼客莫辭頻。"]'),
('736f452a-817a-4a08-aa14-faeec8c7601e','題觀音院','葛勝仲','宋','宋诗','song-poetry','','[]','弱水無風到海山，慈容親覲紫旃檀。',64,'全唐诗/poet.song.78000.json','["弱水無風到海山，慈容親覲紫旃檀。", "亭亭寶刹凌雲近，湛湛清池潄玉寒。", "橘熟獨垂紅萬顆，竹迷曾蒔碧千竿。", "熱官步武何容到，散秩須知第一官。"]'),
('dbb0ebff-e3e1-4003-a957-b631436de436','諸生絕糧偶作二首示勉夫  其一','葛勝仲','宋','宋诗','song-poetry','','[]','庖厨落寞不堪聞，弹鋏無魚甑有塵。',64,'全唐诗/poet.song.78000.json','["庖厨落寞不堪聞，弹鋏無魚甑有塵。", "誰識簞瓢顔氏樂，可憐鮭菜庾郎貧。", "固窮始合稱君子，臨難聊須語細人。", "曳褷長歌商頌在，未應懟憾去來頻。"]'),
('437c854d-d2ca-4e09-9202-3f0cd98a1d77','諸生絕糧偶作二首示勉夫  其二','葛勝仲','宋','宋诗','song-poetry','','[]','饑腸愁坐耳無聞，放飯先疑甑拾塵。',64,'全唐诗/poet.song.78000.json','["饑腸愁坐耳無聞，放飯先疑甑拾塵。", "聞說食功非食志，政宜憂道不憂貧。", "佐饔但有思嘗者，執爨初無欲凊人。", "好向計臺勤自列，文移見卻已頻頻。"]'),
('55502806-9e80-41c9-b7bd-f4578fa5a03f','次韻劉卿任阜民對假菊花嘗新酒','葛勝仲','宋','宋诗','song-poetry','','[]','隆冬急雪舞淄澠，那得鮮鮮細菊呈。',64,'全唐诗/poet.song.78000.json','["隆冬急雪舞淄澠，那得鮮鮮細菊呈。", "何處幻師來衒巧，此花詞客最鍾情。", "盈尊更值醪敷熱，下筯仍欣鱠縷頳。", "應笑蓬蒿張仲蔚，忍寒獨坐到黎明。"]'),
('909a1413-6eef-41b5-8348-33025f59ba39','次韻德升見懷','葛勝仲','宋','宋诗','song-poetry','','[]','米廪無喧似結廬，一簷寒竹伴幽虚。',64,'全唐诗/poet.song.78000.json','["米廪無喧似結廬，一簷寒竹伴幽虚。", "閒開桑落傾浮蟻，凈展芸籤拂蠹魚。", "頻枉詩筒從我讀，已留齋壁待君書。", "二千石子人中爽，風月高情更起予。"]'),
('b45602c3-db18-4239-b619-857db07891b0','次韻德升再講酬唱','葛勝仲','宋','宋诗','song-poetry','','[]','蓮社追攀毎愧心，詩盟此假偶重尋。',64,'全唐诗/poet.song.78000.json','["蓮社追攀毎愧心，詩盟此假偶重尋。", "孤高舊壓元和體，清警新聞正始音。", "龜洛賦成應奪錦，雞林價重定酬金。", "自憐潦倒無佳製，東望家山但越吟。"]'),
('e1bdaf23-1438-4b44-b89d-2c25e72a99b3','次韻蔡安度秀才賦鹽','葛勝仲','宋','宋诗','song-poetry','','[]','法更鹽筴利源開，瀕海熬波亹亹來。',64,'全唐诗/poet.song.78000.json','["法更鹽筴利源開，瀕海熬波亹亹來。", "貢篚燒羊謾南北，嘉籩形虎間榛梅。", "鍜圭搥璧嚴疆域，積雪飛霜阜貨財。", "滋味佐饔周九土，柳星端合祀壇垓。"]'),
('7a2dc060-2c3d-4453-90f4-d1cd0f70433f','青州試院次監門韻四首呈同事李無咎補之簽判王柏立之劉及至父二宰鄭與權存道司户李致志道縣丞  其一','葛勝仲','宋','宋诗','song-poetry','','[]','朱顔幕府美如英，庇邑優閑閉訟庭。',64,'全唐诗/poet.song.78000.json','["朱顔幕府美如英，庇邑優閑閉訟庭。", "語掾氣剛工論事，講郎材拙只横經。", "相從此地初披霧，却望遥天想聚星。", "速發試題乘不備，母令掩耳及驚霆。"]'),
('a66371a1-a17d-45ea-9ade-013645fb7bf0','青州試院次監門韻四首呈同事李無咎補之簽判王柏立之劉及至父二宰鄭與權存道司户李致志道縣丞  其二','葛勝仲','宋','宋诗','song-poetry','','[]','東秦人士富豪英，鄉老賓賢上帝庭。',64,'全唐诗/poet.song.78000.json','["東秦人士富豪英，鄉老賓賢上帝庭。", "玉笋未知誰得地，金籯聞說賸通經。", "雄夸氣各千雲漢，妙製文多煥斗星。", "水鏡諸公標鍳在，大聲從此起非霆。"]'),
('6e48ce64-4370-49f4-9375-e211c6b52efe','青州試院次監門韻四首呈同事李無咎補之簽判王柏立之劉及至父二宰鄭與權存道司户李致志道縣丞  其三','葛勝仲','宋','宋诗','song-poetry','','[]','樽酒重陽泛菊英，此時應得到家庭。',64,'全唐诗/poet.song.78000.json','["樽酒重陽泛菊英，此時應得到家庭。", "奔趨試席雖深貫，囚鏁文闈苦未經。", "夢入故園時栩栩，愁侵衰鬢欲星星。", "評文賴有金閨彦，敏手從來號震霆。"]'),
('82850748-02de-4593-8867-99149041dfc8','青州試院次監門韻四首呈同事李無咎補之簽判王柏立之劉及至父二宰鄭與權存道司户李致志道縣丞  其四','葛勝仲','宋','宋诗','song-poetry','','[]','前山雲物望英英，拘窘無從出户庭。',64,'全唐诗/poet.song.78000.json','["前山雲物望英英，拘窘無從出户庭。", "蓋衆未知除患術，居閒聊喜衛生經。", "客塗淫滯将彌月，王事勤勞毎戴星。", "已恨歸期誤占鵲，阿香何苦更飛霆。"]'),
('285453c0-af3c-423a-9824-424be6767d1f','再次韻四首呈至父  其一','葛勝仲','宋','宋诗','song-poetry','','[]','茂宰才名莫與京，久宜遷擢潤朝廷。',64,'全唐诗/poet.song.78000.json','["茂宰才名莫與京，久宜遷擢潤朝廷。", "儒林傳記夸三篋，聖域淹通貫十經。", "豪縣暫頒天子詔，清資已應議郎星。", "危言峻節他年事，肯向威顔懾震霆。"]'),
('4041be0a-6b74-4c85-82b4-08a0b3d91e94','再次韻四首呈至父  其二','葛勝仲','宋','宋诗','song-poetry','','[]','棘繞重門晝亦扄，白袍摇筆坐中庭。',64,'全唐诗/poet.song.78000.json','["棘繞重門晝亦扄，白袍摇筆坐中庭。", "摛詞緜密多根道，論事軒昂各傳經。", "學博素推通德里，名高先動進賢星。", "知誰吉夢如揚輦，一石龍駒落大霆。"]'),
('64f49248-e037-47c9-9b4e-252ef02fbd4e','再次韻四首呈至父  其三','葛勝仲','宋','宋诗','song-poetry','','[]','文卷縱横未易名，欲捜佳筆送王庭。',64,'全唐诗/poet.song.78000.json','["文卷縱横未易名，欲捜佳筆送王庭。", "去留彼我心無著，工拙錙銖眼盡經。", "老信虚名真畫餅，忙知急景甚飛星。", "自憐考閲專精甚，不覺猝然柱破霆。"]'),
('1cbe9fe8-93e9-416a-914f-8e549aac5505','再次韻四首呈至父  其四','葛勝仲','宋','宋诗','song-poetry','','[]','披卷疲勞亦暫停，相攜款睇聚閒庭。',64,'全唐诗/poet.song.78000.json','["披卷疲勞亦暫停，相攜款睇聚閒庭。", "繪圖細閲吳生品，茗盌分評陸子經。", "牓帖未應憑主第，文窮端已送奴星。", "毬場縶鎻驚踰月，可信流光甚疾霆。"]'),
('692888c2-7018-4bd0-88a7-4acf845db7f8','出院有期呈同院二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','門前輿馬已紛紛，猶爾癡迷校藝文。',64,'全唐诗/poet.song.78000.json','["門前輿馬已紛紛，猶爾癡迷校藝文。", "山色未容飛蓋賞，市聲時得隔牆聞。", "裴頭黄尾皆前定，王後盧前謾自分。", "頗憶安居卧齋榻，淨看香霧起微焚。"]'),
('cda550a4-d51a-4495-b728-7b653e44c2d8','出院有期呈同院二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','旅懷牢落倦文瑒，憲網拘攣出處妨。',64,'全唐诗/poet.song.78000.json','["旅懷牢落倦文瑒，憲網拘攣出處妨。", "眼力半消嫌夜燭，腰圍頓減怯秋霜。", "到家會是揚三喜，取第誰同郭八郎。", "趣駕莫孤餻酒會，東籬菊蘂已金黄。"]'),
('a54da6bf-1450-49a1-ac62-370d2c4a5dc9','次韻祝守康鹿鳴宴贈諸先輩  其一','葛勝仲','宋','宋诗','song-poetry','','[]','清香畫戟，戟燕儒流，場籍英材喜博收。',66,'全唐诗/poet.song.78000.json','["清香畫戟，戟燕儒流，場籍英材喜博收。", "奮袖談辭爭落落，摳衣矩步更秋秋。", "新篇奨激華如衮，公議歸懷綴若旒。", "蘂榜登榮即從政，定知果藝過由求。"]'),
('f0d52d3b-dce5-4890-92c5-58cddc707c01','次韻祝守康鹿鳴宴贈諸先輩  其二','葛勝仲','宋','宋诗','song-poetry','','[]','觀光六十富豪英，賓送春闈屬鉅卿。',64,'全唐诗/poet.song.78000.json','["觀光六十富豪英，賓送春闈屬鉅卿。", "樂采舊知多藻茆，燕敖今喜食蒿苹。", "糊名選藝無私見，置醴優賢有頌聲。", "成就旋歸充貢職，魯人歆艷始知榮。"]'),
('59cedce6-1c89-4f2d-a5d6-94f85d76756f','次韻祝邦直題飲鳯泉','葛勝仲','宋','宋诗','song-poetry','','[]','萬里溪源出小池，喬林修竹映清輝。',64,'全唐诗/poet.song.78000.json','["萬里溪源出小池，喬林修竹映清輝。", "遷鸎榜內偏留落，飲鳯泉邊習遁肥。", "遊覧忽紆都騎貴，稱夸更得綵毫揮。", "故山水石那優此，肯爲低腰便賦歸。"]'),
('02a64b76-7f90-4212-9aac-11203322ced4','示友卿','葛勝仲','宋','宋诗','song-poetry','','[]','飛藿蕭蕭晚自零，來時灌木始欣榮。',64,'全唐诗/poet.song.78000.json','["飛藿蕭蕭晚自零，來時灌木始欣榮。", "毎因勸學添文思，却爲回文動旅情。", "好逐諸儒勤釋菜，莫憂貧嫂便轑羮。", "似聞闞澤中宵夢，月裏分明有姓名。"]'),
('944fc794-9491-47a0-9d78-f36275b2248f','次韻若拙碧線泉','葛勝仲','宋','宋诗','song-poetry','','[]','掉繚穿橋一線過，濟南金色漫浮波。',64,'全唐诗/poet.song.78000.json','["掉繚穿橋一線過，濟南金色漫浮波。", "共疑園客春投繭，直恐針神夜過河。", "貫脱已遺交甫珮，縷飛如擲幼輿梭。", "晚風披拂俄中斷，拆韈雖長苦不多。"]'),
('9407edf2-5f9b-4a82-9712-e1b38cf6800c','諸生詣府見留再任偶作示勉夫二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','魯堂詩禮號多儒，文席非才誤詔除。',64,'全唐诗/poet.song.78000.json','["魯堂詩禮號多儒，文席非才誤詔除。", "賢路久妨顔已厚，儒宫相借計誠疏。", "化鵾未敢圖飛翼，搏虎誰能復下車。", "詣府自言無以稱，空銜諸彦意勤渠。"]'),
('66dfd312-9720-44f7-b432-2954ab8bc955','諸生詣府見留再任偶作示勉夫二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','安閒喜得伴林居，分教無功恨有餘。',64,'全唐诗/poet.song.78000.json','["安閒喜得伴林居，分教無功恨有餘。", "閔貢政爲投劾計，何蕃空上乞留書。", "論文毎愧瑕疵汝，廷譽何煩俎豆予。", "誰識白雲千里念，終更計日望吾廬。"]'),
('2c5e74dd-c557-4aac-9ab2-c279e81ea1ca','将至襄陵二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','西風寥栗不須悲，雲日輕明政自奇。',64,'全唐诗/poet.song.78000.json','["西風寥栗不須悲，雲日輕明政自奇。", "遠岸綠飄梧槭槭，疏林紅露棗離離。", "味廽新醑愁眉破，凉入單紈病骨知。", "試問夜窗燈火讀，何知蚊蚋撲緣時。"]'),
('2f3fa201-df57-4bbf-9de6-5b1a53fa0f98','将至襄陵二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','千里崑崙一月風，乘流初不恨途窮。',64,'全唐诗/poet.song.78000.json','["千里崑崙一月風，乘流初不恨途窮。", "南陔就養晨昏樂，東榻忘懷笑語同。", "牛酒故應推汴上，鱸蓴那復念吳中。", "明朝繫纜襄陵驛，試上高原望鬰蔥。"]'),
('e02fc0a2-9738-4b17-a03f-e473b889bbf3','君山飯僧薦考妣元述示詩次其韻','葛勝仲','宋','宋诗','song-poetry','','[]','負郭簷楹古道場，山形連接楚人黄。',64,'全唐诗/poet.song.78000.json','["負郭簷楹古道場，山形連接楚人黄。", "千尋寶刹留幡影，萬里滄波對練光。", "問膳香蘭無復日，霑襟青血自成行。", "才收英器還遵路，三昧高僧笑我忙。"]'),
('070d8692-1a7c-43f7-abc8-e07b0409046e','次韻敦仁教授述懷','葛勝仲','宋','宋诗','song-poetry','','[]','十載文華蓋衆英，州庠微禄代躬耕。',64,'全唐诗/poet.song.78000.json','["十載文華蓋衆英，州庠微禄代躬耕。", "半生甘爲方穿礙，此假那因曲木驚。", "折角談經於道勝，低簪下匕以身輕。", "兩朝大典資編削，莫向西風厭宦情。"]'),
('3c7345bb-4698-4153-a0c3-879cd41be3f7','近蒙夏蒙夫教授用贈太守韻見貽輙復和答','葛勝仲','宋','宋诗','song-poetry','','[]','百家六藝日披吟，問學淵源已造深。',64,'全唐诗/poet.song.78000.json','["百家六藝日披吟，問學淵源已造深。", "舊直蓬山無俗夢，今官槐市有清陰。", "公餘綠綺乘閒撫，客退黄庭毎自臨。", "官冷定知塵滿甑，誰人裹飯慰愁霖。"]'),
('b9f80ef5-c971-4994-930d-0e9f5f35cc7a','伏蒙達之學諭以詩寵眷生日次韻酬謝','葛勝仲','宋','宋诗','song-poetry','','[]','窮通誰復問東龜，材命由來略可推。',64,'全唐诗/poet.song.78000.json','["窮通誰復問東龜，材命由來略可推。", "去惡敢言除畝薤，律貪聊慕拔園葵。", "百年永悼懸弧日，一顧垂當解印時。", "詩句清新褒借甚，却嫌無當玉爲巵。"]'),
('6070a768-e4b8-4c63-8bd8-18abb1fdb7d3','段去塵教授示書以茶菊自况作詩謝之','葛勝仲','宋','宋诗','song-poetry','','[]','高標落落敢評題，託物銓量庶似之。',64,'全唐诗/poet.song.78000.json','["高標落落敢評題，託物銓量庶似之。", "娯客精神真北苑，可人風味劇東籬。", "雲腴鬭早驚先出，霜蘂禁寒屬後期。", "便欲相稱爲二陸，居然桑苧與天隨。"]'),
('775b0c82-6b37-421b-b9ff-78db114c9335','旬休延聖院納凉周澶州招飲呈德升詩二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','年來形迹苦西東，邂逅招提一笑同。',64,'全唐诗/poet.song.78000.json','["年來形迹苦西東，邂逅招提一笑同。", "世事休論癡黠半，物情都在聖賢中。", "地靈蒸鬰疑無著，友勝喧囂自不通。", "借與方床寬六尺，道人知有竹間風。"]'),
('4a1c9052-0e07-401f-9bbc-73b406ebe64e','旬休延聖院納凉周澶州招飲呈德升詩二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','講席朝來得暫停，藍輿同入法王城。',64,'全唐诗/poet.song.78000.json','["講席朝來得暫停，藍輿同入法王城。", "清壺照座三棱瑩，小扇摇風六角輕。", "方罫共爭棋上劫，頑盆更酌酒中兵。", "佳賓更賴王思遠，霜氣能令暑氣清。"]'),
('7b720186-46f9-4f5a-a464-cf677f7fa0c2','元巳日王循德招飲方池宏道兄有詩奉和以紀一時之事','葛勝仲','宋','宋诗','song-poetry','','[]','浮爽清波正日遲，出郊修禊屬芳時。',64,'全唐诗/poet.song.78000.json','["浮爽清波正日遲，出郊修禊屬芳時。", "幸陪飛觀朋簪盍，未覩華堂舞袖僛。", "命中已于三耦見，爭雄仍向一枰知。", "愛君多藝能傾坐，豈但流觴記逸詩。"]'),
('a3d7d248-a04c-489c-a308-73c6d76e0324','伯兄以家園亭名書壁間因作','葛勝仲','宋','宋诗','song-poetry','','[]','壁間亭榜記家林，獨住雲泉宿昔心。',64,'全唐诗/poet.song.78000.json','["壁間亭榜記家林，獨住雲泉宿昔心。", "千里故園應好在，十年羈宦阻登臨。", "鍾儀長自操南語，荘舄何曾忘越吟。", "松菊未荒歸有約，不知富貴定誰淫。"]'),
('9785c64c-4d81-4ecd-85a7-94892d8f4785','伯父致政通直取謝靈運詩句作蕭散堂賦詩次和寄二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','神武門高早掛冠，首嗟榮路久淹蟠。',64,'全唐诗/poet.song.78000.json','["神武門高早掛冠，首嗟榮路久淹蟠。", "詩辭故故推靈運，禅語時時對道安。", "書字不誇雲五朵，卧閒偏怯日三竿。", "遐齡清德全真樂，誰識榮期善自寬。"]'),
('8b92f0d3-4a76-4228-bdf9-929f40bc7be6','伯父致政通直取謝靈運詩句作蕭散堂賦詩次和寄二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','青雲誰羡猛飛翰，解組歸來分屈蟠。',64,'全唐诗/poet.song.78000.json','["青雲誰羡猛飛翰，解組歸來分屈蟠。", "唯以道腴從已味，肯将心法逐人安。", "林迷曉嶂雲千疊，舟漾春塘水半竿。", "退隱州閭名愈重，坐令鄙薄化敦寬。"]'),
('0bebc3e5-d06b-4996-9428-6aaaee93c266','賀十八叔父及嬸氏受恩封','葛勝仲','宋','宋诗','song-poetry','','[]','聖渥便蕃奨義方，靈椿雙壽慶華堂。',64,'全唐诗/poet.song.78000.json','["聖渥便蕃奨義方，靈椿雙壽慶華堂。", "品開京秩紆藍綬，告錫脂田閟錦囊。", "家世百年逢盛事，庭闈一日拜恩光。", "列封更及諸郎貴，禄釡交迎福熾昌。"]'),
('7c225400-1016-4cd1-8aa6-a0cd9ba405d3','和堯卿兄喜孝卿兄登科','葛勝仲','宋','宋诗','song-poetry','','[]','興賢賜第集英春，勸學應從孟母鄰。',64,'全唐诗/poet.song.78000.json','["興賢賜第集英春，勸學應從孟母鄰。", "黄甲科名新赫奕，青雲岐路肯因循。", "暴鰓昔恨登龍晚，飲羽今驚中鵠親。", "雲陛開陳三道要，寜容舉首屬他人。"]'),
('36332af6-5394-49a8-acce-b8f54ca261b3','堯卿兄改官陞朝作詩紀賀三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','交親衮衮上青雲，冷局辛勤自奮身。',64,'全唐诗/poet.song.78000.json','["交親衮衮上青雲，冷局辛勤自奮身。", "玉陛臚傳瞻覲久，金閨通籍寵光新。", "功名此去未爲晚，富貴儻來那有因。", "預喜郊封榮禰廟，弟兄同列拜恩綸。"]'),
('16337947-f79a-4afd-8dcd-827fa0222e9b','堯卿兄改官陞朝作詩紀賀三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','冷不遷官似子雲，但知謀道不謀身。',64,'全唐诗/poet.song.78000.json','["冷不遷官似子雲，但知謀道不謀身。", "文高書局恩華舊，秩改朝班慶自新。", "此去功名應自致，從來力命固相因。", "榮塗萬里通無礙，峻陟行看奉帝綸。"]'),
('ad51f191-0d91-4302-b4e4-16b35599e6aa','堯卿兄改官陞朝作詩紀賀三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','引對天墀獲望雲，固知儒學不孤身。',64,'全唐诗/poet.song.78000.json','["引對天墀獲望雲，固知儒學不孤身。", "均輸它局交論薦，元會登朝正履新。", "夕秀共誇披未振，夜光那復困無因。", "持荷入侍從兹始，龜紫應卑五兩綸。"]'),
('790cc540-85d0-4a95-a366-dfce7c0c7b32','次韻堯卿兄詩酒中興三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','可惜虚行淮汴路，不憂無繼是巴牋。',64,'全唐诗/poet.song.78000.json','["可惜虚行淮汴路，不憂無繼是巴牋。", "任貧任病須歡伯，更拙更慵猶短篇。", "好拉嘉賓傾若下，剩鈎華藻染由拳。", "離羣他日乖觴詠，馬腹何因更及鞭。"]'),
('cd896d9c-26f7-4431-a72d-3c22c1997c20','次韻堯卿兄詩酒中興三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','舟行詩酒兩相牽，豈暇觀書理廢牋。',64,'全唐诗/poet.song.78000.json','["舟行詩酒兩相牽，豈暇觀書理廢牋。", "金榼興闌多半醉，錦囊才亂罕終篇。", "吟哦有味增閒適，酩酊忘形謝曲拳。", "年大此鄉疑可老，宦塗羞鬻賈人鞭。"]'),
('1fea475d-b5b8-47c1-8d42-b044c14ab7b6','次韻堯卿兄詩酒中興三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','耻向權門事鞾板，懶於驛路奏書牋。',64,'全唐诗/poet.song.78000.json','["耻向權門事鞾板，懶於驛路奏書牋。", "芳醪不厭三千醆，嘉頌時爲十二篇。", "吟裏情懷清似洗，醉中身世小如拳。", "伯倫子美真豪逸，風味平生願執鞭。"]'),
('1367449b-22ce-444b-97cd-d8ac401bfe36','弈棋有進勸工部兄召客','葛勝仲','宋','宋诗','song-poetry','','[]','索居湖海欲忘憂，瓜葛相呼事弈秋。',64,'全唐诗/poet.song.78000.json','["索居湖海欲忘憂，瓜葛相呼事弈秋。", "方罫互贏多有進，圓盆更酌早爲謀。", "格高誰是州中正，米賤休沽縣督郵。", "及取春光尚堪賞，莫辭醉倒更扶頭。"]'),
('9f407ae7-8e8b-4a8f-8f88-d77db9a4bc82','次韻韓景賢承議自金陵沿檄宣歙道中見貽二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','循牒騰装冐苦寒，傷離愁思定應寬。',64,'全唐诗/poet.song.78000.json','["循牒騰装冐苦寒，傷離愁思定應寬。", "剸煩獄市才稱健，奔命郵亭歲欲闌。", "赤米素鹽厨寂寂，清泉白石路漫漫。", "到家尺一應催召，聞說知音正執桓。"]'),
('1d0405bc-5551-4671-b8d1-b90bedd9c932','次韻韓景賢承議自金陵沿檄宣歙道中見貽二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','摇毫傾刻便成章，弱冠名標桂籍香。',64,'全唐诗/poet.song.78000.json','["摇毫傾刻便成章，弱冠名標桂籍香。", "倉氏官閒聊自喜，荆州望重豈能方。", "高談不辨連三日，敏識空驚下五行。", "留落更煩勤慰諭，誰知寵辱漸能忘。"]'),
('a13fe841-fedf-4217-8cb9-5204df4f3555','五月望日會食普滿院夜歸作詩二首呈文中縣丞玉老禅師江斆王彧  其一','葛勝仲','宋','宋诗','song-poetry','','[]','懷冰高韻暑天寒，况有波瀾在筆端。',64,'全唐诗/poet.song.78000.json','["懷冰高韻暑天寒，况有波瀾在筆端。", "可但風流稱不墜，故應哺啜亦堪觀。", "坐曹行赴陳蕃榻，待戍方弹貢禹冠。", "戒食毎煩臨蔔瓠，慚無斗酒鹿盈柈。"]'),
('6842b107-f632-49fa-a367-17a71d83f711','五月望日會食普滿院夜歸作詩二首呈文中縣丞玉老禅師江斆王彧  其二','葛勝仲','宋','宋诗','song-poetry','','[]','簿書填委我何堪，茶串攜尋井水甘。',64,'全唐诗/poet.song.78000.json','["簿書填委我何堪，茶串攜尋井水甘。", "幻境豈能喻十十，禅機聊喜契三三。", "竹風敲玉清音迥，荷雨跳珠綠影涵。", "檀施敢夸蒲塞饌，欲因盧至戒慳貪。"]'),
('4589fe64-a6ab-4aa9-a40e-ed79c17f7e5a','二十四日葉氏林亭燕集成句呈文中縣丞','葛勝仲','宋','宋诗','song-poetry','','[]','執熱何從避火雲，山居岑寂背城闉。',64,'全唐诗/poet.song.78000.json','["執熱何從避火雲，山居岑寂背城闉。", "昂霄木老清陰厚，鍼水秧齊翠剡新。", "鮓熟慣醒虞匠酒，扇輕堪障庾公塵。", "凉飈拂袵容吾共，自意無懷以上人。"]'),
('64d23dba-ebbe-437a-b8d7-1a1509fb1764','葉佐卿見和復次韻答之','葛勝仲','宋','宋诗','song-poetry','','[]','扇上閒題隴首雲，揚風攜過海寜闉。',64,'全唐诗/poet.song.78000.json','["扇上閒題隴首雲，揚風攜過海寜闉。", "于飛鷺識觀光早，前列龜看入貢新。", "會見文辭驚乙覧，莫嫌衣袂點京塵。", "昇平樓下臚傳日，共指中朝第一人。"]'),
('1ace36bd-2d63-4a97-945a-7fdbc793d818','和少藴石林谷草堂三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','寵辱循環厭宦情，蓋頭茅屋手親營。',64,'全唐诗/poet.song.78000.json','["寵辱循環厭宦情，蓋頭茅屋手親營。", "清泉横道疑滋穴，翠袖圍居似化城。", "不擬身名炫俱泰，且圖心跡遂雙清。", "半庵閒地如容我，便足徜徉了一生。"]'),
('64c5466a-958b-4cf6-a730-0350a23df965','和少藴石林谷草堂三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','雲峰带竹似伊川，山溜甘于九隴泉。',64,'全唐诗/poet.song.78000.json','["雲峰带竹似伊川，山溜甘于九隴泉。", "離世未應多怨誹，葆真聊自樂虚緣。", "漫郎擬酌窪樽酒，逋客慚馳驛路烟。", "敢請著書詳勝致，千秋萬歲遣人傳。"]'),
('2df33ecb-4e35-44bf-af9b-54009eac36d8','和少藴石林谷草堂三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','妙年涉筆賦城蕪，歲晚無歌擊唾壺。',64,'全唐诗/poet.song.78000.json','["妙年涉筆賦城蕪，歲晚無歌擊唾壺。", "曾是北扉稱內相，却來東嶺伴寒儒。", "閒來真隱編成傳，靜取飛仙貌作圖。", "豪氣年來除已盡，元龍雅意卧江湖。"]'),
('8d343313-a85e-48e4-a201-8bcc76c97aae','呈去非','葛勝仲','宋','宋诗','song-poetry','','[]','嗣宗曠達早相逢，更喜林間識仲容。',64,'全唐诗/poet.song.78000.json','["嗣宗曠達早相逢，更喜林間識仲容。", "林蕚集中陪唱和，幽棲谷畔許過從。", "雲飛隴首高情遠，楓落吳江好句重。", "梁棟他年知有用，齋前楚楚一株松。"]'),
('b7176e1e-d025-4305-9ebf-40b66a6fab46','婺源祁門二令母年八十求爲保官注家便闕慨然慕之作詩二首自悼  其一','葛勝仲','宋','宋诗','song-poetry','','[]','庭闈無復薦芳羶，烏鳥哀情毎泫然。',64,'全唐诗/poet.song.78000.json','["庭闈無復薦芳羶，烏鳥哀情毎泫然。", "遊子但吟春草句，門人欲廢蓼莪篇。", "風枝數效臯魚泣，水菽難攀子路賢。", "空羡鄰封二佳令，兒啼八十壽親前。"]'),
('622629f0-fa48-40a7-97b9-203870f6ee4c','婺源祁門二令母年八十求爲保官注家便闕慨然慕之作詩二首自悼  其二','葛勝仲','宋','宋诗','song-poetry','','[]','迎養京都突未黔，蒼黄荼毒血霑襟。',64,'全唐诗/poet.song.78000.json','["迎養京都突未黔，蒼黄荼毒血霑襟。", "百年過隙知難復，三釡纒哀政自深。", "不爲鱸蓴歸亦好，獨甘羊棗果何心。", "寄言世上斑衣子，温清應須競寸陰。"]'),
('fd58b6ae-a2fc-4628-9aae-70c5587a5954','周文之運使巡按海寜追憶曩歲與伯仲同奉板輿之樂感慨賦詩不惟辭藻格力清蔚高邁且足以敦孝悌而厚風俗昔夏侯湛作詩示潘岳曰此文非徒温雅乃别見孝悌之性因次韻和二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','褰帷巖邑特從容，憶惜鴒原會一同。',64,'全唐诗/poet.song.78000.json','["褰帷巖邑特從容，憶惜鴒原會一同。", "樂孺共營蘭薦膳，劬勞爭報棘吹風。", "繡衣握節新恩重，綵服承顔往事空。", "三紀光陰真插羽，依然小市夕陽中。"]'),
('131b1647-ad89-4730-b07c-47357fea7fa7','周文之運使巡按海寜追憶曩歲與伯仲同奉板輿之樂感慨賦詩不惟辭藻格力清蔚高邁且足以敦孝悌而厚風俗昔夏侯湛作詩示潘岳曰此文非徒温雅乃别見孝悌之性因次韻和二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','披雲初獲接音容，賢勝風規自不同。',64,'全唐诗/poet.song.78000.json','["披雲初獲接音容，賢勝風規自不同。", "懔懍威明将使指，恂恂孝悌訓民風。", "競傳清唱紙騰貴，爭識皇華巷欲空。", "尚有壁間真墨彩，匣藏留在給園中。"]'),
('db17e04b-ab44-4f74-9d84-fda1305bf262','贈覺僧首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','道貌堂堂老不臞，照齋佚閣送居諸。',64,'全唐诗/poet.song.78000.json','["道貌堂堂老不臞，照齋佚閣送居諸。", "斷常不著安禅後，尋伺皆空入定餘。", "護戒獨持螺畫行，繙經時作鹿輪書。", "山城爲令真非惡，更喜遊從得浩初。"]'),
('b0975d8a-5638-486d-8102-32b5321e613f','贈覺僧首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','上堂慵算海邊沙，分衛寜甘向七家。',64,'全唐诗/poet.song.78000.json','["上堂慵算海邊沙，分衛寜甘向七家。", "篆筆頗疑傳棗木，方袍不羡賜蘭芽。", "名高白社推尊宿，才比紅樓更麗華。", "連枉清篇洗塵滓，緘藏留與里人誇。"]'),
('3edf7fa3-b6ea-4dd3-9755-5cb40dfe33ce','靜林寺','葛勝仲','宋','宋诗','song-poetry','','[]','妙行堂前聳碧鮮，壺中軒外疊巑岏。',64,'全唐诗/poet.song.78000.json','["妙行堂前聳碧鮮，壺中軒外疊巑岏。", "山門靜對清油闊，佛閣寬圍碧玉寒。", "蠟屐喜隨談理客，饋漿驚見字民官。", "開山老侃留遺像，試問何如釋道安。"]'),
('f6897ad1-a974-46d4-b4bd-317b44af4eea','次韻工部兄除夕見寄三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','異縣飄流十載窮，年華又見轉和風。',64,'全唐诗/poet.song.78000.json','["異縣飄流十載窮，年華又見轉和風。", "春遊已陡驚梅白，夜集猶疑共燭紅。", "藍尾方嗟形影隔，蒼頭俄喜信音通。", "麥秋時節摇歸掉，禅榻相從話苦空。"]'),
('aa9bbef4-ff2a-4633-bbf3-5359f912c309','次韻工部兄除夕見寄三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','霜毛垂領病摧頹，歲晚流年四秩催。',64,'全唐诗/poet.song.78000.json','["霜毛垂領病摧頹，歲晚流年四秩催。", "一自貶官瞻日遠，兩經除夕歎星回。", "梅吹畫角餘寒盡，柏欲飛觴暖律來。", "歲莫日斜還隱几，心同白傅守寒灰。"]'),
('3f474a68-b11b-4b65-bc85-8139c091c65e','次韻工部兄除夕見寄三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','江城流落歲還新，懶作雕蟲問大鈞。',64,'全唐诗/poet.song.78000.json','["江城流落歲還新，懶作雕蟲問大鈞。", "月盡嘉平餘景刻，年侵彊仕尚沉淪。", "晚持禅悦惟三白，曉簇春盤又五辛。", "肯把生涯供爛醉，黎明學不動心人。"]'),
('4ea8e4a3-1750-4f41-b554-7eda39185207','維心以詩送花果栽次韻','葛勝仲','宋','宋诗','song-poetry','','[]','奉乞花栽旋旋移，退師老圃自安時。',64,'全唐诗/poet.song.78000.json','["奉乞花栽旋旋移，退師老圃自安時。", "新荄應待天陽發，生意先從地脉知。", "異縣聊尋郭駞傳，他年敢忘角弓詩。", "庭柯只作怡顔具，肯比侯封逐利宜。"]'),
('b34f3a59-94b0-46e7-a05c-2e25e87b83f5','送胡彦師職方迎親赴闕二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','詞華標韻出鄒枚，要路飛翔見軼材。',64,'全唐诗/poet.song.78000.json','["詞華標韻出鄒枚，要路飛翔見軼材。", "編削終篇辭右府，袤延飛詔入中臺。", "碑刊棠蕚如敦實，衣曵荆蘭似老萊。", "五兩風輕清汳路，迎船魚笋助南陔。"]'),
('7954c7f1-01b0-43d6-8297-8bfccabd65cb','送胡彦師職方迎親赴闕二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','簪筆文昌作望郎，暫抛台史護衣香。',64,'全唐诗/poet.song.78000.json','["簪筆文昌作望郎，暫抛台史護衣香。", "摛辭曾是金聲奨，程奏親逢玉色康。", "禄洎千鍾榮滫瀡，圖分九服職封疆。", "到都右衮如相問，爲說飄流鬂已霜。"]'),
('6a92cbb2-e339-4901-8d4a-5cd8e56676ac','侍讀官程伯禹以賜茶寄汪敦仁教授蒙惠四胯以詩紀謝','葛勝仲','宋','宋诗','song-poetry','','[]','講罷清陰轉綠槐，露芽珍賜下銀臺。',64,'全唐诗/poet.song.78000.json','["講罷清陰轉綠槐，露芽珍賜下銀臺。", "品高逈壓仙人掌，味絕堪名瑞草魁。", "分貺雖從稽古出，看題知自邇英來。", "晴窗碾試供詩社，先聽聲轟萬壑雷。"]'),
('28e27ab1-7a52-41fd-87ab-fac113b0e94f','次韻宏道遊三官院園時余往辟廱不果往','葛勝仲','宋','宋诗','song-poetry','','[]','晚攜勝友共揚鑣，應厭家鬟捻紫簫。',64,'全唐诗/poet.song.78000.json','["晚攜勝友共揚鑣，應厭家鬟捻紫簫。", "逮得暇時能有幾，毎逢佳處且相邀。", "大夫高挹髯龍操，公子閒窺白鴈標。", "獨恨抗塵乖寄賞，偶飛輕蓋四門橋。"]'),
('51d41918-20a1-4366-9829-5d2352ebad28','詠槐','葛勝仲','宋','宋诗','song-poetry','','[]','蔽日干霄過百圍，龍蛇夭矯半天垂。',64,'全唐诗/poet.song.78000.json','["蔽日干霄過百圍，龍蛇夭矯半天垂。", "蟠根不老應千載，合抱横分見九枝。", "學市濃陰能幾許，公庭轉影不多時。", "那知山谷無斤斧，坐與冥靈結後期。"]'),
('90b495da-582e-4da8-ab66-770762749808','鄧子文辭曹枉道相過且出往還詩見示次韻二篇上呈  其一','葛勝仲','宋','宋诗','song-poetry','','[]','區區蘇李未應師，句法中涵屈宋姿。',64,'全唐诗/poet.song.78000.json','["區區蘇李未應師，句法中涵屈宋姿。", "華貫即今方慎柬，異材如此會深知。", "飄飄氣概輕餘子，凛凛規摹擴大兒。", "老厭交遊翻覆手，欲於士遜結心期。"]'),
('ef9f865d-9e55-4b69-b9d6-ae7066f33abf','鄧子文辭曹枉道相過且出往還詩見示次韻二篇上呈  其二','葛勝仲','宋','宋诗','song-poetry','','[]','獨學離羣政自傷，寵臨何幸不遺忘。',64,'全唐诗/poet.song.78000.json','["獨學離羣政自傷，寵臨何幸不遺忘。", "莫嗟黄繖稽掀擢，行看青冥指忽荒。", "好問徒知積雞跖，登塗曾不倦羊腸。", "衡州言語高天下，秀拔如君實肯堂。"]'),
('0abd20cc-1df6-4131-a9dc-945ff8440584','次韻正臣朝議見寄二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','解組歸來遯里門，慶源貽後繼臧孫。',64,'全唐诗/poet.song.78000.json','["解組歸來遯里門，慶源貽後繼臧孫。", "幽尋此日扶鳩杖，榮遇當年駕鹿轓。", "高義共夸賢者出，廉風端遣薄夫敦。", "紫壇熙事專優老，盼篚行看下九閽。"]'),
('fdef829a-ce7f-4140-b0b8-62547c8cd3ca','次韻正臣朝議見寄二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','儒學推稱第一流，乞言堪入告嘉猷。',64,'全唐诗/poet.song.78000.json','["儒學推稱第一流，乞言堪入告嘉猷。", "長閒氣味安三徑，難老光陰傲十洲。", "談理清風生玉麈，覆名殊寵謝金甌。", "方瞳大隱年兄弟，營道應居最上樓。"]'),
('aee9cbe3-26fa-4f36-b3dc-96f7bf48cef7','次韻答王聲見贈','葛勝仲','宋','宋诗','song-poetry','','[]','平生未分作臞仙，抵柲英豪不直錢。',64,'全唐诗/poet.song.78000.json','["平生未分作臞仙，抵柲英豪不直錢。", "效智連年居定鼎，策勲何日上凌煙。", "高情獨寄猗蘭操，壮志應存寶劍篇。", "途轍懸知騰上速，請看火色映鳶肩。"]'),
('76bdba2e-8d9a-42ff-bfa4-eaba09ef3a00','和目疾韻','葛勝仲','宋','宋诗','song-poetry','','[]','幻翳乘虗近漆瞳，輕雲蔽月有無中。',64,'全唐诗/poet.song.78000.json','["幻翳乘虗近漆瞳，輕雲蔽月有無中。", "廢書暫阻讎三豕，妨射何因落兩鴻。", "慧眼水清知吉夢，藥師經騐表奇功。", "疾平豈但開巖電，反照觀身覺內通。"]'),
('e563265c-9c85-4739-a83f-06cd2bd44fc5','幽居書懷六首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','材疏出仕久知難，境勝謀居自考槃。',64,'全唐诗/poet.song.78000.json','["材疏出仕久知難，境勝謀居自考槃。", "反抱關爲知道在，賴閒處著得身安。", "離騷毎向醉中讀，周易仍于病裏看。", "萬頃煙波時擊汰，浟浟籊籊弄晴竿。"]'),
('ab04828f-1c6d-4c7b-909c-62f5435b4573','幽居書懷六首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','環堵翛然一畝寬，更無塵霧苦相干。',64,'全唐诗/poet.song.78000.json','["環堵翛然一畝寬，更無塵霧苦相干。", "森森佳樹木奴實，湛湛清池地鏡寒。", "三益時瞻玉界尺，一杯何用肉臺盤。", "官閒坐享無功禄，更恐風人刺伐檀。"]'),
('fc2acb95-e5ba-4d32-9c24-d8d5a342d5a2','幽居書懷六首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','觀名計利了非真，何似江湖習隱淪。',64,'全唐诗/poet.song.78000.json','["觀名計利了非真，何似江湖習隱淪。", "户小但期茶當酒，家貧那有蠟充薪。", "五花自喜風翻簟，一角人看雨墊巾。", "上界神仙多護短，不辭長作葛天民。"]'),
('16646779-fb65-41a0-85f0-dae4e780c301','幽居書懷六首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','不識癰疽與瘠環，柴門雖設自常關。',64,'全唐诗/poet.song.78000.json','["不識癰疽與瘠環，柴門雖設自常關。", "木雞養就都無累，芻狗陳來分合閒。", "聊復讀書牛背上，誰能横槊馬蹄閒。", "子亭結築臨溪面，瓢飲新來待學顔。"]'),
('c859ccf8-227e-49e7-8c2b-3390d8316b98','幽居書懷六首  其五','葛勝仲','宋','宋诗','song-poetry','','[]','我貴從教知我希，靜觀物化養天機。',64,'全唐诗/poet.song.78000.json','["我貴從教知我希，靜觀物化養天機。", "名呼池面遊魚狎，縷繫梁間舊燕飛。", "安石困應存遠志，姜維那遽覓當歸。", "人生安樂他何卹，悵望鄉枌與願違。"]'),
('48119acf-3eb4-46bc-8f6d-19586da9019c','幽居書懷六首  其六','葛勝仲','宋','宋诗','song-poetry','','[]','清時鴛鷺正充庭，何事抽簪喜退耕。',64,'全唐诗/poet.song.78000.json','["清時鴛鷺正充庭，何事抽簪喜退耕。", "百步穿楊防偶蹶，一巵賞畫保先成。", "獺皮冠小隨時用，猪鼻車低取意行。", "官柳野梅春意動，莫教詩酒負平生。"]'),
('6feeb4e8-4c4a-46ee-8bd2-9feb3d021235','謝太守惠茶','葛勝仲','宋','宋诗','song-poetry','','[]','林亭凍卉未芳華，已享先春正焙芽。',64,'全唐诗/poet.song.78000.json','["林亭凍卉未芳華，已享先春正焙芽。", "活火急呼湯餅客，緘囊來自使君家。", "破看鮮馥欺瑶草，煮驗漂浮漾棗花。", "不預頭綱評四品，恍驚流落滯天涯。"]'),
('9c69f79e-d168-48d0-9f5c-ac2f9e1c890b','新茶','葛勝仲','宋','宋诗','song-poetry','','[]','壑源苞貢及春分，玉食分甘賜舊勲。',64,'全唐诗/poet.song.78000.json','["壑源苞貢及春分，玉食分甘賜舊勲。", "水厄陽侯宜避席，天隨陸子合同羣。", "珍同內府新蒼璧，味壓元豐小矞雲。", "便請加籩先果腹，鵝無留掌鼈添裙。"]'),
('9be741e9-173a-4eeb-84e5-5d4dc355cade','謝通判惠茶用前韻','葛勝仲','宋','宋诗','song-poetry','','[]','色味新香各十分，可無桑苧與書勲。',64,'全唐诗/poet.song.78000.json','["色味新香各十分，可無桑苧與書勲。", "打門贈我令呼客，好事知君最出羣。", "飲罷清風引仙闕，睡餘妖夢破朝雲。", "貧無列屋纖纖手，捧盌齊眉但布裙。"]'),
('d4cbd242-e726-44ae-a42e-3011982608cc','次韻郭大夫見寄','葛勝仲','宋','宋诗','song-poetry','','[]','泗上頻蒙訪寓公，十年乖隔馬牛風。',64,'全唐诗/poet.song.78000.json','["泗上頻蒙訪寓公，十年乖隔馬牛風。", "誰知邁往青雲士，尚寄哀遲白髪翁。", "浮食即今尸靖館，育材當日謾儒宫。", "寄聲有道勞虚奨，窶籔方安鼠技窮。"]'),
('c25d1de4-4a5a-4829-8690-691b54649f39','中秋夜宿舞陽精舍','葛勝仲','宋','宋诗','song-poetry','','[]','居心純靜眼無塵，此夜清光遍廣輪。',64,'全唐诗/poet.song.78000.json','["居心純靜眼無塵，此夜清光遍廣輪。", "乖隔謾嗟千里共，澄明還是一年新。", "已抛世外無窮事，獨喜尊前見在身。", "却憶帝城通夕看，清歌百闋會三人。"]'),
('b3678723-5408-4b47-a39e-05a0daccc5fc','二月三日遊風穴白雲寺呈通判二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','世傳三穴起長風，此理誠難識所從。',64,'全唐诗/poet.song.78000.json','["世傳三穴起長風，此理誠難識所從。", "覺性未能參七祖，禅扄聊欲訪千峰。", "桃溪遡日紅霞爛，麥隴酣春翠浪濃。", "簿領回回清興少，乍尋巖壑愧塵容。"]'),
('91a0cb94-be08-4f90-a168-c0fb6c67e2c8','二月三日遊風穴白雲寺呈通判二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','秀野班春過梵宫，賢僚况復肯相從。',64,'全唐诗/poet.song.78000.json','["秀野班春過梵宫，賢僚况復肯相從。", "風緣禦寇來幽穴，雲爲淵明出遠峰。", "柳色直将波共綠，花光疑與酒爭濃。", "一庵此境堪肥遁，寄語山靈幸見容。"]'),
('26a951c0-d232-4c94-9d07-81cd4b27c554','四桂坊','葛勝仲','宋','宋诗','song-poetry','','[]','蕊榜連年詔墨黄，聯翩恩綬月中香。',64,'全唐诗/poet.song.78000.json','["蕊榜連年詔墨黄，聯翩恩綬月中香。", "家聲舊踵三槐位，儒學今標四桂坊。", "酬唱共傳花蕚集，笑談應聚德星堂。", "門同列戟知非晚，更遣鄉評服義方。"]'),
('cd670e69-f059-46ad-805d-a537ce625833','吾家故事子姪登第必有酬獻詩什去歲立悌立經二姪並中科選未有慶以詩者偶示四韻','葛勝仲','宋','宋诗','song-poetry','','[]','充閭秀氣我家多，又喜雙龍並化梭。',64,'全唐诗/poet.song.78000.json','["充閭秀氣我家多，又喜雙龍並化梭。", "同榜連榮追紹聖，傳名躋甲首宣和。", "朝班鳴玉猶陞舍，冠歲横金又中科。", "四葉登華誰得似，會看盛事入編摩。"]'),
('5f01f9d0-5ed6-4f8a-a750-28e2bcb163b6','次韻覺心道人遊郡園','葛勝仲','宋','宋诗','song-poetry','','[]','牢落踰年坐斗州，窺園逢勝輙遲留。',64,'全唐诗/poet.song.78000.json','["牢落踰年坐斗州，窺園逢勝輙遲留。", "招邀風月千章木，收拾峰巒百尺樓。", "雲葉悠揚疑獨鶴，浪花浮動想饑鷗。", "道人知被烟霞錮，當是空門第一流。"]'),
('a17df672-37c0-44f4-9599-7a17d338e5ce','留二季父二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','敢向明時歎滯淹，得官迎飬富魚鹽。',64,'全唐诗/poet.song.78000.json','["敢向明時歎滯淹，得官迎飬富魚鹽。", "百年永抱雙親恨，五斗猶欣二父霑。", "壽耋名應書綠字，康寜藥不待青黏。", "虚堂梧竹饒幽趣，正好端居養智恬。"]'),
('61d318a3-0e16-4be5-8217-06f39d086d5a','留二季父二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','覊宦栖栖易感懷，一秋聊得病顔開。',64,'全唐诗/poet.song.78000.json','["覊宦栖栖易感懷，一秋聊得病顔開。", "幸蒙南巷攜家至，更喜東床自遠來。", "鵠髪二翁頻撰屨，鴒原羣從共衘杯。", "家山莫便懷中隱，風月躋攀更幾回。"]'),
('22b32e45-80bf-4d73-87a9-2ec87a66ca41','和若拙弟說汝州可居已約卜一丘韻','葛勝仲','宋','宋诗','song-poetry','','[]','汝海膏腴人共說，封疆况是接同州。',64,'全唐诗/poet.song.78000.json','["汝海膏腴人共說，封疆况是接同州。", "指囷待惠知無日，負米躬耕會有秋。", "林下要須三徑足，橐中更莫一錢留。", "飰抄雲子當同飽，官職來遲且自休。"]'),
('dcc79cb3-2066-4a08-bd76-0dc0f5dd7e8a','次韻陸巖老祠部見寄五首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','山城岑寂偶分麾，聊欲藏瘝一再期。',64,'全唐诗/poet.song.78000.json','["山城岑寂偶分麾，聊欲藏瘝一再期。", "豈有聲華如所譽，得非朋舊猥相欺。", "久欽黄髪嘉猷壮，初喜青天宿霧披。", "尚恨匆匆還執别，不容重醉習家池。"]'),
('182063ac-974f-4e29-9cdd-627192e2bd37','次韻陸巖老祠部見寄五首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','遶郭芙蓉十里城，畫橋煙水接東瀛。',64,'全唐诗/poet.song.78000.json','["遶郭芙蓉十里城，畫橋煙水接東瀛。", "蘋洲倒照蒼山影，花瀨遥聞白苧聲。", "問舍求田應犯慮，浮家泛宅未忘情。", "催科拙似陽公考，敢覬屏風錄姓名。"]'),
('38975990-2765-4b17-81d9-4dc250247f8d','次韻陸巖老祠部見寄五首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','溪南溪北梵王宫，踴甓亭亭聳半空。',64,'全唐诗/poet.song.78000.json','["溪南溪北梵王宫，踴甓亭亭聳半空。", "紅靺鞨沉山带日，碧琉璃凈水無風。", "雲迷翠閣參差見，舟艤朱橋繚繞通。", "泚筆憑誰寫東絹，盡将煙景薦重瞳。"]'),
('610f274a-aba0-4d32-aa1a-7b03f9982c7b','次韻陸巖老祠部見寄五首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','詞場弱歲以文鳴，落落寒松見老成。',64,'全唐诗/poet.song.78000.json','["詞場弱歲以文鳴，落落寒松見老成。", "劇郡神君頻結課，中台郎位早飛聲。", "當年威令千人廢，此日精神一座傾。", "欲試閒窗鴻筆健，春容詩軸燦瓊英。"]'),
('6a98d26e-526c-431b-b122-ab479b705706','次韻陸巖老祠部見寄五首  其五','葛勝仲','宋','宋诗','song-poetry','','[]','鏡中雙鬂未全華，退隱林泉意緒嘉。',64,'全唐诗/poet.song.78000.json','["鏡中雙鬂未全華，退隱林泉意緒嘉。", "春圃带煙鋤徑草，夜燈和雨看簷花。", "神能自衛同干越，老更知塗似渥洼。", "文注五河初不竭，從來惟屬士衡家。"]'),
('aa70133b-a35a-4d1c-8714-35557b166eea','次韻何總管等慈寺詩二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','寺門修竹映長楸，景似江村事事幽。',64,'全唐诗/poet.song.78000.json','["寺門修竹映長楸，景似江村事事幽。", "山疊青螺雲遶屋，月升紫磨水明樓。", "夢中他日應知路，天上從今與寄愁。", "競病将軍功已就，却将高興賦滄州。"]'),
('67aefb5e-08bb-4b32-97e2-bcd70fd72a02','次韻何總管等慈寺詩二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','古寺蕭清汝水湄，寓公仍有庾征西。',64,'全唐诗/poet.song.78000.json','["古寺蕭清汝水湄，寓公仍有庾征西。", "機輪宛轉春寒磑，浮綫縈紆漾小溪。", "入定僧閒多却掃，深春人去自成蹊。", "一杯相屬知何日，成事因須共到齊。"]'),
('21383c24-d1b8-4940-9385-6e162a4914d0','伯氏喪歸有日遣立方祭奠','葛勝仲','宋','宋诗','song-poetry','','[]','靈轜東下啟銘旌，羈宦惸惸逗楚城。',64,'全唐诗/poet.song.78000.json','["靈轜東下啟銘旌，羈宦惸惸逗楚城。", "遣奠聊憑貽厥力，衘哀遥致友于情。", "虎闈典教曾同遇，鴈塔書名亦並榮。", "齒脱髪稀吾老矣，可堪回首望前楹。"]'),
('00b4c08e-c84f-4484-b57b-faaa6b9630aa','次韻景純将赴襄陽眷戀里第','葛勝仲','宋','宋诗','song-poetry','','[]','枳棘棲鸞豈所宜，鹽車服驥暫韁鞿。',64,'全唐诗/poet.song.78000.json','["枳棘棲鸞豈所宜，鹽車服驥暫韁鞿。", "少而好學書饒讀，壮不貪榮譽自歸。", "重去故山抛小隱，懶趨名路觸危機。", "寄言漢廣徜徉者，聊賞風光且莫違。"]'),
('f480e1dd-148a-4c18-8106-c70cffd2406a','蒙若拙寵次陳敏彦韻三和  其一','葛勝仲','宋','宋诗','song-poetry','','[]','彤墀日覲赤霜袍，何苦懷歸問大刀。',64,'全唐诗/poet.song.78000.json','["彤墀日覲赤霜袍，何苦懷歸問大刀。", "吳坂未逢驚騕褭，豐城行見拭豪曹。", "廟堂仄席方求助，筦庫飛芻莫諱勞。", "即向詞垣摛外翰，當年仙桂幾枝高。"]'),
('45cfcb78-d067-445c-9416-6fe8bb9eaae6','蒙若拙寵次陳敏彦韻三和  其二','葛勝仲','宋','宋诗','song-poetry','','[]','寺居岑寂近方袍，貧舍分瓜毎借刀。',64,'全唐诗/poet.song.78000.json','["寺居岑寂近方袍，貧舍分瓜毎借刀。", "隸事舊聞輕叔寶，讀書今却笑敖曹。", "珍姿渾厚韜和璞，利刃堅剛敵孟勞。", "桂樹獨生千仞表，太丘家世顯名高。"]'),
('671dc0f9-a153-423b-affc-d2c17349ed89','蒙若拙寵次陳敏彦韻三和  其三','葛勝仲','宋','宋诗','song-poetry','','[]','韶顔祕殿賜恩袍，白首山城始夢刀。',64,'全唐诗/poet.song.78000.json','["韶顔祕殿賜恩袍，白首山城始夢刀。", "竹塢有詩緣二妙，棠陰無訟賴諸曹。", "消閒不廢持螯飲，結課曾微汗馬勞。", "更擬松江理煙艇，如歸亭上踵三高。"]'),
('b260546d-4ab0-4943-98f0-9832333514de','次韻宋景純寄陳去非昆仲','葛勝仲','宋','宋诗','song-poetry','','[]','雲臺獻納愧先賢，端合塵迷簿領閒。',64,'全唐诗/poet.song.78000.json','["雲臺獻納愧先賢，端合塵迷簿領閒。", "政似陽城惟下下，文如祖詠只班班。", "著書大似屋中屋，擇禄甘從山上山。", "揣分量材宜置散，敢於造物怨偏慳。"]'),
('aaa35e23-fbb7-4fd2-86cc-0049e46082e9','叔父承事用先公舊韻作詩次韻和呈','葛勝仲','宋','宋诗','song-poetry','','[]','西笑惟攜插架書，雍容車騎不求都。',64,'全唐诗/poet.song.78000.json','["西笑惟攜插架書，雍容車騎不求都。", "觀光鳯闕前蹤在，寄恨鴒原往事徂。", "喜見教忠躋顯仕，勉從迎養涉修途。", "新詩清婉追棠棣，樂孺當年共究圖。"]'),
('d40b42eb-4124-40ea-9cbd-18a32ff187ab','和元方寄若拙弟託覓顔淵之五十畝韻','葛勝仲','宋','宋诗','song-poetry','','[]','下田彌望股清流，謀食誰言必本州。',64,'全唐诗/poet.song.78000.json','["下田彌望股清流，謀食誰言必本州。", "且復種秔資口腹，早知籍稻載春秋。", "攜家便可隨豐儉，仕國從今委去留。", "饘粥粗供吾事濟，寸心安靜得休休。"]'),
('12a14718-e9dc-49f1-86ce-fec2c377052d','蒙若拙見和復次韻','葛勝仲','宋','宋诗','song-poetry','','[]','逸氣軒軒蓋搢紳，後來之秀子其人。',64,'全唐诗/poet.song.78000.json','["逸氣軒軒蓋搢紳，後來之秀子其人。", "文如范曄無空設，學似揚雄已大醇。", "記問五花能奪簟，風標一角共傳巾。", "怪來吐句皆清警，胸次應無庾亮塵。"]'),
('cc1b46ae-5c22-4202-9b16-66999d7e8d14','伏蒙孝立朝請同年赴九日燕集翌日以佳篇須酒謹依韻上謝','葛勝仲','宋','宋诗','song-poetry','','[]','新稻翻匙羮芋魁，慇懃重客肯相陪。',64,'全唐诗/poet.song.78000.json','["新稻翻匙羮芋魁，慇懃重客肯相陪。", "醉歸已徹重城漏，睡起應尋十日杯。", "欲得杜康連榼至，因令毛穎寄辭來。", "扶頭往餉宜頻釂，更喜輸租罷與催。"]'),
('8bb1429c-217a-4696-82b8-cbb39f0a23e0','邇日詩卷承若拙編爲小集見示且有詩因次韻','葛勝仲','宋','宋诗','song-poetry','','[]','驪珠魚目兩無遺，卷袠深煩爲析釐。',64,'全唐诗/poet.song.78000.json','["驪珠魚目兩無遺，卷袠深煩爲析釐。", "賦詠粗疏慚短筆，賡酬刻畫賴連枝。", "似聞警策眈佳句，何用編摩載惡詩。", "敢請冠篇重作序，二難文采勝延之。"]'),
('3af69e19-8525-47c8-ab12-332bd2f04ab1','次韻景純後圃宴集','葛勝仲','宋','宋诗','song-poetry','','[]','攜装過我路漫漫，聊命杯鐺爲禦寒。',64,'全唐诗/poet.song.78000.json','["攜装過我路漫漫，聊命杯鐺爲禦寒。", "漏月竹疏憐影碎，干霄楸老見根蟠。", "城頭飛屐千峰逈，樓角憑欄六幕寬。", "尚欲相留過殘臘，小園佳致雪中看。"]'),
('529bfcfe-bcc2-45fc-b533-25f9926e9ce5','景純到汝數日遽求别僕固不敢留客然宋伯舉爲兄蘇勤道爲婦之兄遽見去似非人情輙賦是詩率二僚留之','葛勝仲','宋','宋诗','song-poetry','','[]','奉留高客敢同黄，恃有親親與鴈行。',64,'全唐诗/poet.song.78000.json','["奉留高客敢同黄，恃有親親與鴈行。", "樂孺誠宜賦棠棣，盤桓何畏嗇檳榔。", "敬通叔達無爭論，法護僧彌各擅長。", "二義周官如問得，且看姜被莫騰装。"]'),
('9de305f4-6c7d-4ddf-8507-3104b26b28e5','懋南博士暫出廽邑以盛藻見觀謹依韻奉和二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','五十之年歲又開，劾歸不勇尚徘徊。',64,'全唐诗/poet.song.78000.json','["五十之年歲又開，劾歸不勇尚徘徊。", "家徒四壁謝金埒，第乏一區慚玉杯。", "彊欲安心師達磨，懶談真我類投灰。", "吾僚輕作經時别，猶喜民謡挽得回。"]'),
('4660a47e-4f67-44dd-83e6-e95531499fd1','懋南博士暫出廽邑以盛藻見觀謹依韻奉和二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','公退蕭閒閉息深，從來縣譜用山陰。',64,'全唐诗/poet.song.78000.json','["公退蕭閒閉息深，從來縣譜用山陰。", "威稜少霽髯垂几，才韻頻将筆捶琴。", "取急卧家聊小憇，捧符還郡却幽尋。", "風流若把名香擬，堪作盈斤百和沉。"]'),
('a67651ff-18d0-4067-ae6c-ebe7acc668f6','提宫工部兄攜家見過輙成律詩二首上呈  其一','葛勝仲','宋','宋诗','song-poetry','','[]','剥啄欣聞夜叩關，相迎一笑解愁顔。',64,'全唐诗/poet.song.78000.json','["剥啄欣聞夜叩關，相迎一笑解愁顔。", "枉帆雖落十人後，過飯今成五郡間。", "自役其身慚鞍掌，無求于世羡蕭閒。", "何如赴隴從招隱，却遣幽叢問小山。"]'),
('d3f4fa57-5955-438c-ad57-76b70b8856d9','提宫工部兄攜家見過輙成律詩二首上呈  其二','葛勝仲','宋','宋诗','song-poetry','','[]','相逢雖幸慰暌離，憂患仍年觸境悲。',64,'全唐诗/poet.song.78000.json','["相逢雖幸慰暌離，憂患仍年觸境悲。", "琴與俱亡念同氣，缶猶難擊愴齊眉。", "筋駑肉緩奔名懶，意廣才疏見事遲。", "只待歸資堪問舍，一封投劾去追隨。"]'),
('1e744808-dc14-4ae8-b0ba-f6683b6d48fc','福國諱日壽寜院作呈工部兄','葛勝仲','宋','宋诗','song-poetry','','[]','一官隨牒浪推移，不到名山二十期。',64,'全唐诗/poet.song.78000.json','["一官隨牒浪推移，不到名山二十期。", "踴甓獨存煨燼日，布金重見鼎新時。", "舊遊已起人琴恨，凈供還增奩鏡悲。", "賴是一般官拓落，林泉深處得追隨。"]'),
('6d906ba6-2a3d-461f-b196-5471a97f68fc','近闢禄隱軒建瓢飲亭季父以詩寄題和韻','葛勝仲','宋','宋诗','song-poetry','','[]','稚節爭名翰墨場，中年習隱水雲鄉。',64,'全唐诗/poet.song.78000.json','["稚節爭名翰墨場，中年習隱水雲鄉。", "遭時有幸常温飽，濟世無能分退藏。", "山色不於覊客秘，日華端爲散人長。", "身閒却笑東方朔，避世金門傲武皇。"]'),
('6e54c088-6a67-4cc5-875c-08129ba67959','次韻景純見寄叙相從之樂','葛勝仲','宋','宋诗','song-poetry','','[]','許昌舊姓有文儒，得得西來過燕居。',64,'全唐诗/poet.song.78000.json','["許昌舊姓有文儒，得得西來過燕居。", "訪我肯題門有鳯，館君深愧食無魚。", "鄣泥難爲清遊惜，便面頻将好句書。", "尚遣雅才淹簿領，好賢誰賦衛干旟。"]'),
('fa3bc56a-a314-4252-89d2-768957d6fb85','奉酬景純道中見寄之什','葛勝仲','宋','宋诗','song-poetry','','[]','慚無才望照簪紳，剖竹藩房誤長人。',64,'全唐诗/poet.song.78000.json','["慚無才望照簪紳，剖竹藩房誤長人。", "堪笑爲官常拓落，獨知取友愛真醇。", "吏休時著煎茶帽，客去今閒漉酒巾。", "曷日清揚重會面，劃開河漢滌心塵。"]'),
('bdf6a141-b433-4a5e-b5ea-e861f6e609c8','友鄉寄謝并月波酒和其韻','葛勝仲','宋','宋诗','song-poetry','','[]','長鬚剥啄叩柴扄，令弟官清遠寄聲。',64,'全唐诗/poet.song.78000.json','["長鬚剥啄叩柴扄，令弟官清遠寄聲。", "擿句已欣資藝圃，漱醪兼賴破愁城。", "牽絲聞說恢材力，露板應連上姓名。", "猶憶具區分袂處，孤帆一點愴離情。"]'),
('91ae3831-f1d9-47f8-8215-3fc04143c7fa','次韻叔才幽居二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','世塗艱險動難諧，學士深居但柏齋。',64,'全唐诗/poet.song.78000.json','["世塗艱險動難諧，學士深居但柏齋。", "紫翠當門流水過，碧鮮遮檻好風懷。", "角巾家巷便高枕，手板公廷厭沒堦。", "天地百年真逆旅，誰能巧宦役筋骸。"]'),
('ca5117b2-0e8f-4ce6-b4d9-c35ec9b8f22f','次韻叔才幽居二首  其二','葛勝仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','粗才濩落與時乖，湖海幽居一竹齋。',64,'全唐诗/poet.song.78000.json','["粗才濩落與時乖，湖海幽居一竹齋。", "月徑清遊疑不夜，風窗高趣到無懷。", "身閒有分白蓮社，地禁無心紅藥堦。", "只待匡廬官秩滿，一章程奏乞殘骸。"]'),
('bfd0f1fa-9104-413d-82bf-f7b3f0fb3713','次韻工部兄見寄三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','影落邗溝是我家，端來吳地寄生涯。',64,'全唐诗/poet.song.78000.json','["影落邗溝是我家，端來吳地寄生涯。", "蝸廬困卧身何擇，蝶夢時歸路不遐。", "幽徑任荒陶令菊，閒門聊蒔邵侯瓜。", "西還約醉中秋月，屈指同襟尚阻賖。"]'),
('3f2ed0af-2a07-4e1a-a6f8-919c08530f0c','次韻工部兄見寄三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','文采清華自一家，行身所到詎能涯。',64,'全唐诗/poet.song.78000.json','["文采清華自一家，行身所到詎能涯。", "學該古昔仍知要，識造高明豈不遐。", "英晤早明當道李，勤書頻事鎮心瓜。", "似聞憂國頭今白，法會無錢想尚賖。"]'),
('602b2137-96b4-4352-8e00-5b67a0145260','次韻工部兄見寄三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','朱門十萬一貧家，鼓枻西歸悵未涯。',64,'全唐诗/poet.song.78000.json','["朱門十萬一貧家，鼓枻西歸悵未涯。", "數米稱薪嗟隱約，望雲臨水負幽遐。", "清音且聽雉登木，曲路任從蠅集瓜。", "午飯蕭然無膾鯉，須知滋味已能賖。"]'),
('53e96e3e-f864-4123-93d8-888d4927f6f5','次韻叔才以詩卷見還有作','葛勝仲','宋','宋诗','song-poetry','','[]','委巷歌謡愧斐狂，雷門布鼓背生芒。',64,'全唐诗/poet.song.78000.json','["委巷歌謡愧斐狂，雷門布鼓背生芒。", "鳯毛忽爾驚懸罄，魚目真能引夜光。", "義重肯爲流俗變，意勤仍以古風将。", "怪來巾笥多珍玩，獲奉英遊已五霜。"]'),
('a014ec0f-1ffa-46f3-a340-c05136a3a5c1','昌化紫霄閣次長老仲希賦','葛勝仲','宋','宋诗','song-poetry','','[]','溪山佳處不須招，未到心旌毎動摇。',64,'全唐诗/poet.song.78000.json','["溪山佳處不須招，未到心旌毎動摇。", "漸喜田園挽陶令，敢将筆硯伏君苗。", "黑雲含雨迷江館，白鳥衝煙映市橋。", "回首海寜驚謫夢，挽舟猶記笏垂腰。"]'),
('1effc945-94e7-4dd6-b3bd-4acaed97b6eb','去南陽有日書懷二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','奠食無勞合退休，君恩誤付百花洲。',64,'全唐诗/poet.song.78000.json','["奠食無勞合退休，君恩誤付百花洲。", "未温坐席已當去，偶带泥封得少留。", "官意正如彊弩末，歸心先問大刀頭。", "略無涓滴蘇民隱，空使閭閻說舊侯。"]'),
('d555ca77-b604-4e3d-a9f1-cdb56101be82','去南陽有日書懷二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','離吳州好冠西畿，左竹纔交賦式微。',64,'全唐诗/poet.song.78000.json','["離吳州好冠西畿，左竹纔交賦式微。", "雲巘遐觀空杳靄，春郊細履負芳菲。", "薄遊頗似桑三宿，重到誰驚柳十圍。", "諾畫諸僚皆府望，不容坐嘯久焉依。"]'),
('99cdd917-ba32-45e5-97b1-be0065c3b86b','郡齋書懷','葛勝仲','宋','宋诗','song-poetry','','[]','暫擺塵勞坐燕居，野人偏與世情疏。',64,'全唐诗/poet.song.78000.json','["暫擺塵勞坐燕居，野人偏與世情疏。", "馬牛價雜慵鈎距，鳬鶩行多厭簿書。", "同醉徑須邀綠竹，盜香無復念紅蕖。", "不持黄卷来遮眼，可惜炎天化日舒。"]'),
('bd0c8029-92e5-4c07-964d-cd296e0cd4e3','南陽諸僚和留别詩再和二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','王事勤勞得少休，全家喜復入汀洲。',64,'全唐诗/poet.song.78000.json','["王事勤勞得少休，全家喜復入汀洲。", "懶於榮路占淹速，尚有浮生任去留。", "名譽未須驚谷口，功名終亦困壺頭。", "歸棲擬種千竿竹，便與題爲瀟灑侯。"]'),
('427a1d1d-53a0-4a89-b55c-a6a18c9627fb','南陽諸僚和留别詩再和二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','十連名郡近天畿，負重懸知困力微。',64,'全唐诗/poet.song.78000.json','["十連名郡近天畿，負重懸知困力微。", "閒客已知無嘯諾，鄰邦聊得看芳菲。", "謀身舊似齊優拙，罹咎今同魯酒圍。", "回首雋遊難戀嫪，索居獨學果疇依。"]'),
('7b46d80e-1f58-44bf-bf0c-32ebab39fdd1','還鄉有作二首  其一','葛勝仲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','菊潭才到便歸休，年大何心泣楚囚。',64,'全唐诗/poet.song.78000.json','["菊潭才到便歸休，年大何心泣楚囚。", "南嶽獻譏無反覆，東臯舒嘯有朋儔。", "龜靈自古稱懷浦，狐老從來只首丘。", "便覺謳吟罷莊舄，翛然隨俗且沈浮。"]'),
('95bfc365-d2c4-4e6a-8a7c-4b1e3334ac79','還鄉有作二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','孑孑攜家反故園，尚霑榮祿愧空飱。',64,'全唐诗/poet.song.78000.json','["孑孑攜家反故園，尚霑榮祿愧空飱。", "官閒未辦夸腰組，車過常先下里門。", "塗巷依然榆社舊，屋廬猶喜枳籬存。", "浮生孰似還鄉樂，謦欬吾前盡弟昆。"]'),
('82db9dff-00ce-4746-8332-d05cdd343410','里中無居寓丹陽縣書懷呈邑宰張子蒙','葛勝仲','宋','宋诗','song-poetry','','[]','假守秦頭兩月彊，往来遵路一年忙。',64,'全唐诗/poet.song.78000.json','["假守秦頭兩月彊，往来遵路一年忙。", "幸逢庇邑人惟舊，暫脱浮家計亦良。", "退食井腴如就國，遙尋祖系似還鄉。", "南風未便輕蓬蓽，也與虚窗拂袵凉。"]'),
('f9664940-ec02-44a5-bc09-66c4bfd60f45','戲書','葛勝仲','宋','宋诗','song-poetry','','[]','木彊與世異酸醎，掃灑真祠屢入銜。',64,'全唐诗/poet.song.78000.json','["木彊與世異酸醎，掃灑真祠屢入銜。", "新格似聞惟半俸，舊官那計是常參。", "茶爐僧缽随時用，手板朝衫竟月緘。", "賴有班書貧可貼，且謀蒲筍慰饑饞。"]'),
('3b5d7c40-e3c2-45a9-b909-65e566bac6eb','依韻和工部兄尋由里山泉眼','葛勝仲','宋','宋诗','song-poetry','','[]','葛帔練裙一散仙，親攜畚鍤道蒙泉。',64,'全唐诗/poet.song.78000.json','["葛帔練裙一散仙，親攜畚鍤道蒙泉。", "濫觴初見開微溜，中準終能作止淵。", "棲畝稻秧滋菶菶，入池藕葉泛田田。", "道人跬步不知處，未遇高賢名孰傳。"]'),
('f0f2f0bb-9abe-49d9-a312-80bcf889dd7f','依韻和工部兄雪五首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','風撼柴門夜不關，黎明瓊玉遍人寰。',64,'全唐诗/poet.song.78000.json','["風撼柴門夜不關，黎明瓊玉遍人寰。", "舉頭寒掩東隅日，縦目高疑西域山。", "朝路昔寧飄袂上，禪房今喜點爐間。", "亦知塵霧難攖拂，萬徑行蹤絕往還。"]'),
('de816ff4-7457-46c9-bda4-317d69142cd8','依韻和工部兄雪五首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','排寒聊與酒交關，呈瑞應先自帝寰。',64,'全唐诗/poet.song.78000.json','["排寒聊與酒交關，呈瑞應先自帝寰。", "初見同雲迷六幕，漸驚飛鳥絕千山。", "知酬素景風塵外，坐隔清遊咫尺間。", "飛灑卻羞来傍鬢，安仁年少不重還。"]'),
('a5789b7a-f447-44f0-bb90-e7a5065daf2d','依韻和工部兄雪五首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','從此何憂家事關，明年粒米厭區寰。',64,'全唐诗/poet.song.78000.json','["從此何憂家事關，明年粒米厭區寰。", "腰青不見飛花女，頭白先看對面山。", "絃凍未應停綠綺，膠彊仍喜彀黄間。", "平鋪萬頃茅簷冷，欲問城居幾日還。"]'),
('f118ffda-d3b5-44d9-b651-cbfafab939c7','依韻和工部兄雪五首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','門似柴桑畫亦關，歘驚閶闔堕人寰。',64,'全唐诗/poet.song.78000.json','["門似柴桑畫亦關，歘驚閶闔堕人寰。", "郊原那異熬波海，壠阜渾疑聚米山。", "望遠恨無樓百尺，逃寒阻共屋三間。", "阿兄詩句清奇甚，格律都高漢以還。"]'),
('d86b8240-3265-470d-925e-10115a096926','依韻和工部兄雪五首  其五','葛勝仲','宋','宋诗','song-poetry','','[]','偶兹窮臘憩鄉關，無蔕花飛遍海寰。',64,'全唐诗/poet.song.78000.json','["偶兹窮臘憩鄉關，無蔕花飛遍海寰。", "粉飾門闈疑省户，雲屯觀闕想神山。", "飄狂不絕三冬裏，積厚遙追二紀間。", "聞說旗亭增酒價，沈酣凖擬典衣還。"]'),
('a1b831bd-9d60-49f4-ad77-b46410039e42','菁山梅花盛開予獨未之知十一月二十二日周元舉察院餉數枝以詩三首爲謝  其一','葛勝仲','宋','宋诗','song-poetry','','[]','香雪常開小雪天，孤芳今占六花前。',64,'全唐诗/poet.song.78000.json','["香雪常開小雪天，孤芳今占六花前。", "欲從玉女互爭秀，不分青腰誇擅權。", "見事自知秦相緩，著鞭甘被祖生先。", "左轓不要宜春郡，應戀南枝映水鮮。"]'),
('8967db93-3ec1-45ea-afc4-7bfb629bc0c3','菁山梅花盛開予獨未之知十一月二十二日周元舉察院餉數枝以詩三首爲謝  其二','葛勝仲','宋','宋诗','song-poetry','','[]','冬早寒輕測測天，疏枝明秀忽来前。',64,'全唐诗/poet.song.78000.json','["冬早寒輕測測天，疏枝明秀忽来前。", "土酥結色神仙種，冰麝分香造化權。", "三白共驚千樹發，一年都占百花先。", "巡簷索與冰姿笑，凖擬攜壺更撃鮮。"]'),
('28516a53-3f28-43df-b484-6541710363ce','菁山梅花盛開予獨未之知十一月二十二日周元舉察院餉數枝以詩三首爲謝  其三','葛勝仲','宋','宋诗','song-poetry','','[]','山頭雲物凍吳天，幾樹寒英喚我前。',64,'全唐诗/poet.song.78000.json','["山頭雲物凍吳天，幾樹寒英喚我前。", "老不禁愁聊索笑，病方止酒暫從權。", "松篁傲雪堪爲伴，桃李酣春未敢先。", "習隱菁山真不惡，吟鞍十里看芳鮮。"]'),
('1f3231ce-4da1-4427-a65e-692c72879f8a','次韻耿守咏雪','葛勝仲','宋','宋诗','song-poetry','','[]','低雲晻曖與天同，剪水飛空候應冬。',64,'全唐诗/poet.song.78000.json','["低雲晻曖與天同，剪水飛空候應冬。", "沴氣潛消煩燮理，歡謠藹布荷明農。", "漾舟訪友乘清興，授簡延賓繼舊蹤。", "歲好定知豐五稼，倉箱行慶畝收鍾。"]'),
('ad23c65a-cb8e-41af-b8b8-9d444706d79c','景山寺居大風步月','葛勝仲','宋','宋诗','song-poetry','','[]','溪邊空谷偶来逃，散步虚廊破鬱陶。',64,'全唐诗/poet.song.78000.json','["溪邊空谷偶来逃，散步虚廊破鬱陶。", "庭户月華封玉雪，林巒風響洶波濤。", "氣寒秋盡衣裳薄，夜靜山深殿閣高。", "欲識羈懷愁幾許，明朝攬鏡看霜毛。"]'),
('736850fa-c039-462d-8b3b-d942c47f1eb0','十二月十日泛舟以北風寒回棹','葛勝仲','宋','宋诗','song-poetry','','[]','雲山冬瘦露精神，整棹溪邊試問津。',64,'全唐诗/poet.song.78000.json','["雲山冬瘦露精神，整棹溪邊試問津。", "懸坎带坻冰積厚，緣甍冒棟雪飛頻。", "出乘舴艋爲龜手，歸卧蝸牛分曲身。", "已覺烏蟾不能活，陽熙早晚定回春。"]'),
('43ba4572-2b68-4595-83ad-bf3140658b70','正月二十六日雪後登子亭示道祖','葛勝仲','宋','宋诗','song-poetry','','[]','淑景因陰苦未韶，峭寒於老不相饒。',64,'全唐诗/poet.song.78000.json','["淑景因陰苦未韶，峭寒於老不相饒。", "竊香風韻歸梅萼，刻楮工夫到柳條。", "萬瓦雪消疑夜雨，一溪波漲誤春潮。", "連枝别後兒曹遠，賴有吾人慰寂寥。"]'),
('92c10305-3062-418d-a8a1-db86fd2cd818','贈講華嚴惠照大師','葛勝仲','宋','宋诗','song-poetry','','[]','松陵講舌看瀾翻，滯論冰消瞬息間。',64,'全唐诗/poet.song.78000.json','["松陵講舌看瀾翻，滯論冰消瞬息間。", "覺性已明華藏海，退身聊遁莫釐山。", "識真久認魚筌假，處靜因求麈尾閒。", "我是殊庭仙隱吏，二年雲水共躋攀。"]'),
('8f5f1f7d-b935-4bc3-b363-1c817341dd7f','贈深老','葛勝仲','宋','宋诗','song-poetry','','[]','折床學子厭如雲，卷席歸棲震澤濱。',64,'全唐诗/poet.song.78000.json','["折床學子厭如雲，卷席歸棲震澤濱。", "識了大千俱是幻，理窮餘二即非真。", "已辭白社拘方侣，更笑紅樓應制人。", "弟子安心安已竟，不知若个是迷津。"]'),
('b57f8f13-256b-4a7f-9d3d-7a779faf74c9','贈福勝院老僧有宣','葛勝仲','宋','宋诗','song-poetry','','[]','諸方行盡已忘筌，宴坐歸来水石邊。',64,'全唐诗/poet.song.78000.json','["諸方行盡已忘筌，宴坐歸来水石邊。", "五葉承来真的嗣，七朝閲過到耆年。", "鸞音衮衮閒猶振，鶴骨昂昂高更堅。", "我特叩門来問道，投針相值恐前緣。"]'),
('edd8a27f-a546-42d0-b348-1c23a306089a','春日野步二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','一年春好是清明，萬事都歸笑矣行。',64,'全唐诗/poet.song.78000.json','["一年春好是清明，萬事都歸笑矣行。", "卵色天容供遠興，縠紋波面惬閒情。", "門生陪從無參佐，野服徜徉束珮纓。", "午困乞漿先饋少，已無形夢不須驚。"]'),
('0e0516b7-a914-4925-8714-0f2d1dd06cf7','春日野步二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','一春連雨少晴明，曳杖郊坰偶意行。',64,'全唐诗/poet.song.78000.json','["一春連雨少晴明，曳杖郊坰偶意行。", "嫵媚花枝空濺淚，風流柳色但牽情。", "長饑頻覺带移眼，大笑何寧冠絕纓。", "北極朝廷今咫尺，穰穰寇盜莫相驚。"]'),
('e1b313ad-4159-44e7-856c-ed121fa7258e','二月十五日遊謝村福田院觀涅盤會寺乃靈運故宅呈道祖','葛勝仲','宋','宋诗','song-poetry','','[]','年来生計一輕舠，晨出晡歸豈憚勞。',64,'全唐诗/poet.song.78000.json','["年来生計一輕舠，晨出晡歸豈憚勞。", "謝客兒山存勝致，佛泥涅日往遊遨。", "波間星斗沈光冷，月裏山河結影高。", "何日菁山山上寺，與君痛飲讀離騷。"]'),
('5c9b771f-f9ae-4653-a7ea-5b6717dfc3b2','天寜節感事示寶華鑑老','葛勝仲','宋','宋诗','song-poetry','','[]','詔語從天下九圍，並嚴法會保宸闈。',64,'全唐诗/poet.song.78000.json','["詔語從天下九圍，並嚴法會保宸闈。", "山稱萬歲誠尤切，鑑奉千秋事已非。", "已聽鸞音勤請祝，故應龍輅慶遄歸。", "孤臣拭血懷君處，小坌峰前淚滿衣。"]'),
('a1f345db-9123-4a10-a6a6-2edb98e98e25','和西郊春事招元方同遊韻','葛勝仲','宋','宋诗','song-poetry','','[]','仙橋水殿照清流，攘攘遊人聚九州。',64,'全唐诗/poet.song.78000.json','["仙橋水殿照清流，攘攘遊人聚九州。", "光景從来夸輦轂，風標况是富陽秋。", "天開卵色春方好，月上弓形夜更留。", "勉作新篇書盛麗，莫令少味似韓休。"]'),
('cb947c41-3c3e-4bc9-b486-46ef3771c702','和元方用韻見寄次韻奉謝兼呈元東詩二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','人與嚴徐是一流，英英儒雅冠吾州。',64,'全唐诗/poet.song.78000.json','["人與嚴徐是一流，英英儒雅冠吾州。", "白虹吐燭呈文夜，紅杏飄筵得意秋。", "祿薄未應腰爲折，語多共歎舌無留。", "令君舉善搜寒俊，不進清華諒不休。"]'),
('563a3435-060c-43a0-8361-597600c7fd77','和元方用韻見寄次韻奉謝兼呈元東詩二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','文律高峰與激流，五言佳處似蘇州。',64,'全唐诗/poet.song.78000.json','["文律高峰與激流，五言佳處似蘇州。", "寜甘鬲縣中漓酒，不羨宣城賞弈秋。", "白首同歸相器重，青雲一蹙豈淹留。", "外家門閥期君大，作德雖休更勿休。"]'),
('b875c0a8-adec-4cd6-ade0-c38e1466ab5c','追賢院食已度嶺歷宋胡諸庵轉山夜歸','葛勝仲','宋','宋诗','song-poetry','','[]','撃缶那能似漆園，銷魂来訪小桑門。',64,'全唐诗/poet.song.78000.json','["撃缶那能似漆園，銷魂来訪小桑門。", "仰衝雲陣尋峰頂，細步泉流覓水源。", "九里環觀山向背，兩輿歸趁月黄昏。", "春風不識愁人意，柳暗花明自逐村。"]'),
('577f1a72-b3e0-42ef-b1ee-c395744841aa','定山寺','葛勝仲','宋','宋诗','song-poetry','','[]','入門松桂拂天長，遣化誰来自衆香。',64,'全唐诗/poet.song.78000.json','["入門松桂拂天長，遣化誰来自衆香。", "初剪蕨嶶豐菜把，半殘桃杏露花房。", "不辭峻極猶登踐，免使幽尋墮渺茫。", "聞有山人宅巖頂，試從度世覓神方。"]'),
('ecccd1a4-b5e2-49b2-b09f-719f4019002c','章申公墳寺','葛勝仲','宋','宋诗','song-poetry','','[]','千章宰木蔭長城，申枉行頒寵數新。',64,'全唐诗/poet.song.78000.json','["千章宰木蔭長城，申枉行頒寵數新。", "金薤文華才冠世，銀鈎字畫品稱神。", "佳城此日看馴鹿，文保當年想夢麟。", "定有玉璜傳後裔，投竿端自渭城濱。"]'),
('6c82d38d-d55f-455c-b2db-e2ce1f925dc1','讀史二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','祖尚浮虚事漆園，生平圜府不曾言。',64,'全唐诗/poet.song.78000.json','["祖尚浮虚事漆園，生平圜府不曾言。", "神峰峻若瑤林茂，手色全如玉柄温。", "翊輔但求三兔窟，風流空擅一龍門。", "季年喪國排牆禍，綺靡諛言可得存。"]'),
('b5fe93f4-127f-4378-bf75-8f7a395657ed','讀史二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','曾侍東皇採紫芝，朅來西土宴瑶池。',64,'全唐诗/poet.song.78000.json','["曾侍東皇採紫芝，朅來西土宴瑶池。", "藻翁梁上休繁役，灰劫池中認遠期。", "數木故應煩鬼子，竊桃那免號偷兒。", "蒿廬不愛深山卧，避世金門世孰知。"]'),
('a2c17cb3-7102-4405-bfbb-7982c206780c','與工部兄邇歲離多會少又樂少苦多述懷','葛勝仲','宋','宋诗','song-poetry','','[]','並寓僧藍得幾時，薄遊苕霅遽暌離。',64,'全唐诗/poet.song.78000.json','["並寓僧藍得幾時，薄遊苕霅遽暌離。", "一麾爲郡乖同濟，百謫還鄉獨後期。", "第隔東西希聚首，憂連宗戚罕伸眉。", "何時解組俱林下，松菊園寬日共窺。"]'),
('87193209-2edb-4c2b-b28d-0e20d8c1ec66','和工部兄遷中散述懷韻','葛勝仲','宋','宋诗','song-poetry','','[]','一歲連膺四命書，衣冠慶美近時無。',64,'全唐诗/poet.song.78000.json','["一歲連膺四命書，衣冠慶美近時無。", "綿長本自天資厚，憑藉由来地勢孤。", "襆被昔高蘭省去，彯纓今喜棘班趨。", "立言制行俱忠孝，豈愧堂堂七尺軀。"]'),
('f9088266-eca2-4458-9858-9b406ee604f4','寄獻中散兄生辰','葛勝仲','宋','宋诗','song-poetry','','[]','吉月迎秋萬寶成，充閭瑞氣降耆英。',64,'全唐诗/poet.song.78000.json','["吉月迎秋萬寶成，充閭瑞氣降耆英。", "枌榆社裏藏身稳，桐柏宫中庀職清。", "黄髪定應驚再少，絳田端自保長生。", "壽觴親薦猶彌月，歸夢馳誠栩栩輕。"]'),
('3e9b6836-0a08-44e6-b1bc-e1de5ffa4e2e','次韻大資節使薛公見貽二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','黑頭自致已三旌，暫寄江湖適性情。',64,'全唐诗/poet.song.78000.json','["黑頭自致已三旌，暫寄江湖適性情。", "五總龜遊欽學富，九臯鶴立見神清。", "西雍寧累飛章薦，東閤頻蒙倒屣迎。", "方幸台躔照苕霅，以兹投劾未能輕。"]'),
('95e4e73f-17c0-47fd-ab87-9e1a310599be','次韻大資節使薛公見貽二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','劇談世事邇来慵，時向烟波掉雪篷。',64,'全唐诗/poet.song.78000.json','["劇談世事邇来慵，時向烟波掉雪篷。", "德業未嘗矜久大，光塵惟曲示和同。", "十年輔政裨元化，萬國賓賢振士風。", "敢請中興重作頌，衮衣不日見歸公。"]'),
('b3c94b7f-5176-4650-90a2-e2a10ea994e5','依韻和薛大資將往仙潭','葛勝仲','宋','宋诗','song-poetry','','[]','久向巖廊侍禹湯，歸身丘壑興尤長。',64,'全唐诗/poet.song.78000.json','["久向巖廊侍禹湯，歸身丘壑興尤長。", "東阡方幸陪遊樂，南浦難輕送别傷。", "欲以中經諮詁訓，更將奇字問偏旁。", "勉留衮舄輝山郡，不日天書下寵光。"]'),
('9e8d7eda-3376-484e-bb82-5bf1b50fcd42','次韻林茂南祀喜雪二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','膜拜同祈海岸仙，風雲奔走會諸天。',64,'全唐诗/poet.song.78000.json','["膜拜同祈海岸仙，風雲奔走會諸天。", "山巖恍若龍銜曜，墀廡頻驚鶴奪鮮。", "莫訝瑤英来有信，都緣玉燭氣無偏。", "化工應念催科拙，乞與穰穰大有年。"]'),
('49ed0f83-7fc9-4743-aada-9e689c08f521','次韻林茂南祀喜雪二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','吾僚齋禱極精誠，俄見聫翩舞玉霙。',64,'全唐诗/poet.song.78000.json','["吾僚齋禱極精誠，俄見聫翩舞玉霙。", "逞巧封條危不堕，弄閒飄幌細無聲。", "傾都奇貨歸王老，侵戶寒威賴麴生。", "天念春回惟七日，故教連夜趁嘉平。"]'),
('59663752-2e2d-4175-bd34-37ecc2ee5b6f','僚佐再和復作二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','雅步誰追鶴氅仙，峭寒真是酒家天。',64,'全唐诗/poet.song.78000.json','["雅步誰追鶴氅仙，峭寒真是酒家天。", "謝庭最愛因風起，桓扇寧書遇象鮮。", "遠覺歸巢禽翅重，靜看當檻竹枝偏。", "三吳此景宜增賞，飄瞥郊原似昔年。"]'),
('a3f993db-3488-46ef-8a99-153139b47db6','僚佐再和復作二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','從来愛雪是真誠，又見祥飛六出霙。',64,'全唐诗/poet.song.78000.json','["從来愛雪是真誠，又見祥飛六出霙。", "材薄敢招能賦客，庭閒聊作詠詩聲。", "瑤階誤向凡間見，春蘤翻驚臘裏生。", "賀板並来無答語，自慚詞筆太平平。"]'),
('95fcf2cf-3cde-4187-9c6d-4ac2ba4d0f22','次韻中散兄及諸弟寄顧渚茶二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','苕溪溪上一茶神，三表遺經品藻親。',64,'全唐诗/poet.song.78000.json','["苕溪溪上一茶神，三表遺經品藻親。", "輕拂競看雲態度，初嘗應惬舌根塵。", "草堂遙憶金沙水，花瀨聊分紫氣春。", "尤物從来常貴少，彭城園外即非真。"]'),
('20b7d1e2-192c-48b6-9042-f45796417c3c','次韻中散兄及諸弟寄顧渚茶二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','健步蒼頭捷若神，露芽三日到情親。',64,'全唐诗/poet.song.78000.json','["健步蒼頭捷若神，露芽三日到情親。", "輕甌延喜凝珍玉，小磑鄰虚堕細塵。", "便好相招十日飲，莫教虚負一年春。", "慇懃後訊當重餉，月六齋時供應真。"]'),
('08f92b3e-88a5-43c5-9877-594f764fa9a2','哭衞卿弟三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','搖毫射策逐羣裾，獨以高名唱玉除。',64,'全唐诗/poet.song.78000.json','["搖毫射策逐羣裾，獨以高名唱玉除。", "五斗抛来爲詩酒，三餘收得向樵漁。", "固存夙悟無生理，永訣親裁忍死書。", "晚歲異鄉成一慟，大紅親破茂紅綀。"]'),
('6b4664c8-47d3-4c6b-afd8-e05247c14884','哭衞卿弟三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','遠業相期未易量，那知百歲似風狂。',64,'全唐诗/poet.song.78000.json','["遠業相期未易量，那知百歲似風狂。", "鵩来有恨催新賦，鵲往無醫識禁方。", "鄰笛他年那忍聽，人琴此日遂俱亡。", "長空後夜西風急，吹斷驚鴻不作行。"]'),
('19583b8e-29ab-43bf-9499-8748c688b824','哭衞卿弟三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','高材磊落氣崢嶸，命薄難將智力爭。',64,'全唐诗/poet.song.78000.json','["高材磊落氣崢嶸，命薄難將智力爭。", "赤米白鹽生理窄，紅蓮綠水宦情輕。", "曾期虚閣憑欄醉，不遂扁舟適野迎。", "汝已反真歸大化，山城空慟十年兄。"]'),
('28ae8587-1d8a-4e81-bf02-c01ea9520267','曾夢良惠然見存出口字詩十有七篇偶摭所遺成三篇紀謝  其一','葛勝仲','宋','宋诗','song-poetry','','[]','未有歸資可買山，一封程奏便求閑。',64,'全唐诗/poet.song.78000.json','["未有歸資可買山，一封程奏便求閑。", "睢睢去後容爭席，碌碌羞来肯抱關。", "幻界已知都是夢，真心自要識無還。", "尊前衮衮聽名理，坐遣窮愁一破顔。"]'),
('acae13af-eb9f-4c44-b75f-acb3aa91c922','曾夢良惠然見存出口字詩十有七篇偶摭所遺成三篇紀謝  其二','葛勝仲','宋','宋诗','song-poetry','','[]','清明時節訪溪山，消盡機心大智閑。',64,'全唐诗/poet.song.78000.json','["清明時節訪溪山，消盡機心大智閑。", "元亮孤舟聊自棹，尚平家事不相關。", "叩門雖幸千金顧，戀德翻嗟半日還。", "並水幽亭同歷覽，應憐瓢飲政希顔。"]'),
('5171648f-21c3-479d-8154-c2eec323ab20','曾夢良惠然見存出口字詩十有七篇偶摭所遺成三篇紀謝  其三','葛勝仲','宋','宋诗','song-poetry','','[]','居然埋照向窮山，誰識龍媒伏帝閑。',64,'全唐诗/poet.song.78000.json','["居然埋照向窮山，誰識龍媒伏帝閑。", "意氣雖吞雲夢澤，功名未羨玉門關。", "身常靜退緣知止，心不傾邪畏好還。", "但恐搢紳公論在，招延行見覲威顔。"]'),
('dd2fc795-756a-4a72-a8e0-cb0bb7ba0270','中散兄喜罷郡有詩次韻却寄','葛勝仲','宋','宋诗','song-poetry','','[]','上印歸来卧蓽門，此心炯炯向誰論。',64,'全唐诗/poet.song.78000.json','["上印歸来卧蓽門，此心炯炯向誰論。", "平生疏拙真天賦，此去安閒盡主恩。", "舊識愧真爲我累，近知凡百喪吾存。", "好来同習菁山隱，白髪仙臞兩弟昆。"]'),
('df422913-2b0a-4691-b008-44337317683f','次韻中散兄見寄','葛勝仲','宋','宋诗','song-poetry','','[]','晦迹纔須一畝間，浮家暫寄五湖邊。',64,'全唐诗/poet.song.78000.json','["晦迹纔須一畝間，浮家暫寄五湖邊。", "官抛印綬輕千里，祿隱漁樵已十年。", "眼對雲山偏爛爛，腹藏篇牘自便便。", "政緣欲遂幽棲樂，豈是清時獨棄捐。"]'),
('2d635ba2-5291-4613-80c0-db412e2b974c','次韻錢伸仲見貽兼送别二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','四年五度訪郊村，苜蓿羮稀不厭貧。',64,'全唐诗/poet.song.78000.json','["四年五度訪郊村，苜蓿羮稀不厭貧。", "清韻喜逢鬚展戟，奥篇仍覩筆書銀。", "一笻巖壑幽棲地，五兩江湖自在身。", "他日願陪雞黍社，貴鄰應不買增珍。"]'),
('02132beb-64bf-4ecd-ad85-d1a25cd4479a','次韻錢伸仲見貽兼送别二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','郊居牢落似東屯，剥啄欣聞客叩門。',64,'全唐诗/poet.song.78000.json','["郊居牢落似東屯，剥啄欣聞客叩門。", "筆下波濤文貫道，胸中瑜瑾學逢源。", "西余未遂諧清賞，南浦俄驚黯别魂。", "金菊萬株秋露重，此時重復望来轅。"]'),
('1020f83e-44c9-4bcb-838e-ead2bf2f3561','題寄伸仲先塋瞻雲亭','葛勝仲','宋','宋诗','song-poetry','','[]','銜哀負土記當年，白首来臨涕泫然。',64,'全唐诗/poet.song.78000.json','["銜哀負土記當年，白首来臨涕泫然。", "宰樹成行無鹿觸，佳城卜吉自牛眠。", "已乖綵服親嘗膳，猶幸綸封數漏泉。", "反顧雲飛頻悵望，孝誠寜愧斗南賢。"]'),
('29f8f504-b64d-4828-980e-60fe482a2bdc','喜中散兄將至','葛勝仲','宋','宋诗','song-poetry','','[]','兩年僑寓爲知音，百指仍攜就泛金。',64,'全唐诗/poet.song.78000.json','["兩年僑寓爲知音，百指仍攜就泛金。", "蠅集樹榛曾掣肘，魚傳尺素喜回心。", "無邊紅芰邀同醉，不盡青山得共尋。", "白首居諸良會少，對床免被别愁侵。"]'),
('e69b46da-cd85-4b42-8a47-965730c8c372','次韻中散兄將到先示詩','葛勝仲','宋','宋诗','song-poetry','','[]','雲山佳處復躋攀，景物依然得破顔。',64,'全唐诗/poet.song.78000.json','["雲山佳處復躋攀，景物依然得破顔。", "春事闌珊三月尾，時光荏苒七年間。", "重来懷紱成何事，歸去抽簪幸有山。", "且盡一杯今日樂，投林飛鳥會知還。"]'),
('bc168def-e229-4be4-aeeb-e8d3b819bd36','次韻中散兄喜雪二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','林薄風號兩日先，俄驚剪水堕遙天。',64,'全唐诗/poet.song.78000.json','["林薄風號兩日先，俄驚剪水堕遙天。", "坐看山路禽飛絕，聊勝泥塗馬不前。", "輕點紅爐呈妙意，斜飄素髪映衰年。", "寒霙與我官同冷，莫笑柴扉日晏眠。"]'),
('2a088203-f628-4403-82cb-ce7c1590ddf0','次韻中散兄喜雪二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','縹緲山頭白最先，模糊雲物變吳天。',64,'全唐诗/poet.song.78000.json','["縹緲山頭白最先，模糊雲物變吳天。", "陸機玉圃無精粗，王衍瑤林滿後前。", "酒漲微瀾宜永夜，麥翻翠浪看明年。", "曉晴便是春消息，梅萼包香柳欲眠。"]'),
('fd6683ea-9388-4b47-9c45-dea8ef613f13','次韻中散兄二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','泉石清遊一月間，風輕氣爽未驚寒。',64,'全唐诗/poet.song.78000.json','["泉石清遊一月間，風輕氣爽未驚寒。", "唱經雲岫頻清梵，佞佛爐烟費紫檀。", "震澤魚肥聊獨酌，包山橘熟阻同看。", "歸来頓識南宗髓，寧見彌天釋道安。"]'),
('c1f46a80-cab2-46e5-b73e-849eaaf20eea','次韻中散兄二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','遍遊湖寺棹舟還，重理殘書逼小寒。',64,'全唐诗/poet.song.78000.json','["遍遊湖寺棹舟還，重理殘書逼小寒。", "衰鬢迎風似蒲柳，貧爐無火取槐檀。", "毫銖利祿回頭笑，翻覆人情洗眼看。", "癡鈍老人堪底用，故應衡宇自偷安。"]'),
('54727863-64af-4bc4-8c8a-1c49b714ca74','友卿弟見和復賦二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','歲律崢嶸又欲還，鳴條風急作清寒。',64,'全唐诗/poet.song.78000.json','["歲律崢嶸又欲還，鳴條風急作清寒。", "菊英媚日猶呈秀，梅蘂包香未吐檀。", "江水過門兼汐到，鄉山當面带雲看。", "是身已覺都無事，只有空飱不自安。"]'),
('04be612b-73c7-414a-983a-bcdaa0f12519','友卿弟見和復賦二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','門無雜客往仍還，趺坐澄心定水寒。',64,'全唐诗/poet.song.78000.json','["門無雜客往仍還，趺坐澄心定水寒。", "清凈苦嫌千日酒，蕭閒惟事一銖檀。", "眼中金屑全無用，髻裏明珠得自看。", "作止更能除任滅，已無禪病自輕安。"]'),
('bb360c95-3962-4d68-bd6e-0c27e74c77df','次韻維心二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','蕭衣無柰客愁多，日飲那知酒有戈。',64,'全唐诗/poet.song.78000.json','["蕭衣無柰客愁多，日飲那知酒有戈。", "松徑崎危羊石卧，筠筒屈曲虎泉過。", "懶尋丹竈山名葛，且供禪龕人姓何。", "共看今年龍集酉，穰穰蕃熟慶時和。"]'),
('fefbdbcf-d935-432b-9655-780c33d769bb','次韻維心二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','側席求賢歲又除，如君德盛孰儀圖。',64,'全唐诗/poet.song.78000.json','["側席求賢歲又除，如君德盛孰儀圖。", "軼材共仰人之傑，讜議懸知帝曰都。", "豈有簀中終去魏，未妨廡下略居吳。", "蒲輪不日来徵聘，禪句休誇雪點爐。"]'),
('9405aea4-2f46-4452-88ec-327f8647e511','次韻葉少協泛舟','葛勝仲','宋','宋诗','song-poetry','','[]','水風斜日惬新晴，初解銅章病骨輕。',64,'全唐诗/poet.song.78000.json','["水風斜日惬新晴，初解銅章病骨輕。", "遠寺藏烟增晻靄，寒峰带雪更鮮明。", "尋幽屢辦揚舲出，辱訪慚乖倒屣迎。", "煙艇遙遙逐鷗颺，淵明從此得浮生。"]'),
('dec2258c-22bd-4b99-9cab-f907dd136ca9','寄題拙臺','葛勝仲','宋','宋诗','song-poetry','','[]','講罷公堂得少休，下簾清興與天悠。',64,'全唐诗/poet.song.78000.json','["講罷公堂得少休，下簾清興與天悠。", "書空怪事知無益，爲圃機心逝不留。", "四至九卿空士笑，一當萬乘豈人謀。", "先生獨有摛詞巧，奪盡人間重錦裘。"]'),
('ce79b9df-f351-46c0-aa17-157dd89828ef','和小室韻','葛勝仲','宋','宋诗','song-poetry','','[]','一味伽那已默傳，隨機任運且忘年。',64,'全唐诗/poet.song.78000.json','["一味伽那已默傳，隨機任運且忘年。", "翻經不落摩騰後，成佛仍居謝客前。", "教海就舟方見聖，宗門得髄始通禪。", "蕭齋一炷寒沈水，了盡因緣與自然。"]'),
('5359ec5e-b74b-4026-8a81-26af09ec186b','次韻朝隱招飲二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','千古興亡馬食槽，醉鄉真可寄廉高。',64,'全唐诗/poet.song.78000.json','["千古興亡馬食槽，醉鄉真可寄廉高。", "功名戲事何須掛，富貴危機詎肯饕。", "幸有碧筩消暑溽，休誇白堕執逋逃。", "牢愁滯恨知多少，凖擬都將付濁醪。"]'),
('322b79d4-3c23-4eac-932d-920d37a222ad','次韻朝隱招飲二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','何須邏逤響檀槽，獨喜杯中酒浪高。',64,'全唐诗/poet.song.78000.json','["何須邏逤響檀槽，獨喜杯中酒浪高。", "芰實深酬屈到嗜，鱸魚仍足季鷹饕。", "加籩亹亹情尤厚，醉舞僛僛罪敢逃。", "我亦頭巾漉家釀，明當相速醉芳醪。"]'),
('39630e4b-d5b6-4db0-9856-25bc73a21ad0','招中散兄飲','葛勝仲','宋','宋诗','song-poetry','','[]','飄零羈旅苦摧頽，旬日希逢笑口開。',64,'全唐诗/poet.song.78000.json','["飄零羈旅苦摧頽，旬日希逢笑口開。", "爐冷難施文武火，氣寒聊雜聖賢杯。", "牛鳴地去無多遠，羊胛熟時宜便来。", "聞說家山動歸興，預愁疊鼓起高桅。"]'),
('21243f87-48ea-4898-a905-b4419cddc004','次韻卿任賦立春','葛勝仲','宋','宋诗','song-poetry','','[]','陽和協氣起寒灰，席上清歌聽落梅。',64,'全唐诗/poet.song.78000.json','["陽和協氣起寒灰，席上清歌聽落梅。", "煖逐日華驚歲換，夜占天象覺星回。", "書籌屢點蟾蜍硯，命釂連催鸚鵡杯。", "願斂春祺錫黎庶，熙熙一鏡似登臺。"]'),
('da38e370-4ca7-406b-841a-3f8e9ae07aec','次韻道祖賦立春','葛勝仲','宋','宋诗','song-poetry','','[]','棠華鞾韡綺筵開，何用三行粉面回。',64,'全唐诗/poet.song.78000.json','["棠華鞾韡綺筵開，何用三行粉面回。", "金鴨香殘知漏永，土牛色重喜春来。", "飄霙著樹狂欺柳，剪綵裝花巧鬬梅。", "俛仰光陰驚歲換，誰將藍尾更銜杯。"]'),
('29f33ac8-4928-481e-9a11-e1c45f386d68','喜晴','葛勝仲','宋','宋诗','song-poetry','','[]','補陁香供走人天，赴感隨緣舊所傳。',64,'全唐诗/poet.song.78000.json','["補陁香供走人天，赴感隨緣舊所傳。", "霖雨方憂困桑户，晚晴俄喜賦樊川。", "階庭旋見收黄潦，齋壁何因上綠錢。", "多謝化工哀老子，遨遊不復更祈年。"]'),
('6bbbdd0d-aa85-4ba1-8071-c57f67804391','陳朝檜','葛勝仲','宋','宋诗','song-poetry','','[]','拏雲老檜欲千春，幾閲人間旦復曛。',64,'全唐诗/poet.song.78000.json','["拏雲老檜欲千春，幾閲人間旦復曛。", "風裏樛枝喧過雨，月中清影碎流雲。", "蟠根不願郎官谷，聳榦宜參君子軍。", "須信英靈神物護，頻經兵寇惜揮斤。"]'),
('35ea2181-b736-42d9-830d-54115c88d3f0','春晝偶作次元述韻','葛勝仲','宋','宋诗','song-poetry','','[]','屏居岑寂似禪關，顧笑初無素與蠻。',64,'全唐诗/poet.song.78000.json','["屏居岑寂似禪關，顧笑初無素與蠻。", "晝棟差池寧識燕，綺窗葱翠舊遊山。", "時危謾自懷頗牧，境靜聊欣接尹班。", "二紀家園逋細履，身閒今得一時還。"]'),
('2e63602e-5d8b-44e1-b117-6a626848e701','次韻元述','葛勝仲','宋','宋诗','song-poetry','','[]','漂泊身如不繋舟，芙蓉湖上懶回頭。',64,'全唐诗/poet.song.78000.json','["漂泊身如不繋舟，芙蓉湖上懶回頭。", "干戈時幸逃新鬼，巖壑人能識故侯。", "已覺功名真破甑，却驚歲月甚奔流。", "仙庭五載空浮食，恩重丘山豈易酬。"]'),
('311bbf09-a78d-4e44-8588-9cf3c2b1530b','即事  其一','葛勝仲','宋','宋诗','song-poetry','','[]','五載投閒隱薜蘿，眼看時事只悲歌。',64,'全唐诗/poet.song.78000.json','["五載投閒隱薜蘿，眼看時事只悲歌。", "家貧不畏鬼来笑，世變難教佛柰何。", "髀肉生緣癡坐久，带圍減爲客愁多。", "他年莫忘菁山寺，百口啼饑兩鬢皤。"]'),
('be78f736-58be-4d2a-af2b-6dc0eccb37fa','即事  其二','葛勝仲','宋','宋诗','song-poetry','','[]','青雲那肯羡雄飛，前料山邊習遁肥。',64,'全唐诗/poet.song.78000.json','["青雲那肯羡雄飛，前料山邊習遁肥。", "名教固應多樂地，賤貧聊幸脱危機。", "虀無萍韭何妨醉，羮有菰蓴自合歸。", "格外一官垂欲滿，便從神武挂冠衣。"]'),
('32f23851-06a7-45c5-91a6-475c2edd4ca9','即事  其三','葛勝仲','宋','宋诗','song-poetry','','[]','諸公衮衮上巖廊，濟世無能分退藏。',64,'全唐诗/poet.song.78000.json','["諸公衮衮上巖廊，濟世無能分退藏。", "所止先名大隱洞，平生本望祕書郎。", "畫成顧失一巵酒，箭蹶空穿百步楊。", "幻界光陰凛無幾，養生從此學長桑。"]'),
('8f035724-a611-4d86-8179-9f5a8a87af11','村人寫予像即景山飯道僧祈禱爲會頗盛','葛勝仲','宋','宋诗','song-poetry','','[]','單車去位五年强，初乏恩襦庇一方。',64,'全唐诗/poet.song.78000.json','["單車去位五年强，初乏恩襦庇一方。", "大姓殷勤攜老稚，精藍祈祝飯緇黄。", "此時美稷勤邀迓，他日桐鄉必奉嘗。", "爲報庚桑相俎豆，不如道術永相忘。"]'),
('07901356-49ea-467b-8ec5-6eb12231ab95','除夕郊居書懷','葛勝仲','宋','宋诗','song-poetry','','[]','晚塗蕭颯寄漁樵，夢亦無因到上朝。',64,'全唐诗/poet.song.78000.json','["晚塗蕭颯寄漁樵，夢亦無因到上朝。", "書在床頭脱復看，客逢野外偶相要。", "敢嗟祿薄難餬口，大勝官粗毎折腰。", "六十七年明日是，亦逢村釀也浮椒。"]'),
('80721452-78a7-49ee-a956-3b91e225a6a0','次韻德升頤軒書懷','葛勝仲','宋','宋诗','song-poetry','','[]','煙霄飛步欲青春，未信論甘肯忌辛。',64,'全唐诗/poet.song.78000.json','["煙霄飛步欲青春，未信論甘肯忌辛。", "三仕固應無喜色，一鳴今復見驚人。", "射如關尹方知中，畫若元君始識真。", "早晚奏篇来拭目，清塗聊爲洗荒榛。"]'),
('1efc0ad6-7c37-4307-8f91-0f45f401f418','次韻中散兄慶立方賜第','葛勝仲','宋','宋诗','song-poetry','','["\u534e\u5c71"]','兒曹春榜預言揚，竊吹知難服士鄉。',64,'全唐诗/poet.song.78000.json','["兒曹春榜預言揚，竊吹知難服士鄉。", "黄絹未能摛好語，青氊偶幸繼前芳。", "穿楊喜共東床客，攀桂同標北寺房。", "聖世選材如華嶽，積塵曾不棄毫芒。"]'),
('a2770254-d9e6-4d7a-93b5-7d5c778cfc99','次韻邊公明放魚','葛勝仲','宋','宋诗','song-poetry','','[]','小鮮無數命臨危，邂逅雲莊擴大悲。',64,'全唐诗/poet.song.78000.json','["小鮮無數命臨危，邂逅雲莊擴大悲。", "巨浸何勞長者水，親臨尤勝校人池。", "依蒲俯視還真樂，貫柳充庖那復知。", "圉圉介鱗俱得所，道人因得一伸眉。"]'),
('dba1a750-13b9-4ad6-a7cf-b17088fa885c','次韻顔孝立同年','葛勝仲','宋','宋诗','song-poetry','','[]','亦識韶華不肯留，時危那更事嬉遊。',64,'全唐诗/poet.song.78000.json','["亦識韶華不肯留，時危那更事嬉遊。", "羈懷不辦愁花雨，空廪惟知望麥秋。", "顧我端憂宜燥吻，如公無事合扶頭。", "麴生漫助齊眉餉，清洗錢塘兩玉舟。"]'),
('669003ce-b69f-4301-b868-98e2b93e21e4','和必先龍圖謝酒兼呈沈次律大學士','葛勝仲','宋','宋诗','song-poetry','','[]','臺閣高賢卧里門，清揚乖隔阻寒温。',64,'全唐诗/poet.song.78000.json','["臺閣高賢卧里門，清揚乖隔阻寒温。", "尚賒宴豆陪三雅，聊即烟郵寓一尊。", "亂後官居同幕燕，春来香味憶河豚。", "溪亭午夜銜杯處，應對梅花淡月昏。"]'),
('f99dd824-d79e-47b4-8750-a46c3c1df1fc','贈史德謙','葛勝仲','宋','宋诗','song-poetry','','[]','不入城闉已十年，足音何幸聽跫然。',64,'全唐诗/poet.song.78000.json','["不入城闉已十年，足音何幸聽跫然。", "杯觴共樂三更後，書史相從一世前。", "鳥倦尚飛慚我老，鴻冥何慕覺公賢。", "錙銖得失何須算，聞健惟當數撃鮮。"]'),
('5635c2cd-1b9b-4c91-8cfe-012027a0ee35','贈鮑欽止二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','錦窠朱紱亦何榮，辭劇求閒責自輕。',64,'全唐诗/poet.song.78000.json','["錦窠朱紱亦何榮，辭劇求閒責自輕。", "聊喜青葱供俯仰，未應紅腐較奇贏。", "久知飛鳥有真意，誰信鳴雞非惡聲。", "只恐朝端闕司隸，又將斂手避威名。"]'),
('8d350622-ceff-4f4e-81fd-aa40cafa87c8','贈鮑欽止二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','紅塵衮衮厭朝班，官寺深藏洛尾灣。',64,'全唐诗/poet.song.78000.json','["紅塵衮衮厭朝班，官寺深藏洛尾灣。", "識擢早驚郎位峻，招尋今見水仙閒。", "高標自置羲皇上，俗眼從教季孟間。", "倉氏一官寜久困，禁途供奉政才難。"]'),
('7b8f4471-93bb-4cc7-a4c0-96792ec96a4e','挽致政奉議魯公歌詞','葛勝仲','宋','宋诗','song-poetry','','[]','翛然丈室老維摩，不愧家聲舊曲阿。',64,'全唐诗/poet.song.78000.json','["翛然丈室老維摩，不愧家聲舊曲阿。", "事閲七朝推壽俊，慶鍾六子半文科。", "白蓮入社塵緣息，朱紱通閨聖渥多。", "空唱已聞生凈域，可須薤露起悲歌。"]'),
('79d562b3-9717-4e4b-ac31-e7feb6bf9d50','張子蒙令君挽歌詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','賦歸州里半年間，豈料循題哭二難。',64,'全唐诗/poet.song.78000.json','["賦歸州里半年間，豈料循題哭二難。", "屢薦嘗爲趨幕客，數奇終困字民官。", "清談竟日師夷甫，寢瘵連年痛士安。", "身後華名知不朽，幾多墨妙翠珉刊。"]'),
('1febd490-1a0b-4ac3-8cef-10d13153a2eb','張子蒙令君挽歌詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','文義游從四十春，艱難契闊見情親。',64,'全唐诗/poet.song.78000.json','["文義游從四十春，艱難契闊見情親。", "少年漣上初傾蓋，末路雲陽擬卜鄰。", "萬室謳吟依愷悌，一生志氣負經綸。", "渭陽豈特兒曹慟，老送佳城淚滿巾。"]'),
('6459a7c4-666b-4f9a-97a8-f817ce06bc1f','大卿表兄莫公挽歌詞二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','露奏求閒猛挂冠，忽驚卿月堕雲端。',64,'全唐诗/poet.song.78000.json','["露奏求閒猛挂冠，忽驚卿月堕雲端。", "中年屢攬澄清轡，末路堅辭矍鑠鞍。", "自卜壽藏松已拱，親裁幽刻墨方乾。", "映溪清遠樓前月，後夜登門忍獨看。"]'),
('a4b91d35-3709-4b42-bb14-4b24aa12d504','大卿表兄莫公挽歌詞二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','遊從五紀荷勤渠，白首来依霅水居。',64,'全唐诗/poet.song.78000.json','["遊從五紀荷勤渠，白首来依霅水居。", "郡閤箴規言有補，家林書疏月無虚。", "方期老驗長桑藥，忽見神升廣柳車。", "兄姊同時封吉壤，不堪清涙屑衣裾。"]'),
('8d093153-a2b5-4109-9507-0d34ccac6f87','先兄中散挽歌詞四首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','昂昂鶴骨素康彊，微疢生朝罷舉觴。',66,'全唐诗/poet.song.78000.json','["昂昂鶴骨素康彊，微疢生朝罷舉觴。", "尚冀魂隨香釡反，那知人逐綺琴亡。", "禁方不驗三茅洞，遺墨平砥空留二老堂。", "從此幽棲風雨夜，一翻姜被一凄凉。"]'),
('e1cff49f-05be-455e-a716-a50eb382c5ca','先兄中散挽歌詞四首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','德與才高位不酬，大鈞杳默向誰尤。',64,'全唐诗/poet.song.78000.json','["德與才高位不酬，大鈞杳默向誰尤。", "剖符政化傳沂水，握節威名振宛丘。", "心悟三乘真合覺，學該九域獨推優。", "鴈行影拆元龜喪，涙洒西風不忍收。"]'),
('c2b38ee0-5686-4993-b96a-3b4f5192cd7d','先兄中散挽歌詞四首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','粉闈當日正逢辰，興在滄洲猛乞身。',64,'全唐诗/poet.song.78000.json','["粉闈當日正逢辰，興在滄洲猛乞身。", "袖手旁觀真得計，急流勇退更何人。", "翺翔詞館全無累，笑傲丘園不計春。", "鼎鼐百年均此路，惟公達識夐誰論。"]'),
('47cf5e9e-85ff-4af3-b519-4a3cf9eb545e','先兄中散挽歌詞四首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','流年八袠慶初開，駒隙那知二豎催。',64,'全唐诗/poet.song.78000.json','["流年八袠慶初開，駒隙那知二豎催。", "書聚五車緣嗜學，家徒四壁爲輕財。", "幻身夢蝶自云適，曲路增蠅何處来。", "深恨滯留暌屬纊，此生賫恨在天台。"]'),
('0fda9ba5-7a02-4c4b-a799-c41e730de7dc','哀範卿學士弟','葛勝仲','宋','宋诗','song-poetry','','[]','萬卷胸中學已優，安恬當向古人求。',64,'全唐诗/poet.song.78000.json','["萬卷胸中學已優，安恬當向古人求。", "有財謾說駒千里，此路何殊貉一丘。", "儒館芸香今寂寂，親闈芝檢竟悠悠。", "懸知簫鼓江村路，茂柏深松結暮愁。"]'),
('f5c8e75d-6305-485f-bbb1-d5875ec747c9','楊彦安大夫挽歌詞','葛勝仲','宋','宋诗','song-poetry','','[]','英猷卓躒世無多，用不酬材可柰何。',96,'全唐诗/poet.song.78000.json','["英猷卓躒世無多，用不酬材可柰何。", "庀邑頌聲空製錦，阜財智算謾熬波。", "鱣堂積學家傳慶，蟾窟登榮子繼科。", "下里有車催遣奠，上池無藥起沈痾。", "心期於我勤知過，肺腑從公久切磋。", "十載飄流隔生死，東風吹淚寄滂沲。"]'),
('f049ab8b-d82d-4d9b-882a-b626e7f5e780','讀史八首 王嘉','葛勝仲','宋','宋诗','song-poetry','','[]','王嘉冤死有由緣，峻節忠言照史篇。',32,'全唐诗/poet.song.78000.json','["王嘉冤死有由緣，峻節忠言照史篇。", "最是一條堪恨處，臨刑猶道孔光賢。"]'),
('b9be2563-0dac-4cda-9fcf-35f724af051b','讀史八首 馬融','葛勝仲','宋','宋诗','song-poetry','','[]','爲梁草奏枉忠臣，李固夤緣遂殺身。',32,'全唐诗/poet.song.78000.json','["爲梁草奏枉忠臣，李固夤緣遂殺身。", "南郡何須施絳悵，應無面目見時人。"]'),
('3bda3569-eb6a-4cbe-82e2-58c4547d404c','讀史八首 陳蕃','葛勝仲','宋','宋诗','song-poetry','','[]','閹尹流凶遍海隅，飛章露奏計誠疏。',32,'全唐诗/poet.song.78000.json','["閹尹流凶遍海隅，飛章露奏計誠疏。", "黄門詔獄空忠鬼，天下何因遂掃除。"]'),
('866ef4c6-987c-41e7-b7f5-eccecab13257','讀史八首 鄧伯道','葛勝仲','宋','宋诗','song-poetry','','[]','賊掠家儲歲阻饑，將兒繫樹後無兒。',32,'全唐诗/poet.song.78000.json','["賊掠家儲歲阻饑，將兒繫樹後無兒。", "林回輕棄千金璧，始信皇天是有知。"]'),
('e6af36d1-2d3e-4159-b381-a9d02b04afc3','讀史八首 法真','葛勝仲','宋','宋诗','song-poetry','','[]','奬鑒人倫重法真，親庭曾遺助求人。',32,'全唐诗/poet.song.78000.json','["奬鑒人倫重法真，親庭曾遺助求人。", "牖間占察曾何補，只得庸庸番土臣。"]'),
('b278ebda-ef66-4bc9-bcf8-cc02bfa2c77a','讀史八首 王戎','葛勝仲','宋','宋诗','song-poetry','','[]','兒時黠慧豈尋常，苦李徒教結道傍。',32,'全唐诗/poet.song.78000.json','["兒時黠慧豈尋常，苦李徒教結道傍。", "何事季年癡更甚，爲財鑽核長膏肓。"]'),
('430f40ef-ccc9-45c6-b274-2113f8a970ff','讀史八首 沈約','葛勝仲','宋','宋诗','song-poetry','','[]','革運稱梁出秘謀，壽光不許范雲留。',32,'全唐诗/poet.song.78000.json','["革運稱梁出秘謀，壽光不許范雲留。", "赤章夜奏稱非已，合向人間謚隱侯。"]'),
('441c63bc-5c2d-4c93-af83-56724ec9f7a6','讀史八首 王維','葛勝仲','宋','宋诗','song-poetry','','[]','子昂文律唱唐家，摩詰詩聲未易加。',32,'全唐诗/poet.song.78000.json','["子昂文律唱唐家，摩詰詩聲未易加。", "場屋有誰深薦達，坐令入彀賴琵琶。"]'),
('1a8935f3-75ad-4b41-9e94-ab17be9c6fc0','泮水','葛勝仲','宋','宋诗','song-poetry','','[]','半璧清波勢自然，鸞聲旂色想當年。',32,'全唐诗/poet.song.78000.json','["半璧清波勢自然，鸞聲旂色想當年。", "野芹不識興亡恨，猶自牽風漾碧漣。"]'),
('2f3825be-579d-43e0-9337-caf3ed50075c','廟宅','葛勝仲','宋','宋诗','song-poetry','','[]','素王遺廟屋渠渠，老檜陰濃耀碧虚。',32,'全唐诗/poet.song.78000.json','["素王遺廟屋渠渠，老檜陰濃耀碧虚。", "無復升堂聞古樂，尚傳開甕得丹書。"]'),
('bab8b45e-17f9-4791-9070-ba24d922a8e1','靈光故基','葛勝仲','宋','宋诗','song-poetry','','[]','蟠螭宛轉謾承楣，東序西廂只廢基。',32,'全唐诗/poet.song.78000.json','["蟠螭宛轉謾承楣，東序西廂只廢基。", "終與建章同圯壞，浪言神力有支持。"]'),
('8a164a33-ebcf-4161-8495-2d3235ae412a','望嶽亭','葛勝仲','宋','宋诗','song-poetry','','[]','迤邐羣山不識名，天門日觀遠崢嶸。',32,'全唐诗/poet.song.78000.json','["迤邐羣山不識名，天門日觀遠崢嶸。", "地靈不見二宫迹，聖作時聞萬歲聲。"]'),
