('cae3ae08-81a9-45a8-8f0d-bde6ea818e9e','疊前韻三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','晚凉湯餅點青蒿，蔔瓠分甘笑楚糟。',32,'全唐诗/poet.song.78000.json','["晚凉湯餅點青蒿，蔔瓠分甘笑楚糟。", "好摘江蘺充雜佩，不須歲晚夢三刀。"]'),
('225f73a6-83d9-4095-9306-eef402985200','埇橋道中','葛勝仲','宋','宋诗','song-poetry','','[]','雨跳濁水千漚亂，風過橋林萬弩齊。',32,'全唐诗/poet.song.78000.json','["雨跳濁水千漚亂，風過橋林萬弩齊。", "頃刻埇橋斜景在，市人來去兩虹霓。"]'),
('6f44fbb3-40c7-47ff-840d-c7d87d4a5fde','七夕','葛勝仲','宋','宋诗','song-poetry','','[]','朱閣瓊宫耀紫房，翠翹下墮慰愁腸。',32,'全唐诗/poet.song.78000.json','["朱閣瓊宫耀紫房，翠翹下墮慰愁腸。", "天中感遇非塵世，不念癡牛念郭郎。"]'),
('23d7ad38-b847-4c7a-9e4f-ec88a1bfe8c9','次韻德升七夕二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','盈盈一水截長空，烏雀橋成得暫通。',32,'全唐诗/poet.song.78000.json','["盈盈一水截長空，烏雀橋成得暫通。", "逗曉歸来装萬恨，舊機牢落響寒風。"]'),
('0eda13cc-8ba9-4289-b87e-9ce73b6a47e0','次韻德升七夕二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','霓旌鸞扇去央央，雲路輕車駕七香。',32,'全唐诗/poet.song.78000.json','["霓旌鸞扇去央央，雲路輕車駕七香。", "靈會此宵才瞬息，經年何苦夜偏長。"]'),
('677eca9d-03cc-4f8e-940d-966c0df2ea8b','次韻德升頤軒詩五首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','晴碾春龍鬬小窗，飲慳難遣睡魔降。',32,'全唐诗/poet.song.78000.json','["晴碾春龍鬬小窗，飲慳難遣睡魔降。", "翩然夢遶滄洲去，白馬波寒槳一雙。"]'),
('879fecca-b34a-4d1a-aff1-8324be80f1ef','次韻德升頤軒詩五首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','轆轤聲到讀書帷，草解招凉暑氣遲。',32,'全唐诗/poet.song.78000.json','["轆轤聲到讀書帷，草解招凉暑氣遲。", "凈掃竹軒人不到，戍樓哀角又空吹。"]'),
('934e6d10-67a7-4bfb-8d66-119b862ac37c','次韻德升頤軒詩五首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','造物機緘屬小兒，懶從寒燠究端倪。',32,'全唐诗/poet.song.78000.json','["造物機緘屬小兒，懶從寒燠究端倪。", "綠陰晝寂孤花凈，猶有黄鸝恰恰啼。"]'),
('3e1b4e4c-3329-46c4-b6b3-4b66f7c2f9cc','次韻德升頤軒詩五首  其四','葛勝仲','宋','宋诗','song-poetry','','[]','金鑾賜第新搴桂，鐡幕官期未及瓜。',32,'全唐诗/poet.song.78000.json','["金鑾賜第新搴桂，鐡幕官期未及瓜。", "隱几蒲團無一事，五車關眼未昏花。"]'),
('00b8334a-4b59-4397-8653-32cd6d2e9e67','次韻德升頤軒詩五首  其五','葛勝仲','宋','宋诗','song-poetry','','[]','外物年来論已齊，眼看人事浪推移。',32,'全唐诗/poet.song.78000.json','["外物年来論已齊，眼看人事浪推移。", "禨祥白犢何勞問，寵辱黄粱共一炊。"]'),
('cf3baa48-14f9-46ba-a4ee-1b9961f7bab3','次韻德升惠新茶  其一','葛勝仲','宋','宋诗','song-poetry','','[]','寵餉頭綱北焙茶，分甘應自五侯家。',32,'全唐诗/poet.song.78000.json','["寵餉頭綱北焙茶，分甘應自五侯家。", "午鷄驚破槐安夢，猶有新香在齒牙。"]'),
('6a184c46-e7c4-4539-a7e9-c2ab5b9cb89b','次韻德升惠新茶  其二','葛勝仲','宋','宋诗','song-poetry','','[]','雙疊紅囊貯揀芽，旋將活火試瑤花。',32,'全唐诗/poet.song.78000.json','["雙疊紅囊貯揀芽，旋將活火試瑤花。", "半生未有陽侯厄，喜聽咿啞轉井車。"]'),
('72cb346d-9263-4790-a528-077cf9c080a1','新茶','葛勝仲','宋','宋诗','song-poetry','','[]','當日火攻應有法，此時水厄定無餘。',32,'全唐诗/poet.song.78000.json','["當日火攻應有法，此時水厄定無餘。", "閒軒七碗宜頻試，九隴清泉勝具區。"]'),
('18be3acd-b86a-46be-b506-28e36b7259cb','烹茶','葛勝仲','宋','宋诗','song-poetry','','[]','俗耳未容聽滴瀝，水瓶聊遣挹泓澄。',32,'全唐诗/poet.song.78000.json','["俗耳未容聽滴瀝，水瓶聊遣挹泓澄。", "晴軒小酌煎新茗，紗帽籠頭似管寜。"]'),
('c2627682-316b-4199-b878-716030225e37','鰣魚','葛勝仲','宋','宋诗','song-poetry','','[]','貫以柳條仍撥刺，芼之筠笋佐鮮肥。',32,'全唐诗/poet.song.78000.json','["貫以柳條仍撥刺，芼之筠笋佐鮮肥。", "他年京洛憎凡饌，莫忘河亭染指時。"]'),
('e847decd-01f9-42d5-a83b-151a3492cb62','烹笋','葛勝仲','宋','宋诗','song-poetry','','[]','味佳端可供羮梜，韻勝尤宜薦酒螺。',32,'全唐诗/poet.song.78000.json','["味佳端可供羮梜，韻勝尤宜薦酒螺。", "自笑癡人饕口腹，不求新竹透林多。"]'),
('da2e0425-2a56-4ef4-baac-c76857b5880a','友人惠芍藥并青梅一枝偶成三絕  其一','葛勝仲','宋','宋诗','song-poetry','','[]','窺園記我分名卉，大似梁園重錦紅。',32,'全唐诗/poet.song.78000.json','["窺園記我分名卉，大似梁園重錦紅。", "自愧江淹才已盡，卻須還與主人翁。"]');
